// usePlanProtocols.js — hook para carregar protocolos de um bloco semântico
// Reutiliza treatmentsService.getActiveTreatments e filtra por planId ou protocolIds[]

import { useState, useEffect } from 'react'
import { getActiveTreatments } from '../../treatments/services/treatmentsService'

/**
 * Converte "HH:MM" para minutos desde meia-noite.
 */
function toMinutes(hhmm) {
  const [h, m] = hhmm.split(':').map(Number)
  return h * 60 + m
}

/**
 * Retorna true se o protocolo tem algum horário em time_schedule dentro
 * de uma janela de ±windowMinutes em relação ao horário alvo.
 */
function isInWindow(protocol, scheduledTime, windowMinutes = 120) {
  if (!scheduledTime) return true
  const target = toMinutes(scheduledTime)
  return (protocol.time_schedule ?? []).some(t => Math.abs(toMinutes(t) - target) <= windowMinutes)
}

/**
 * Carrega os protocolos ativos correspondentes a um bloco de notificação,
 * filtrando pela janela de horário (±2h do scheduledTime) quando informado.
 *
 * @param {{ mode: 'plan'|'misc', planId?: string, protocolIds?: string[], scheduledTime?: string, userId: string }} params
 * @returns {{ protocols: Object[], loading: boolean, error: string|null }}
 */
export function usePlanProtocols({ mode, planId, protocolIds, scheduledTime, userId }) {
  const [protocols, setProtocols] = useState([])
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState(null)

  useEffect(() => {
    if (!userId) return
    if (mode === 'plan' && !planId) return
    if (mode === 'misc' && (!protocolIds || protocolIds.length === 0)) return

    let isMounted = true
    setLoading(true)
    setError(null)

    getActiveTreatments(userId)
      .then(result => {
        if (!isMounted) return
        if (!result.success) {
          setError(result.error ?? 'Erro ao carregar protocolos.')
          return
        }
        const all = result.data ?? []
        if (mode === 'plan') {
          setProtocols(
            all
              .filter(p => p.treatment_plan?.id === planId)
              .filter(p => isInWindow(p, scheduledTime))
          )
        } else {
          setProtocols(all.filter(p => protocolIds.includes(p.id)))
        }
      })
      .catch(err => {
        if (!isMounted) return
        setError(err.message ?? 'Erro desconhecido.')
      })
      .finally(() => {
        if (isMounted) setLoading(false)
      })

    return () => { isMounted = false }
  }, [mode, planId, protocolIds, scheduledTime, userId])

  return { protocols, loading, error }
}

// doseService.js — serviço thin para registo de doses no mobile
// ADR-029: thin local service — Supabase directo via nativeSupabaseClient
// R5-008: online-first — escrita offline bloqueada com mensagem clara
// R-121: validação Zod antes de qualquer mutação

import { supabase } from '../../../platform/supabase/nativeSupabaseClient'
import { logSchema } from '@dosiq/core'
import { logEvent } from '../../../platform/analytics/firebaseAnalytics'
import { EVENTS } from '../../../platform/analytics/analyticsEvents'

/**
 * Regista uma dose tomada.
 * Falha de forma clara se o dispositivo estiver offline.
 *
 * @param {{
 *   protocol_id: string|null,
 *   medicine_id: string,
 *   taken_at: string,       — ISO 8601 (ex: "2026-04-14T08:30:00")
 *   quantity_taken: number,
 *   notes?: string|null
 * }} logData
 * @returns {Promise<{ success: boolean, data?: Object, error?: string }>}
 */
export async function registerDose(logData) {
  // R5-008: verificar conectividade antes de escrever
  // React Native não tem navigator.onLine — tentamos a mutação e tratamos o erro de rede
  // A separação é garantida pelo fallback no catch abaixo.

  // R-121: validar com Zod antes de enviar ao Supabase
  if (__DEV__) console.log('[doseService] registerDose — input:', JSON.stringify(logData))
  const parsed = logSchema.safeParse(logData)
  if (!parsed.success) {
    if (__DEV__) console.warn('[doseService] Zod validation FAILED:', JSON.stringify(parsed.error.issues[0]))
    const firstError = parsed.error.issues[0]
    return { success: false, error: firstError.message }
  }
  if (__DEV__) console.log('[doseService] Zod OK — parsed:', JSON.stringify(parsed.data))

  try {
    const { data: { user }, error: authError } = await supabase.auth.getUser()
    if (authError || !user) {
      return { success: false, error: 'Sessão expirada. Faça login novamente.' }
    }

    if (__DEV__) console.log('[doseService] insert start — user:', user.id)
    const { data: logEntry, error: insertError } = await supabase
      .from('medicine_logs')
      .insert({ ...parsed.data, user_id: user.id })
      .select('id, taken_at, quantity_taken, medicine_id')
      .single()

    if (insertError) {
      if (__DEV__) console.error('[doseService] insert ERRO:', JSON.stringify(insertError))
      // Detectar erro de rede (R5-008: mensagem clara offline)
      if (insertError.message?.includes('fetch') || insertError.message?.includes('network') || insertError.code === 'PGRST301') {
        return { success: false, error: 'Sem ligação à internet. O registo de dose requer conexão.' }
      }
      return { success: false, error: insertError.message }
    }

    if (__DEV__) console.log('[doseService] insert OK — id:', logEntry?.id, 'A consumir stock...')

    // R-170: Consumir stock via RPC transactional (Wave 4 legacy compatibility)
    // p_medicine_id, p_quantity, p_medicine_log_id
    const { error: stockError } = await supabase.rpc('consume_stock_fifo', {
      p_medicine_id: logEntry.medicine_id,
      p_quantity: logEntry.quantity_taken,
      p_medicine_log_id: logEntry.id
    })

    if (stockError) {
      // R-170: Logar erro de estoque para depuração conforme padrão do projeto
      console.warn('[doseService] erro ao consumir stock:', stockError)

      // ROLLBACK: remover o log inserido se não for possível consumir o stock
      const { error: rollbackError } = await supabase
        .from('medicine_logs')
        .delete()
        .eq('id', logEntry.id)

      if (rollbackError) {
        console.error('[doseService] erro crítico no rollback:', rollbackError)
        return { 
          success: false, 
          error: 'Erro crítico: falha ao atualizar estoque pós-registro. Contacte o suporte.' 
        }
      }

      // Traduções amigáveis para erros comuns de stock
      if (stockError.message?.includes('Estoque insuficiente')) {
        return { success: false, error: 'Estoque insuficiente para registrar esta dose.' }
      }

      return { success: false, error: 'Não foi possível registrar a dose: erro ao processar estoque.' }
    }

    if (__DEV__) console.log('[doseService] stock consumido com sucesso')
    await logEvent(EVENTS.DOSE_LOGGED, { medicine_id: logEntry.medicine_id })
    return { success: true, data: logEntry }
  } catch (err) {
    if (__DEV__) console.error('[doseService] erro catastrófico:', err)
    // Captura erros de rede não estruturados do fetch
    if (err.message?.includes('Network') || err.message?.includes('fetch')) {
      return { success: false, error: 'Sem ligação à internet. O registo de dose requer conexão.' }
    }
    return { success: false, error: err.message ?? 'Erro desconhecido ao registrar dose.' }
  }
}

/**
 * Registra múltiplas doses em batch.
 * Insert batch via Supabase (1 roundtrip) → consume_stock_fifo por log (sequencial).
 * Rollback individual por log se stock falhar — não aborta o batch inteiro.
 *
 * @param {Array<{ protocol_id: string|null, medicine_id: string, taken_at: string, quantity_taken: number }>} logsData
 * @returns {Promise<{ success: boolean, results: Array<{ id: string, success: boolean, error?: string }>, error?: string }>}
 */
export async function registerDoseMany(logsData) {
  if (!logsData || logsData.length === 0) {
    return { success: false, results: [], error: 'Nenhuma dose selecionada.' }
  }

  // R-121: validar cada log com Zod antes de qualquer mutação
  const validatedLogs = []
  for (const logData of logsData) {
    const parsed = logSchema.safeParse(logData)
    if (!parsed.success) {
      if (__DEV__) console.warn('[doseService] registerDoseMany Zod FAILED:', parsed.error.issues[0])
      return { success: false, results: [], error: parsed.error.issues[0].message }
    }
    validatedLogs.push(parsed.data)
  }

  try {
    const { data: { user }, error: authError } = await supabase.auth.getUser()
    if (authError || !user) {
      return { success: false, results: [], error: 'Sessão expirada. Faça login novamente.' }
    }

    // Batch insert — 1 roundtrip para N logs
    const { data: insertedLogs, error: insertError } = await supabase
      .from('medicine_logs')
      .insert(validatedLogs.map(l => ({ ...l, user_id: user.id })))
      .select('id, taken_at, quantity_taken, medicine_id')

    if (insertError) {
      if (__DEV__) console.error('[doseService] registerDoseMany insert ERRO:', insertError)
      if (insertError.message?.includes('fetch') || insertError.message?.includes('network') || insertError.code === 'PGRST301') {
        return { success: false, results: [], error: 'Sem ligação à internet. O registo de dose requer conexão.' }
      }
      return { success: false, results: [], error: insertError.message }
    }

    // R-170: consume_stock_fifo por log — rollback individual se falhar
    const results = []
    for (const logEntry of insertedLogs) {
      const { error: stockError } = await supabase.rpc('consume_stock_fifo', {
        p_medicine_id: logEntry.medicine_id,
        p_quantity: logEntry.quantity_taken,
        p_medicine_log_id: logEntry.id,
      })

      if (stockError) {
        console.warn('[doseService] registerDoseMany stock ERRO para', logEntry.id, stockError)
        // Rollback individual — não interrompe os demais
        const { error: rollbackError } = await supabase.from('medicine_logs').delete().eq('id', logEntry.id)
        if (rollbackError && __DEV__) console.error('[doseService] Erro crítico no rollback do batch:', rollbackError)
        const errMsg = stockError.message?.includes('Estoque insuficiente')
          ? 'Estoque insuficiente.'
          : 'Erro ao processar estoque.'
        results.push({ id: logEntry.id, success: false, error: errMsg })
      } else {
        results.push({ id: logEntry.id, success: true })
      }
    }

    const successCount = results.filter(r => r.success).length
    if (successCount > 0) {
      await logEvent(EVENTS.DOSE_LOGGED_BULK, { count: successCount })
    }
    if (__DEV__) console.log('[doseService] registerDoseMany concluído — sucesso:', successCount, '/', results.length)
    return { success: successCount > 0, results }
  } catch (err) {
    if (__DEV__) console.error('[doseService] registerDoseMany erro catastrófico:', err)
    if (err.message?.includes('Network') || err.message?.includes('fetch')) {
      return { success: false, results: [], error: 'Sem ligação à internet. O registo de dose requer conexão.' }
    }
    return { success: false, results: [], error: err.message ?? 'Erro desconhecido ao registrar doses.' }
  }
}

/**
 * NotificationItem — Item da Central de Avisos (Mobile).
 *
 * Título contextual por tipo (medicine_name / protocol_name).
 * CTA semântico por tipo. Status "enviada" silencioso; "falhou" mostra ícone discreto.
 * R-167: logs em __DEV__ apenas. R-138: ícone sempre com label. ADR-023: fontWeight ≥ 400.
 */
import { useState } from 'react'
import { View, Text, StyleSheet, TouchableOpacity, Pressable } from 'react-native'
import {
  Clock, Package, AlertTriangle, BarChart2, TrendingUp, Bell, ChevronRight,
  Pill, Tablets, ListChecks, NotepadText
} from 'lucide-react-native'
import { getNotificationIcon, formatRelativeTime } from '@dosiq/core'
import { colors } from '../../../shared/styles/tokens'

const ICON_MAP = {
  Clock, Package, AlertTriangle, BarChart2, TrendingUp, Bell,
  Pill, Tablets, ListChecks, NotepadText
}

const CTA_MAP = {
  dose_reminder:         { label: 'Registrar dose',    action: 'dashboard' },
  dose_reminder_by_plan: { label: 'Registrar plano',   action: 'bulk-plan' },
  dose_reminder_misc:    { label: 'Registrar doses',   action: 'bulk-misc' },
  stock_alert:           { label: 'Ver estoque',        action: 'stock' },
  missed_dose:           { label: 'Registrar atrasada', action: 'history' },
  titration_update:      { label: 'Ver tratamento',     action: 'treatment' },
  daily_digest:          null,
}

function resolveTitle(notification, label) {
  const { notification_type, medicine_name, protocol_name } = notification
  switch (notification_type) {
    case 'dose_reminder':
    case 'stock_alert':
    case 'missed_dose':
      return medicine_name ?? label
    case 'titration_update':
      return protocol_name ?? label
    case 'daily_digest':
      return 'Resumo do dia'
    case 'dose_reminder_by_plan':
      return notification.treatment_plan_name ?? 'Plano de tratamento'
    case 'dose_reminder_misc':
      return 'Doses agora'
    default:
      return label
  }
}

/**
 * @param {Object} props
 * @param {Object}   props.notification - Objeto notificationLog do DB
 * @param {boolean}  [props.wasTaken]   - Se dose já foi registrada (calculado pelo pai)
 * @param {function} [props.onNavigate] - (routeName) => void
 */
export default function NotificationItem({ notification, wasTaken, onNavigate }) {
  const [expanded, setExpanded] = useState(false)

  const { notification_type, status, sent_at, title, body } = notification

  const { iconName, color, bgColor, label } = getNotificationIcon(notification_type)
  const IconComponent  = ICON_MAP[iconName] ?? Bell
  const relativeTime   = formatRelativeTime(sent_at)
  const isFailed       = ['falhou', 'failed'].includes(status?.toLowerCase())
  const isDailyDigest  = notification_type === 'daily_digest'
  const isDoseReminder = ['dose_reminder', 'dose_reminder_by_plan', 'dose_reminder_misc'].includes(notification_type)

  const displayTitle = resolveTitle(notification, label)
  const displayBody  = body ?? null
  const doses        = notification.doses ?? null
  const cta          = CTA_MAP[notification_type] ?? null
  const groupedComplete = isDoseReminder && typeof wasTaken === 'object' && wasTaken.taken === wasTaken.total
  const hasNavAction = cta && !!onNavigate && !(isDoseReminder && wasTaken === true) && !groupedComplete

  const inner = (
    <View style={styles.row}>
      <View style={[styles.iconCircle, { backgroundColor: bgColor }]}>
        <IconComponent size={20} color={color} strokeWidth={2} />
      </View>

      <View style={styles.body}>
        {/* Cabeçalho */}
        <View style={styles.titleRow}>
          <Text style={styles.title} numberOfLines={1}>{displayTitle}</Text>
          <View style={styles.timeRow}>
            <Text style={styles.time}>{relativeTime}</Text>
            {isFailed && (
              <AlertTriangle
                size={12}
                color={colors.status?.error ?? '#dc2626'}
                strokeWidth={2.5}
                accessibilityLabel="Falhou ao enviar"
              />
            )}
          </View>
        </View>

        {/* Corpo */}
        {doses?.length > 0 ? (
          <View style={styles.doseList}>
            {doses.map((dose, i) => (
              <Text key={i} style={styles.doseItem}>
                {`${dose.dosage}x ${dose.medicineName}`}
              </Text>
            ))}
          </View>
        ) : displayBody ? (
          <>
            <Text
              style={styles.preview}
              numberOfLines={isDailyDigest && !expanded ? 2 : undefined}
            >
              {displayBody}
            </Text>
            {isDailyDigest && (
              <Pressable
                onPress={() => setExpanded(prev => !prev)}
                accessibilityRole="button"
                accessibilityLabel={expanded ? 'Ver menos' : 'Ver mais'}
                hitSlop={{ top: 6, bottom: 6, left: 0, right: 0 }}
              >
                <Text style={styles.expandBtn}>{expanded ? 'Ver menos' : 'Ver mais'}</Text>
              </Pressable>
            )}
          </>
        ) : null}

        {/* Rodapé: CTA ou confirmação de dose tomada */}
        <View style={styles.footer}>
          {isDoseReminder && wasTaken === true ? (
            <Text style={styles.takenLabel}>✓ Tomada</Text>
          ) : groupedComplete ? (
            <Text style={[styles.takenLabel, styles.takenFull]}>
              {wasTaken.taken}/{wasTaken.total} tomadas
            </Text>
          ) : hasNavAction ? (
            <View style={styles.actionLabel}>
              {typeof wasTaken === 'object' && (
                <Text style={styles.takenLabel}>{wasTaken.taken}/{wasTaken.total} • </Text>
              )}
              <Text style={styles.actionText}>{cta.label}</Text>
              <ChevronRight size={13} color={colors.primary?.[600] ?? '#006a5e'} strokeWidth={2.5} />
            </View>
          ) : null}
        </View>
      </View>
    </View>
  )

  if (hasNavAction) {
    return (
      <TouchableOpacity
        activeOpacity={0.7}
        onPress={() => onNavigate(cta.action)}
        accessibilityRole="button"
        accessibilityLabel={`${cta.label} — ${displayTitle}`}
        style={styles.item}
      >
        {inner}
      </TouchableOpacity>
    )
  }

  return <View style={styles.item}>{inner}</View>
}

const styles = StyleSheet.create({
  item:        { paddingHorizontal: 20, paddingVertical: 14 },
  row:         { flexDirection: 'row', alignItems: 'flex-start', gap: 14 },
  iconCircle:  { width: 40, height: 40, borderRadius: 20, alignItems: 'center', justifyContent: 'center', marginTop: 1, flexShrink: 0 },
  body:        { flex: 1, gap: 4 },
  titleRow:    { flexDirection: 'row', alignItems: 'baseline', justifyContent: 'space-between', gap: 8 },
  title:       { fontSize: 15, fontWeight: '600', color: colors.text?.primary ?? '#111827', flex: 1 },
  timeRow:     { flexDirection: 'row', alignItems: 'center', gap: 4, flexShrink: 0 },
  time:        { fontSize: 12, fontWeight: '400', color: colors.text?.muted ?? '#9ca3af', fontVariant: ['tabular-nums'] },
  preview:     { fontSize: 13, fontWeight: '400', color: colors.text?.secondary ?? '#4b5563', lineHeight: 19 },
  expandBtn:   { fontSize: 12, fontWeight: '500', color: colors.text?.muted ?? '#6b7280', marginTop: 2 },
  footer:      { flexDirection: 'row', alignItems: 'center', justifyContent: 'flex-end', marginTop: 4 },
  takenLabel:  { fontSize: 12, fontWeight: '500', color: colors.text?.muted ?? '#6b7280' },
  takenFull:   { color: colors.primary?.[600] ?? '#006a5e' },
  actionLabel: { flexDirection: 'row', alignItems: 'center', gap: 2 },
  actionText:  { fontSize: 13, fontWeight: '600', color: colors.primary?.[600] ?? '#006a5e' },
  doseList:    { gap: 2, marginTop: 2 },
  doseItem:    { fontSize: 13, fontWeight: '400', color: colors.text?.secondary ?? '#4b5563', lineHeight: 19 },
})

