/**
 * useNotificationLog — Hook Nativo para histórico de notificações (Mobile)
 *
 * Segue o padrão de resiliência offline com snapshot em AsyncStorage.
 *
 * @module useNotificationLog
 */

import { useState, useEffect, useCallback, useRef } from 'react'
import { AppState } from 'react-native'
import { getTodayLocal, getNow, parseISO, addDays, cloneDate } from '@dosiq/core'
import AsyncStorage from '@react-native-async-storage/async-storage'
import { createNotificationLogRepository } from '@dosiq/shared-data'
import { supabase } from '../../platform/supabase/nativeSupabaseClient'

/**
 * Gera chave de cache dinâmica por usuário para evitar vazamento de dados (Security Fix)
 * @param {string} userId 
 * @returns {string}
 */
const getCacheKey = (userId) => `@dosiq/notif-log-snapshot:${userId}`

// Repositório singleton para a plataforma mobile
const repo = createNotificationLogRepository({ supabase })

/**
 * Enriquece logs de notificações agrupadas com a lista de medicamentos via join relacional.
 * Para by_plan: busca protocolos do treatment_plan_id filtrados pelo horário do sent_at.
 * Para misc: busca protocolos pelos IDs em provider_metadata.protocol_ids.
 * Evita duplicar dados no notification_log — busca sempre do estado atual dos protocolos.
 */
async function enrichWithDoses(logs) {
  const byPlanLogs = logs.filter(l => l.notification_type === 'dose_reminder_by_plan' && l.treatment_plan_id)
  const miscLogs   = logs.filter(l => l.notification_type === 'dose_reminder_misc')

  const planIds        = [...new Set(byPlanLogs.map(l => l.treatment_plan_id))]
  const miscProtocolIds = [...new Set(miscLogs.flatMap(l => l.provider_metadata?.protocol_ids ?? []))]

  const [planProtoMap, miscProtoMap] = await Promise.all([
    planIds.length > 0
      ? supabase
          .from('protocols')
          .select('id, dosage_per_intake, treatment_plan_id, time_schedule, medicine:medicine_id(name)')
          .in('treatment_plan_id', planIds)
          .eq('active', true)
          .then(({ data }) => {
            const map = {}
            for (const p of data ?? []) {
              if (!map[p.treatment_plan_id]) map[p.treatment_plan_id] = []
              map[p.treatment_plan_id].push(p)
            }
            return map
          })
      : Promise.resolve({}),

    miscProtocolIds.length > 0
      ? supabase
          .from('protocols')
          .select('id, dosage_per_intake, medicine:medicine_id(name)')
          .in('id', miscProtocolIds)
          .then(({ data }) => Object.fromEntries((data ?? []).map(p => [p.id, p])))
      : Promise.resolve({}),
  ])

  return logs.map(log => {
    if (log.notification_type === 'dose_reminder_by_plan' && log.treatment_plan_id) {
      const d    = parseISO(log.sent_at)
      const hhmm = `${String(d.getHours()).padStart(2, '0')}:${String(d.getMinutes()).padStart(2, '0')}`
      const doses = (planProtoMap[log.treatment_plan_id] ?? [])
        .filter(p => (p.time_schedule ?? []).includes(hhmm))
        .map(p => ({ medicineName: p.medicine?.name ?? 'Medicamento', dosage: p.dosage_per_intake ?? 1 }))
      return { ...log, doses }
    }

    if (log.notification_type === 'dose_reminder_misc') {
      const doses = (log.provider_metadata?.protocol_ids ?? [])
        .map(pid => miscProtoMap[pid])
        .filter(Boolean)
        .map(p => ({ medicineName: p.medicine?.name ?? 'Medicamento', dosage: p.dosage_per_intake ?? 1 }))
      return { ...log, doses }
    }

    return log
  })
}

/**
 * Hook para buscar logs de notificações com resiliência offline.
 *
 * @param {Object} options
 * @param {string} options.userId - ID do usuário (UUID)
 * @param {number} [options.limit=20] - Itens por página
 * @param {boolean} [options.enabled=true] - Se deve ativar o carregamento e listeners
 * @returns {Object} { data, loading, error, stale, refresh }
 */
export function useNotificationLog(options = {}) {
  const { userId, limit = 20, offset = 0, enabled = true } = options

  const [data, setData] = useState(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)
  const [stale, setStale] = useState(false)

  // Ref para evitar atualizações em componente desmontado
  const isMounted = useRef(true)

  const load = useCallback(async () => {
    if (!userId || !enabled) {
      setLoading(false)
      return
    }

    setLoading(true)
    setError(null)

    try {
      if (__DEV__) console.log('[useNotificationLog] Fetching notifications...')

      const raw  = await repo.listByUserId(userId, { limit, offset })
      const logs = await enrichWithDoses(raw)

      const cacheKey = getCacheKey(userId)
      const snapshot = {
        logs,
        capturedAt: getNow().toISOString(),
        localDay: getTodayLocal(), // R-114 compat
      }

      // Persiste para uso offline
      await AsyncStorage.setItem(cacheKey, JSON.stringify(snapshot))

      if (isMounted.current) {
        setData(logs)
        setStale(false)
        setError(null)
      }
    } catch (err) {
      if (__DEV__) console.warn('[useNotificationLog] Fetch failed, checking cache:', err.message)

      try {
        const cacheKey = getCacheKey(userId)
        const cached = await AsyncStorage.getItem(cacheKey)
        if (cached && isMounted.current) {
          const { logs } = JSON.parse(cached)
          setData(logs)
          setStale(true)
          setError(null)
        } else if (isMounted.current) {
          setError(err.message || 'Erro ao carregar notificações.')
        }
      } catch (cacheErr) {
        if (isMounted.current) setError('Erro de conexão e cache ausente.')
      }
    } finally {
      if (isMounted.current) setLoading(false)
    }
  }, [userId, limit, offset, enabled])

  useEffect(() => {
    isMounted.current = true
    load()
    return () => {
      isMounted.current = false
    }
  }, [load])

  // Lógica de Refresh de Meia-Noite e AppState (R-184)
  // Garante que logs fiquem atualizados quando o dia muda ou app volta do background
  useEffect(() => {
    if (!enabled) return

    let midnightTimer

    const scheduleMidnightRefresh = () => {
      const now = getNow()
      const nextMidnight = addDays(now, 1)
      nextMidnight.setHours(0, 0, 0, 0)

      const msUntilMidnight = nextMidnight.getTime() - now.getTime()

      clearTimeout(midnightTimer)
      midnightTimer = setTimeout(() => {
        if (__DEV__) console.log('[useNotificationLog] Meia-noite: Refreshing...')
        load()
        scheduleMidnightRefresh()
      }, msUntilMidnight + 1000)
    }

    scheduleMidnightRefresh()

    const handleStateChange = (nextState) => {
      if (nextState === 'active') {
        // Forçar um refresh leve ao voltar, opcionalmente checar se o dia mudou
        if (__DEV__) console.log('[useNotificationLog] App active: Refreshing...')
        load()
      }
    }

    const subscription = AppState.addEventListener('change', handleStateChange)

    return () => {
      subscription.remove()
      clearTimeout(midnightTimer)
    }
  }, [load, enabled])

  return {
    data,
    loading,
    error,
    stale,
    refresh: load,
  }
}

/**
 * useUnreadBadgeCount — Badge leve de não-lidas (sem fetch de logs).
 *
 * Lê apenas o AsyncStorage para comparar last-seen com um count RPC simples.
 * Alternativa leve ao useNotificationLog para contextos que só precisam do badge.
 */
import { useState, useEffect, useCallback } from 'react'
import AsyncStorage from '@react-native-async-storage/async-storage'
import { useFocusEffect } from '@react-navigation/native'
import { supabase } from '../../platform/supabase/nativeSupabaseClient'

const getStorageKey = (userId) =>
  userId ? `@dosiq/notif-last-seen:${userId}` : '@dosiq/notif-last-seen'

/**
 * @param {string|null} userId
 * @returns {{ unreadCount: number, refreshBadge: () => Promise<void> }}
 */
export function useUnreadBadgeCount(userId) {
  const [unreadCount, setUnreadCount] = useState(0)

  const refreshBadge = useCallback(async () => {
    if (!userId) return
    try {
      const lastSeen = await AsyncStorage.getItem(getStorageKey(userId))
      let query = supabase
        .from('notification_log')
        .select('id', { count: 'exact', head: true })
        .eq('user_id', userId)

      if (lastSeen) {
        query = query.gt('sent_at', lastSeen)
      }

      const { count, error } = await query
      if (!error) setUnreadCount(count ?? 0)
    } catch (e) {
      // Silencioso — badge é cosmético
      if (__DEV__) console.error('[useUnreadBadgeCount] Fetch failed:', e.message)
    }
  }, [userId])

  // Atualiza ao focar na tela (ex: ao voltar da Inbox)
  useFocusEffect(
    useCallback(() => {
      refreshBadge()
    }, [refreshBadge])
  )

  useEffect(() => {
    refreshBadge()
  }, [refreshBadge])

  return { unreadCount, refreshBadge }
}

const { withAppDelegate, withDangerousMod } = require('@expo/config-plugins');
const fs = require('fs');
const path = require('path');

const withFirebaseFix = (config) => {
  // 1. Injeta no AppDelegate.swift
  config = withAppDelegate(config, config => {
    if (config.modResults.language === 'swift') {
      let contents = config.modResults.contents;

      if (!contents.includes('import FirebaseCore')) {
        contents = contents.replace(
          /import Expo/g,
          `import Expo\nimport FirebaseCore`
        );
      }

      const configureLine = `FirebaseApp.configure()`;
      if (!contents.includes(configureLine)) {
        contents = contents.replace(
          /(public override func application\(\s*_ application: UIApplication,\s*didFinishLaunchingWithOptions launchOptions: \[UIApplication\.LaunchOptionsKey: Any\]\? = nil\s*\) -> Bool \{)/,
          `$1\n    ${configureLine}`
        );
      }

      config.modResults.contents = contents;
    }
    return config;
  });

  // Removido o bloco que injeta use_modular_headers! pois conflita com Hermes e RN 0.76+

  return config;
};

module.exports = withFirebaseFix;

import { useState, useEffect, lazy, Suspense } from 'react'
import { motion, AnimatePresence, useReducedMotion } from 'framer-motion'
import { BotMessageSquare } from 'lucide-react'
import { getCurrentUser, onAuthStateChange, supabase } from '@shared/utils/supabase'
import { useNotificationLog } from '@shared/hooks/useNotificationLog'
import { useUnreadNotificationCount } from '@shared/hooks/useUnreadNotificationCount'
import '@shared/styles/index.css'
import appStyles from './App.module.css'
import Auth from './views/Auth'
import Loading from '@shared/components/ui/Loading'

// Lazy imports — carregam apenas quando a view é acessada
const Landing = lazy(() => import('./views/Landing'))
const Medicines = lazy(() => import('./views/redesign/Medicines'))
const Stock = lazy(() => import('./views/redesign/Stock'))
const Protocols = lazy(() => import('./views/Protocols'))
const HealthHistory = lazy(() => import('./views/redesign/HealthHistory'))
const Settings = lazy(() => import('./views/redesign/Settings'))
const Emergency = lazy(() => import('./views/redesign/Emergency'))
const Treatment = lazy(() => import('./views/redesign/Treatments'))
const Profile = lazy(() => import('./views/redesign/Profile'))
const Consultation = lazy(() => import('./views/redesign/Consultation'))
const DLQAdmin = lazy(() => import('./views/admin/DLQAdmin'))
const Dashboard = lazy(() => import('./views/redesign/Dashboard'))
const NotificationInbox = lazy(() => import('./views/redesign/NotificationInbox'))
const ChatWindow = lazy(() => import('@features/chatbot/components/ChatWindow'))
const BottomNavRedesign = lazy(() => import('@shared/components/ui/BottomNavRedesign'))
const Sidebar = lazy(() => import('@shared/components/ui/Sidebar'))
const GlobalDoseModal = lazy(() => import('@shared/components/ui/GlobalDoseModal'))
import TestConnection from '@shared/components/TestConnection'
import { OnboardingProvider, OnboardingWizard } from '@shared/components/onboarding'
import { DashboardProvider } from '@dashboard/hooks/useDashboardContext.jsx'
import InstallPrompt from '@shared/components/pwa/InstallPrompt'
import { OfflineBanner } from '@shared/components/ui/OfflineBanner'

/**
 * Placeholder exibido enquanto chunk de view carrega
 */
function ViewSkeleton() {
  return (
    <div
      role="status"
      style={{
        minHeight: '60vh',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        color: 'var(--color-text-secondary)',
        fontSize: '14px',
      }}
      aria-busy="true"
      aria-label="Carregando view..."
    >
      <span className="sr-only">Carregando...</span>
    </div>
  )
}

function AppInner() {
  const shouldReduceMotion = useReducedMotion()
  const [session, setSession] = useState(null)
  const [isLoading, setIsLoading] = useState(true)
  const [currentView, setCurrentView] = useState('dashboard')
  const [isChatOpen, setIsChatOpen] = useState(false)
  const [isDoseModalOpen, setIsDoseModalOpen] = useState(false)
  const [doseModalInitialValues, setDoseModalInitialValues] = useState(null)
  const [initialProtocolParams, setInitialProtocolParams] = useState(null)
  const [initialStockParams, setInitialStockParams] = useState(null)
  const [initialTreatmentMedicineId, setInitialTreatmentMedicineId] = useState(null)
  const [showAuth, setShowAuth] = useState(false) // toggles auth UI for unauthenticated visitors

  const { data: notifData } = useNotificationLog({ userId: session?.id, limit: 30, enabled: !!session?.id })
  const { unreadCount } = useUnreadNotificationCount(notifData)

  useEffect(() => {
    // Check initial session
    getCurrentUser()
      .then((user) => {
        setSession(user)
        setIsLoading(false)
      })
      .catch(() => {
        setSession(null)
        setIsLoading(false)
      })

    // Listen for changes
    const {
      data: { subscription },
    } = onAuthStateChange(async (event, session) => {
      if (event === 'SIGNED_OUT') {
        // Refresh token pode ter falhado por race condition (PWA + aba do browser concorrentes).
        // Verificar se outro contexto já renovou a sessão antes de deslogar o usuário.
        const { data: { session: latestSession } } = await supabase.auth.getSession()
        setSession(latestSession?.user ?? null)
        return
      }
      setSession(session?.user ?? null)
    })

    return () => subscription.unsubscribe()
  }, [])

  const navigateToProtocol = (medicineId) => {
    setInitialTreatmentMedicineId(medicineId)
    setCurrentView('treatment')
  }

  const navigateToStock = (medicineId) => {
    setInitialStockParams({ medicineId })
    setCurrentView('stock')
  }

  if (isLoading) {
    return (
      <div
        className="app-container"
        style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh' }}
      >
        <Loading text="Carregando..." />
      </div>
    )
  }

  const isAuthenticated = !!session

  const renderCurrentView = () => {
    if (!session) {
      return showAuth ? (
        <Auth
          onAuthSuccess={() => {
            setShowAuth(false)
            setCurrentView('dashboard')
          }}
          onClose={() => setShowAuth(false)}
        />
      ) : (
        <Suspense fallback={<ViewSkeleton />}>
          <Landing isAuthenticated={false} onOpenAuth={() => setShowAuth(true)} />
        </Suspense>
      )
    }

    switch (currentView) {
      case 'landing':
        return (
          <Suspense fallback={<ViewSkeleton />}>
            <Landing
              isAuthenticated={isAuthenticated}
              onOpenAuth={() => setShowAuth(true)}
              onContinue={() => setCurrentView('dashboard')}
            />
          </Suspense>
        )
      case 'medicines':
        return (
          <Suspense fallback={<ViewSkeleton />}>
            <Medicines onNavigateToProtocol={navigateToProtocol} />
          </Suspense>
        )
      case 'stock':
        return (
          <Suspense fallback={<ViewSkeleton />}>
            <Stock
