import { useState, useMemo } from 'react'
import { motion } from 'framer-motion'
import {
  Sun,
  Moon,
  Sunrise,
  ChevronRight,
  Pill,
  PillBottle,
  CheckCircle2,
  CircleCheckBig,
  CircleAlert,
  Circle,
} from 'lucide-react'
import { useMotion } from '@shared/hooks/useMotion'
import { getNow } from '@utils/dateUtils'
import { DOSE_REGISTRATION_TOLERANCE_MS } from '@dashboard/hooks/useDoseZones'

// Janela ±120min — fonte única em useDoseZones. Reutilizada para getDoseStatus e isWithinActionWindow.
const LATE_WINDOW_MINUTES = DOSE_REGISTRATION_TOLERANCE_MS / 60_000

const PERIODS = [
  { id: 'midnight', label: 'Madrugada', Icon: Moon, timeRange: [0, 6] },
  { id: 'morning', label: 'Manhã', Icon: Sunrise, timeRange: [6, 12] },
  { id: 'afternoon', label: 'Tarde', Icon: Sun, timeRange: [12, 18] },
  { id: 'night', label: 'Noite', Icon: Moon, timeRange: [18, 24] },
]

function getHour(scheduledTime) {
  return parseInt(scheduledTime.split(':')[0], 10)
}

/**
 * Determina o status de uma dose baseado em registro e horário agendado.
 * Uma dose é "missed" apenas quando passou mais de 2h do horário agendado (mesma janela de classifyDose).
 * @param {Object} dose
 * @param {Date} now
 * @returns {'done'|'missed'|'pending'}
 */
function getDoseStatus(dose, now) {
  if (dose.isRegistered) return 'done'
  const [h, m] = dose.scheduledTime.split(':').map(Number)
  const scheduledMinutes = h * 60 + m
  const nowMinutes = now.getHours() * 60 + now.getMinutes()
  // Perdida somente após 2h do horário agendado
  return nowMinutes - scheduledMinutes > LATE_WINDOW_MINUTES ? 'missed' : 'pending'
}

/**
 * Verifica se a dose está dentro da janela de ação (±2h do horário agendado).
 * Fora da janela: botão TOMAR não exibido (muito cedo ou muito tarde).
 */
function isWithinActionWindow(dose, now) {
  const [h, m] = dose.scheduledTime.split(':').map(Number)
  const scheduledMinutes = h * 60 + m
  const nowMinutes = now.getHours() * 60 + now.getMinutes()
  return Math.abs(nowMinutes - scheduledMinutes) <= LATE_WINDOW_MINUTES
}

/**
 * CronogramaDoseItem — Card com status diferenciado: done / missed / pending
 */
function CronogramaDoseItem({ dose, onRegister, stockDays, stockStatus, now }) {
  const status = getDoseStatus(dose, now)
  const canTake = status === 'pending' && isWithinActionWindow(dose, now)
  const done = status === 'done'
  const missed = status === 'missed'
  const showStockBadge = !missed && (stockStatus === 'critical' || stockStatus === 'low')
  const isSupplement = dose.medicineType === 'suplemento'
  const MedicineIcon = isSupplement ? PillBottle : Pill

  return (
    <div className={`cronograma-dose-card cronograma-dose-card--${status}`}>
      {/* Status icon — topo-direita (posição absoluta) */}
      {done && (
        <CircleCheckBig
          size={18}
          className="cronograma-dose-card__status-icon"
          color="var(--color-primary)"
          aria-label="Dose registrada"
        />
      )}
      {missed && (
        <CircleAlert
          size={18}
          className="cronograma-dose-card__status-icon"
          color="var(--color-warning)"
          aria-label="Dose perdida"
        />
      )}

      {/* Ícone do tipo */}
      <div
        className={`cronograma-dose-card__icon-wrap cronograma-dose-card__icon-wrap--${isSupplement ? 'supplement' : 'medicine'}`}
      >
        <MedicineIcon size={20} color="var(--color-white)" aria-hidden="true" />
      </div>

      {/* Bloco principal: info à esquerda, horário grande à direita */}
      <div className="cronograma-dose-card__main">
        <div className="cronograma-dose-card__details">
          {/* Linha 1: nome + concentração */}
          <div className="cronograma-dose-card__name-row">
            <span className="cronograma-dose-card__title">{dose.medicineName}</span>
            {dose.dosagePerPill && dose.dosageUnit && (
              <span className="cronograma-dose-card__strength">
                {dose.dosagePerPill}
                {dose.dosageUnit}
              </span>
            )}
          </div>
          {/* Linha 2: quantidade por dose + badge de estoque */}
          <div className="cronograma-dose-card__intake-row">
            <span className="cronograma-dose-card__intake">
              {dose.dosagePerIntake} comprimido{dose.dosagePerIntake !== 1 ? 's' : ''}
            </span>
            {showStockBadge && (
              <span
                className={`cronograma-dose-card__stock-badge cronograma-dose-card__stock-badge--${stockStatus}`}
              >
                {stockStatus === 'critical' ? 'Crítico' : 'Baixo'}
                {stockDays !== null ? ` ${stockDays}d` : ''}
              </span>
            )}
          </div>
        </div>

        {/* Horário — grande, ocupa a altura de ambas as linhas */}
        <time className="cronograma-dose-card__time" dateTime={dose.scheduledTime}>
          {dose.scheduledTime}
        </time>
      </div>

      {/* Botão TOMAR: apenas dentro da janela ±2h */}
      {canTake && (
        <button
          onClick={() => onRegister?.(dose)}
          aria-label={`Registrar dose de ${dose.medicineName}`}
          className="cronograma-dose-card__btn"
        >
          TOMAR
        </button>
      )}
    </div>
  )
}

/**
 * CronogramaPeriodo — Cronograma de doses agrupado por Madrugada/Manhã/Tarde/Noite.
 *
 * Sempre exibe as 4 zonas durante todo o dia.
 * - Zonas passadas: dimmed + fechadas ao carregar
 * - Zonas vazias: sempre fechadas, mostram empty state ao abrir
 * - Status diferenciado por dose: done / missed / pending
 *
 * @param {Array} allDoses — Todas as doses do dia (expandProtocolsToDoses, enriquecidas com stock)
 * @param {Function} onRegister — callback: onRegister(dose)
 * @param {string} variant — 'complex' (default) ou 'simple' para lista plana
 * @param {Date} now — Instância de data sincronizada com useDoseZones
 */
export default function CronogramaPeriodo({
  allDoses = [],
  onRegister,
  variant = 'complex',
  now = getNow(),
}) {
  const { cascade } = useMotion()
  const currentHour = now.getHours()

  // Zonas que o usuário abriu/fechou explicitamente
  const [manuallyToggledZones, setManuallyToggledZones] = useState({})

  // Lógica de abertura automática (passados → fechados, atual/futuros → abertos, vazios → fechados)
  const autoOpenZones = useMemo(() => {
    return Object.fromEntries(
      PERIODS.map(({ id, timeRange }) => {
        const [start, end] = timeRange
        const isPast = currentHour >= end

        // Se temos doses, fechamos se a zona estiver vazia
        if (allDoses.length > 0) {
          const hasDoses = allDoses.some((d) => {
            const h = getHour(d.scheduledTime)
            return h >= start && h < end
          })
          if (!hasDoses) return [id, false]
        }

        // Padrão: aberto se for atual ou futuro
        return [id, !isPast]
      })
    )
  }, [allDoses, currentHour])

  const toggleZone = (id) => {
    setManuallyToggledZones((prev) => ({
      ...prev,
      [id]: !(manuallyToggledZones[id] ?? autoOpenZones[id])
    }))
  }

  // Agrupar doses por período (sempre 4 períodos — sem .filter)
  const grouped = useMemo(() => {
    return PERIODS.map(({ id, label, Icon, timeRange }) => {
      const [start, end] = timeRange
      const isPast = currentHour >= end
      const isCurrent = currentHour >= start && currentHour < end
      const doses = allDoses
        .filter((d) => {
          const h = getHour(d.scheduledTime)
          return h >= start && h < end
        })
        .sort((a, b) => a.scheduledTime.localeCompare(b.scheduledTime))

      return { id, label, Icon, doses, isPast, isCurrent }
    })
  }, [allDoses, currentHour])

  // ── MODO SIMPLE: lista plana cronológica ──
  if (variant === 'simple') {
    const sorted = [...allDoses].sort((a, b) => a.scheduledTime.localeCompare(b.scheduledTime))
    if (sorted.length === 0) return null
    return (
      <div
        className="cronograma-doses cronograma-doses--simple"
        aria-label="Cronograma de doses de hoje"
      >
        {sorted.map((dose) => (
          <CronogramaDoseItem
            key={`${dose.protocolId}-${dose.scheduledTime}`}
            dose={dose}
            onRegister={onRegister}
            stockDays={dose.stockDays}
            stockStatus={dose.stockStatus}
            now={now}
          />
        ))}
      </div>
    )
  }

  // ── MODO COMPLEX: 4 zonas com accordion ──
  return (
    <motion.div
      style={{ display: 'flex', flexDirection: 'column', gap: '1.25rem' }}
      aria-label="Cronograma de doses de hoje"
      variants={cascade.container}
      initial="hidden"
      animate="visible"
    >
      {grouped.map(({ id, label, Icon, doses, isPast, isCurrent }) => {
        const PeriodIcon = Icon
        const isOpen = manuallyToggledZones[id] ?? autoOpenZones[id]
        const isEmpty = doses.length === 0
        // Passado com conteúdo → verde apagado; passado vazio → cinza esmaecido
        const isPastActive = isPast && !isEmpty
        const isPastEmpty = isPast && isEmpty
        const doneCount = doses.filter((d) => d.isRegistered).length
        const missedCount = isPast ? doses.filter((d) => !d.isRegistered).length : 0

        return (
          <motion.section
            key={id}
            aria-label={`${label}: ${doses.length} dose${doses.length !== 1 ? 's' : ''}`}
            variants={cascade.item}
          >
            {/* Header accordion */}
            <button
              className={[
                'cronograma-period-header',
                isPastActive ? 'cronograma-period-header--past-active' : '',
                isPastEmpty ? 'cronograma-period-header--past' : '',
                isCurrent ? 'cronograma-period-header--current' : '',
              ]
                .filter(Boolean)
                .join(' ')}
              onClick={() => toggleZone(id)}
              aria-expanded={isOpen}
            >
              <PeriodIcon
                size={16}
                color={
                  isPastActive
                    ? 'var(--color-primary)'
                    : isPastEmpty
                      ? 'var(--color-outline-variant)'
                      : 'var(--color-outline)'
                }
                aria-hidden="true"
              />
              <span className="cronograma-period-header__label">{label}</span>

              <div className="cronograma-period-header__right">
                {isEmpty ? (
                  <span className="cronograma-period-header__empty-tag">Vazio</span>
                ) : isPast ? (
                  missedCount > 0 ? (
                    <span className="cronograma-period-header__missed-count">
                      {missedCount} perdida{missedCount !== 1 ? 's' : ''}
                    </span>
                  ) : (
                    <>
                      <span className="cronograma-period-header__done-tag">· Concluído</span>
                      <CheckCircle2
                        size={14}
                        color="var(--color-primary)"
                        aria-hidden="true"
                      />
                    </>
                  )
                ) : (
                  <span className="cronograma-period-header__count">
                    {doneCount}/{doses.length}
                  </span>
                )}
                <ChevronRight
                  size={16}
                  className={`cronograma-period-header__chevron ${isOpen ? 'cronograma-period-header__chevron--open' : ''}`}
                  aria-hidden="true"
                />
              </div>
            </button>

            {/* Conteúdo: empty state ou lista de doses */}
            {isOpen &&
              (isEmpty ? (
                <div className="cronograma-period-empty" role="status">
                  <Circle
                    size={18}
                    color="var(--color-outline-variant)"
                    aria-hidden="true"
                  />
                  <p className="cronograma-period-empty__text">
                    Nenhum medicamento para este período
                  </p>
                </div>
              ) : (
                <div className="cronograma-doses">
                  {doses.map((dose) => (
                    <CronogramaDoseItem
                      key={`${dose.protocolId}-${dose.scheduledTime}`}
                      dose={dose}
                      onRegister={onRegister}
                      stockDays={dose.stockDays}
                      stockStatus={dose.stockStatus}
                      now={now}
                    />
                  ))}
                </div>
              ))}
          </motion.section>
        )
      })}
    </motion.div>
  )
}

/**
 * DailyDoseModal - Modal para exibir detalhes das doses de um dia específico
 *
 * Exibe lista de doses tomadas e perdidas para o dia selecionado no sparkline.
 *
 * @component
 * @example
 * <DailyDoseModal
 *   date="2026-02-11"
 *   isOpen={true}
 *   onClose={() => setIsOpen(false)}
 *   logs={logs}
 *   isLoading={false}
 *   error={null}
 *   dailySummary={{ adherence: 85, taken: 3, expected: 4 }}
 * />
 */

import { useMemo } from 'react'
import Modal from '@shared/components/ui/Modal'
import Loading from '@shared/components/ui/Loading'
import EmptyState from '@shared/components/ui/EmptyState'
import DoseListItem from './DoseListItem'
import { calculateDosesByDate } from '@utils/adherenceLogic'
import { parseLocalDate } from '@utils/dateUtils.js'
import { useFocusTrap } from '@shared/hooks/useFocusTrap'
import './DailyDoseModal.css'

/**
 * Formata data para exibição em português
 * @param {string} dateStr - Data em formato YYYY-MM-DD
 * @returns {string} Data formatada (ex: "terça-feira, 11 de fevereiro")
 */
const formatDate = (dateStr) => {
  if (!dateStr) return ''
  const date = parseLocalDate(dateStr)
  return date.toLocaleDateString('pt-BR', {
    weekday: 'long',
    day: 'numeric',
    month: 'long',
    timeZone: 'America/Sao_Paulo',
  })
}

/**
 * Formata data curta (para aria-label)
 * @param {string} dateStr - Data em formato YYYY-MM-DD
 * @returns {string} Data formatada curta
 */
const formatShortDate = (dateStr) => {
  if (!dateStr) return ''
  const date = parseLocalDate(dateStr)
  return date.toLocaleDateString('pt-BR', {
    day: 'numeric',
    month: 'short',
    timeZone: 'America/Sao_Paulo',
  })
}

/**
 * Componente DailyDoseModal
 *
 * @param {Object} props
 * @param {string} props.date - Data selecionada (YYYY-MM-DD)
 * @param {boolean} props.isOpen - Controle de visibilidade
 * @param {Function} props.onClose - Handler de fechamento
 * @param {Array} props.logs - Logs do dia
 * @param {Array} props.protocols - Protocolos ativos para cálculo de doses perdidas
 * @param {boolean} props.isLoading - Estado de loading
 * @param {Error} props.error - Erro se houver
 * @param {Object} props.dailySummary - Resumo do dia { adherence, taken, expected }
 * @param {Function} props.onRetry - Handler para retry em caso de erro
 */
export function DailyDoseModal({
  date,
  isOpen,
  onClose,
  logs = [],
  protocols = null,
  isLoading = false,
  error = null,
  dailySummary = null,
  onRetry,
}) {
  const { containerRef: modalRef, handleKeyDown } = useFocusTrap(isOpen)

  // Calcular doses tomadas, perdidas e agendadas usando a nova função
  const { takenDoses, missedDoses, scheduledDoses } = useMemo(() => {
    // Se protocols não foi passado, fallback para comportamento anterior
    if (!protocols) {
      return { takenDoses: logs || [], missedDoses: [], scheduledDoses: [] }
    }

    try {
      return calculateDosesByDate(date, logs, protocols)
    } catch (err) {
      console.error('Erro ao calcular doses:', err)
      // Fallback seguro em caso de erro
      return { takenDoses: logs || [], missedDoses: [], scheduledDoses: [] }
    }
  }, [date, logs, protocols])

  const hasDoses = takenDoses.length > 0 || missedDoses.length > 0 || scheduledDoses.length > 0
  const hasScheduledDoses = hasDoses
  const formattedDate = formatDate(date)
  const shortDate = formatShortDate(date)

  // Calcular porcentagem de adesão
  const adherencePercent = dailySummary?.adherence ?? 0
  const adherenceStatus =
    adherencePercent >= 80 ? 'good' : adherencePercent >= 50 ? 'warning' : 'poor'

  return (
    <Modal isOpen={isOpen} onClose={onClose} title={formattedDate}>
      <div
        ref={modalRef}
        className="daily-dose-modal"
        onKeyDown={handleKeyDown}
        role="dialog"
        aria-modal="true"
        aria-labelledby="daily-dose-title"
        data-testid="daily-dose-modal"
      >
        {/* Header com resumo - escondido visualmente pois Modal já tem título */}
        <div id="daily-dose-title" className="sr-only">
          Doses do dia {shortDate}
        </div>

        {/* Badge de adesão */}
        {dailySummary && (
          <div className="daily-dose-summary" aria-live="polite" aria-atomic="true">
            <span
              className={`adherence-badge adherence-badge--${adherenceStatus}`}
              aria-label={`Adesão: ${adherencePercent}%`}
            >
              {adherencePercent}% adesão
            </span>
            <span
              className="dose-count"
              aria-label={`${dailySummary.taken} de ${dailySummary.expected} doses`}
            >
              {dailySummary.taken} de {dailySummary.expected} doses
            </span>
          </div>
        )}

        {/* Estado de loading */}
        {isLoading && (
          <div className="daily-dose-loading">
            <Loading message="Carregando doses..." />
          </div>
        )}

        {/* Estado de erro */}
        {error && !isLoading && (
          <EmptyState
            icon="⚠️"
            title="Erro ao carregar"
            message="Não foi possível carregar os dados deste dia."
            action={
              onRetry
                ? {
                    label: 'Tentar novamente',
                    onClick: onRetry,
                  }
                : null
            }
          />
        )}

        {/* Estado vazio - sem doses agendadas */}
        {!isLoading && !error && !hasScheduledDoses && (
          <EmptyState
            icon="📋"
            title="Nenhuma dose agendada"
            message={`Não há doses programadas para este dia.`}
          />
        )}

        {/* Lista de doses tomadas */}
        {!isLoading && !error && takenDoses.length > 0 && (
          <div className="dose-list-section">
            <h3 className="dose-list-section__title">Doses Tomadas ({takenDoses.length})</h3>
            <div className="dose-list" role="list" aria-label={`Doses tomadas em ${shortDate}`}>
              {takenDoses.map((log, index) => (
                <DoseListItem key={log.id} log={log} isTaken={true} index={index} />
              ))}
            </div>
          </div>
        )}

        {/* Lista de doses perdidas */}
        {!isLoading && !error && missedDoses.length > 0 && (
          <div className="dose-list-section dose-list-section--missed">
            <h3
              className="dose-list-section__title dose-list-section__title--missed"
              aria-live="polite"
            >
              Doses Perdidas ({missedDoses.length})
            </h3>
            <div className="dose-list" role="list" aria-label={`Doses perdidas em ${shortDate}`}>
              {missedDoses.map((log, index) => (
                <DoseListItem
                  key={log.id}
                  log={log}
                  isTaken={false}
                  scheduledTime={log.scheduledTime}
                  index={index}
                />
              ))}
            </div>
          </div>
        )}

        {/* Lista de doses agendadas (futuras) */}
        {!isLoading && !error && scheduledDoses.length > 0 && (
          <div className="dose-list-section dose-list-section--scheduled">
            <h3
              className="dose-list-section__title dose-list-section__title--scheduled"
              aria-live="polite"
            >
              Doses Agendadas ({scheduledDoses.length})
            </h3>
            <div className="dose-list" role="list" aria-label={`Doses agendadas em ${shortDate}`}>
              {scheduledDoses.map((log, index) => (
                <DoseListItem
                  key={log.id}
                  log={log}
                  isTaken={false}
                  status="scheduled"
                  scheduledTime={log.scheduledTime}
                  index={index}
                />
              ))}
            </div>
          </div>
        )}

        {/* Footer informativo */}
        {hasDoses && (
          <div className="daily-dose-footer">
            <p className="daily-dose-hint">💡 Clique em uma dose para ver detalhes</p>
          </div>
        )}
      </div>
    </Modal>
  )
}

export default DailyDoseModal

/**
 * DoseListItem - Componente para exibir uma dose individual na lista do drill-down
 *
 * Mostra informações de uma dose (tomada, perdida ou agendada) com indicador visual de status.
 *
 * @component
 * @example
 * <DoseListItem log={log} status="scheduled" scheduledTime="08:00" />
 */

import { motion } from 'framer-motion'
import { parseISO } from '@utils/dateUtils'
import './DoseListItem.css'

/**
 * Formata horário para exibição
 * @param {string} dateStr - Data/hora ISO 8601
 * @returns {string} Horário formatado (HH:mm)
 */
const formatTime = (dateStr) => {
  if (!dateStr) return '--:--'
  const date = parseISO(dateStr)
  return date.toLocaleTimeString('pt-BR', {
    hour: '2-digit',
    minute: '2-digit',
    timeZone: 'America/Sao_Paulo',
  })
}

/**
 * Formata nome do medicamento (trunca se muito longo)
 * @param {string} name - Nome do medicamento
 * @param {number} maxLength - Comprimento máximo
 * @returns {string} Nome formatado
 */
const formatMedicineName = (name, maxLength = 30) => {
  if (!name) return 'Remédio'
  if (name.length <= maxLength) return name
  return name.substring(0, maxLength - 3) + '...'
}

/**
 * Retorna label de quantidade no plural correto
 * @param {number} quantity - Quantidade
 * @param {string} unit - Unidade (comprimido, cápsula, etc)
 * @returns {string} Label formatado
 */
const getQuantityLabel = (quantity, unit = 'comprimido') => {
  if (quantity === 1) return `1 ${unit}`
  return `${quantity} ${unit}s`
}

/**
 * Componente DoseListItem
 *
 * @param {Object} props
 * @param {Object} props.log - Log da dose
 * @param {string} props.log.id - ID do log
 * @param {string} props.log.taken_at - Data/hora da dose
 * @param {number} props.log.quantity_taken - Quantidade tomada
 * @param {Object} props.log.medicine - Dados do medicamento
 * @param {string} props.log.medicine.name - Nome do medicamento
 * @param {Object} props.log.protocol - Dados do protocolo
 * @param {string} props.log.protocol.name - Nome do protocolo
 * @param {boolean} props.isTaken - Se a dose foi tomada (backward compat)
 * @param {string} props.status - Status: 'taken', 'missed', ou 'scheduled'
 * @param {string} props.scheduledTime - Horário previsto (opcional)
 * @param {Function} props.onClick - Handler de click opcional
 * @param {number} props.index - Índice para animação staggered
 */
export function DoseListItem({ log, isTaken, status, scheduledTime, onClick, index = 0 }) {
  // Determinar o status efetivo
  const effectiveStatus = status || (isTaken ? 'taken' : 'missed')

  const medicineName = formatMedicineName(log.medicine?.name)
  const protocolName = log.protocol?.name || 'Protocolo'
  const unit = log.medicine?.type === 'cápsula' ? 'cápsula' : 'comprimido'
  // Usar expectedQuantity para doses futuras (scheduled/missed), quantity_taken para doses tomadas
  const quantity =
    effectiveStatus === 'taken'
      ? log.quantity_taken || 1
      : log.expectedQuantity || log.quantity_taken || 1
  const quantityLabel = getQuantityLabel(quantity, unit)

  // Horário real se tomada, ou previsto se perdida/agendada
  const displayTime =
    effectiveStatus === 'taken' ? formatTime(log.taken_at) : scheduledTime || '--:--'

  // Label de status em português
  const statusLabels = {
    taken: 'Tomada',
    missed: 'Perdida',
    scheduled: 'Agendada',
  }

  // Ícone baseado no status
  const statusIcons = {
    taken: '✓',
    missed: '✕',
    scheduled: '○',
  }

  return (
    <motion.div
      className={`dose-list-item dose-list-item--${effectiveStatus}`}
      role="listitem"
      onClick={onClick}
      initial={{ opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{
        duration: 0.2,
        delay: index * 0.05, // Staggered animation
      }}
      data-testid={`dose-list-item-${log.id}`}
    >
      <div className="dose-list-item__status" aria-hidden="true">
        <span className={`dose-status-icon dose-status-icon--${effectiveStatus}`}>
          {statusIcons[effectiveStatus]}
        </span>
      </div>

      <div className="dose-list-item__content">
        <div className="dose-list-item__header">
          <span className="dose-medicine-name" title={log.medicine?.name}>
            {medicineName}
          </span>
        </div>

        <div className="dose-list-item__details">
          <span className="dose-protocol-name">{protocolName}</span>
          <span className="dose-quantity" aria-label={`Quantidade: ${quantityLabel}`}>
            {quantityLabel}
          </span>
        </div>
      </div>

      <div className="dose-list-item__time">
        <time
          className="dose-time"
          dateTime={log.taken_at || scheduledTime}
          aria-label={
            effectiveStatus === 'taken'
              ? `Tomada às ${displayTime}`
              : `Prevista para ${displayTime}`
          }
        >
          {displayTime}
        </time>
        <span className={`dose-status-label dose-status-label--${effectiveStatus}`}>
          {statusLabels[effectiveStatus]}
        </span>
      </div>
    </motion.div>
  )
}

export default DoseListItem

import React, { useState, useMemo } from 'react'
import { parseISO } from '@utils/dateUtils'
import { motion, AnimatePresence } from 'framer-motion'
import TreatmentAccordion from '@dashboard/components/TreatmentAccordion'
import SwipeRegisterItem from '@dashboard/components/SwipeRegisterItem'
import PlanBadge from '@dashboard/components/PlanBadge'
import BatchRegisterButton from '@dashboard/components/BatchRegisterButton'
import './DoseZoneList.css'

// Configuração visual de cada zona
const ZONE_CONFIG = {
  late: { icon: '⚠️', label: 'ATRASADAS', color: 'late' },
  now: { icon: '▶', label: 'AGORA', color: 'now' },
  upcoming: { icon: '🕐', label: 'PRÓXIMAS', color: 'upcoming' },
  later: { icon: '📅', label: 'MAIS TARDE', color: 'later' },
  done: { icon: '✓', label: 'REGISTRADAS', color: 'done' },
}

const ZONE_ORDER = ['late', 'now', 'upcoming', 'later', 'done']

/**
 * Determina se uma zona deve iniciar expandida com base na complexidade.
 */
function getDefaultExpanded(zone) {
  if (zone === 'late') return true
  if (zone === 'now') return true
  if (zone === 'upcoming') return true // ação principal quando não há late/now
  return false // later e done: sempre colapsadas
}

/**
 * DoseCard — Card de dose para modo hora (time mode).
 * Mostra horário, nome do medicamento, PlanBadge e botão de registro.
 */
function DoseCard({ dose, onRegisterDose, selectedDoses, onToggleSelection, done = false }) {
  const isSelected = selectedDoses?.has(`${dose.protocolId}:${dose.scheduledTime}`) ?? false

  const displayTime =
    done && dose.registeredAt
      ? parseISO(dose.registeredAt).toLocaleTimeString('pt-BR', {
          hour: '2-digit',
          minute: '2-digit',
          timeZone: 'America/Sao_Paulo',
        })
      : dose.scheduledTime

  const handleCardClick = (e) => {
    if (done || !onToggleSelection || e.target.closest('.dose-card__register-btn')) return
    onToggleSelection(dose.protocolId, dose.scheduledTime)
  }

  return (
    <motion.div
      className={`dose-card${done ? ' dose-card--done' : ''}${isSelected ? ' dose-card--selected' : ''}`}
      data-testid={`dose-card-${dose.protocolId}`}
      initial={{ opacity: 0, y: 4 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.2 }}
    >
      <button
        type="button"
        className="dose-card__select-area"
        onClick={() => onToggleSelection?.(dose.protocolId, dose.scheduledTime)}
        disabled={done || !onToggleSelection}
        style={!done && onToggleSelection ? { cursor: 'pointer' } : { cursor: 'default' }}
      >
        <div className="dose-card__time">{displayTime}</div>
        <div className="dose-card__info">
          <span className="dose-card__name">{dose.medicineName}</span>
          {dose.planBadge && (
            <PlanBadge
              emoji={dose.planBadge.emoji}
              color={dose.planBadge.color}
              planName={dose.treatmentPlanName}
            />
          )}
          <span className="dose-card__dosage">{dose.dosagePerIntake} cp</span>
        </div>
      </button>
      {done ? (
        <span className="dose-card__done-icon" aria-label="Registrada">
          ✓
        </span>
      ) : (
        <button
          className="dose-card__register-btn"
          onClick={() => onRegisterDose(dose.protocolId, dose.dosagePerIntake)}
          aria-label={`Registrar ${dose.medicineName}`}
          type="button"
        >
          ✓
        </button>
      )}
    </motion.div>
  )
}

/**
 * ZoneSection — Seção colapsável de uma zona temporal.
 */
function ZoneSection({ zoneKey, doses, expanded, onToggle, config, children }) {
  if (!doses || doses.length === 0) return null

  return (
    <div className="dose-zone-section" data-testid={`zone-${zoneKey}`}>
      <button
        type="button"
        className={`zone-header zone-header--${config.color}`}
        onClick={onToggle}
        aria-expanded={expanded}
      >
        <span className="zone-header__icon" aria-hidden="true">
          {config.icon}
        </span>
        <span className="zone-header__label">{config.label}</span>
        <span className="zone-header__count">{doses.length}</span>
        <span
          className={`zone-header__chevron${expanded ? ' zone-header__chevron--expanded' : ''}`}
        >
          ▾
        </span>
      </button>

      <AnimatePresence>
        {expanded && (
          <motion.div
            key={`${zoneKey}-content`}
            className="zone-content"
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: 'auto', opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            transition={{ duration: 0.25, ease: 'easeInOut' }}
          >
            <motion.div
              className="zone-content__items"
              variants={{ visible: { transition: { staggerChildren: 0.03 } } }}
              initial="hidden"
              animate="visible"
            >
              {children}
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  )
}

/**
 * Agrupa doses por treatmentPlanId.
 * Doses sem plano ficam em avulsos[].
 */
function groupDosesByPlan(doses) {
  const groupMap = {}
  const avulsos = []

  for (const dose of doses) {
    if (!dose.treatmentPlanId) {
      avulsos.push(dose)
    } else {
      if (!groupMap[dose.treatmentPlanId]) {
        groupMap[dose.treatmentPlanId] = {
          planId: dose.treatmentPlanId,
          planName: dose.treatmentPlanName,
          planBadge: dose.planBadge,
          doses: [],
        }
      }
      groupMap[dose.treatmentPlanId].doses.push(dose)
    }
  }

  return { planGroups: Object.values(groupMap), avulsos }
}

/**
 * Cria objeto protocol sintético para TreatmentAccordion a partir de um grupo de plano.
 */
function makeSyntheticProtocol(group, zoneKey) {
  return {
    name: group.planName || 'Tratamento',
    medicines_count: group.doses.length,
    next_dose: group.doses[0]?.scheduledTime || '--:--',
    next_dose_window_end: null,
    is_in_tolerance_window: zoneKey === 'now' || zoneKey === 'late',
  }
}

/**
 * DoseZoneList — Lista de zonas temporais com doses do dia.
 *
 * Renderiza zonas (ATRASADAS, AGORA, PRÓXIMAS, MAIS TARDE, REGISTRADAS) com suporte
 * a dois modos de visualização:
 * - "time": lista flat com PlanBadge para contexto clínico
 * - "plan": agrupado por TreatmentAccordion (Princípio 2 da visão UX)
 *
 * @param {Object} props
 * @param {Object} props.zones - Output de useDoseZones().zones
 * @param {Object} props.totals - Output de useDoseZones().totals
 * @param {'time'|'plan'} props.viewMode - Modo de visualização
 * @param {'simple'|'moderate'|'complex'} props.complexityMode - Complexidade do paciente
 * @param {Function} props.onRegisterDose - (protocolId, dosagePerIntake) => void
 * @param {Function} props.onBatchRegister - (doseItems[]) => void
 * @param {Function} props.onToggleSelection - (protocolId, scheduledTime) => void
 * @param {Set<string>} props.selectedDoses - IDs selecionados no formato "protocolId:scheduledTime"
 */
export default function DoseZoneList({
  zones,
  viewMode,
  onRegisterDose,
  onBatchRegister,
  onToggleSelection,
  selectedDoses = new Set(),
}) {
  // Inicializar zonas expandidas com base em complexidade e contagens
  const [expandedZones, setExpandedZones] = useState(() => {
    const expanded = new Set()
    for (const zoneKey of ZONE_ORDER) {
      if (getDefaultExpanded(zoneKey)) {
        expanded.add(zoneKey)
      }
    }
    return expanded
  })

  const toggleZone = (zoneKey) => {
    setExpandedZones((prev) => {
      const next = new Set(prev)
      if (next.has(zoneKey)) {
        next.delete(zoneKey)
      } else {
        next.add(zoneKey)
      }
      return next
    })
  }

  // Doses pendentes na zona "agora" (todas, pois registradas vão para zones.done)
  const nowPending = useMemo(() => zones.now || [], [zones.now])

  return (
    <div className="dose-zone-list" data-testid="dose-zone-list">
      {ZONE_ORDER.map((zoneKey) => {
        const doses = zones[zoneKey] || []
        if (doses.length === 0) return null

        const config = ZONE_CONFIG[zoneKey]
        const isExpanded = expandedZones.has(zoneKey)
        const isDone = zoneKey === 'done'

        return (
          <ZoneSection
            key={zoneKey}
            zoneKey={zoneKey}
            doses={doses}
            expanded={isExpanded}
            onToggle={() => toggleZone(zoneKey)}
            config={config}
          >
            {viewMode === 'time' ? (
              <>
                {doses.map((dose) => (
                  <DoseCard
                    key={`${dose.protocolId}:${dose.scheduledTime}`}
                    dose={dose}
                    onRegisterDose={onRegisterDose}
                    selectedDoses={selectedDoses}
                    onToggleSelection={onToggleSelection}
                    done={isDone}
                  />
                ))}
                {zoneKey === 'now' && nowPending.length > 0 && (
                  <BatchRegisterButton
                    pendingCount={nowPending.length}
                    label="Registrar pendentes"
                    onClick={() => onBatchRegister(nowPending)}
                  />
                )}
              </>
            ) : (
              /* Modo plano: agrupa por TreatmentAccordion (Princípio 2 — preservar accordion) */
              <PlanModeZone
                doses={doses}
                zoneKey={zoneKey}
                selectedDoses={selectedDoses}
                onRegisterDose={onRegisterDose}
                onBatchRegister={onBatchRegister}
                onToggleSelection={onToggleSelection}
              />
            )}
          </ZoneSection>
        )
      })}
    </div>
  )
}

/**
 * PlanModeZone — Renderização em modo plano, com TreatmentAccordion por grupo.
 * Extraído para reduzir complexidade do componente principal.
 */
function PlanModeZone({
  doses,
  zoneKey,
  selectedDoses,
  onRegisterDose,
  onBatchRegister,
  onToggleSelection,
}) {
  const { planGroups, avulsos } = useMemo(() => groupDosesByPlan(doses), [doses])

  return (
    <>
      {planGroups.map((group) => (
        <TreatmentAccordion
          key={group.planId}
          protocol={makeSyntheticProtocol(group, zoneKey)}
          onBatchRegister={() => onBatchRegister(group.doses)}
          selectedMedicines={group.doses
            .filter((d) => selectedDoses.has(`${d.protocolId}:${d.scheduledTime}`))
            .map((d) => d.medicineId)}
        >
          {group.doses.map((dose) => (
            <SwipeRegisterItem
              key={`${dose.protocolId}:${dose.scheduledTime}`}
              medicine={{ id: dose.medicineId, name: dose.medicineName }}
              dosagePerIntake={dose.dosagePerIntake}
              time={dose.scheduledTime}
              isSelected={selectedDoses.has(`${dose.protocolId}:${dose.scheduledTime}`)}
              onToggleSelection={() => onToggleSelection(dose.protocolId, dose.scheduledTime)}
              onRegister={(_medicineId, dosage) => onRegisterDose(dose.protocolId, dosage)}
            />
          ))}
        </TreatmentAccordion>
      ))}

      {/* Doses avulsas (sem plano de tratamento) */}
      {avulsos.map((dose) => (
        <SwipeRegisterItem
          key={`${dose.protocolId}:${dose.scheduledTime}`}
          medicine={{ id: dose.medicineId, name: dose.medicineName }}
          dosagePerIntake={dose.dosagePerIntake}
          time={dose.scheduledTime}
          isSelected={selectedDoses.has(`${dose.protocolId}:${dose.scheduledTime}`)}
          onToggleSelection={() => onToggleSelection(dose.protocolId, dose.scheduledTime)}
          onRegister={(_medicineId, dosage) => onRegisterDose(dose.protocolId, dosage)}
        />
      ))}
    </>
  )
}

import { useMemo } from 'react'
import { useDashboard } from '@dashboard/hooks/useDashboardContext'
import { getNow, parseISO, getSaoPauloTime } from '@utils/dateUtils.js'
import './LastDosesWidget.css'

/**
 * LastDosesWidget - Widget de Últimas Doses Tomadas
 *
 * Exibe as 5 doses mais recentes tomadas, ordenadas cronologicamente
 * (mais recentes primeiro), independente do dia em que foram tomadas.
 *
 * Features:
 * - Lista até 5 doses mais recentes
 * - Ordenação inversa cronológica (mais recente primeiro)
 * - Exibe nome do medicamento, horário relativo e quantidade
 * - Link para histórico completo
 * - Estado vazio quando não há doses
 */
export default function LastDosesWidget({ onViewHistory, viewAllClassName }) {
  const { logs, protocols, medicines, isLoading } = useDashboard()

  // Processar e ordenar as últimas doses
  const lastDoses = useMemo(() => {
    if (!logs || logs.length === 0) return []

    // Filtrar apenas doses tomadas (com taken_at válido)
    const takenDoses = logs.filter((log) => log.taken_at && log.quantity_taken > 0)

    // Ordenar por taken_at descendente (mais recente primeiro)
    const sortedDoses = takenDoses.sort((a, b) => {
      return parseISO(b.taken_at).getTime() - parseISO(a.taken_at).getTime()
    })

    // Limitar a 3 doses (balance com próximas doses)
    return sortedDoses.slice(0, 3)
  }, [logs])

  // Criar mapas para lookup rápido
  const medicineMap = useMemo(() => {
    if (!medicines) return new Map()
    return new Map(medicines.map((m) => [m.id, m]))
  }, [medicines])

  const protocolMap = useMemo(() => {
    if (!protocols) return new Map()
    return new Map(protocols.map((p) => [p.id, p]))
  }, [protocols])

  // Formatar horário relativo
  const formatRelativeTime = (dateString) => {
    // R-020: Ambos devem estar no mesmo referencial (shifted SP) para aritmética correta
    const date = getSaoPauloTime(parseISO(dateString))
    const now = getNow()
    const diffMs = now.getTime() - date.getTime()
    const diffMinutes = Math.floor(diffMs / (1000 * 60))
    const diffHours = Math.floor(diffMs / (1000 * 60 * 60))
    const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24))

    const options = { timeZone: 'America/Sao_Paulo' }
    const timeOptions = { ...options, hour: '2-digit', minute: '2-digit' }

    // Menos de 1 hora
    if (diffMinutes < 60) {
      if (diffMinutes < 1) return 'Agora mesmo'
      return `Há ${diffMinutes} ${diffMinutes === 1 ? 'minuto' : 'minutos'}`
    }

    // Menos de 24 horas
    if (diffHours < 24) {
      return `Há ${diffHours} ${diffHours === 1 ? 'hora' : 'horas'}`
    }

    // Ontem
    if (diffDays === 1) {
      return `Ontem às ${date.toLocaleTimeString('pt-BR', timeOptions)}`
    }

    // 2-6 dias atrás
    if (diffDays < 7) {
      const weekdays = ['Domingo', 'Segunda', 'Terça', 'Quarta', 'Quinta', 'Sexta', 'Sábado']
      // M9.0: Extrair dia da semana no fuso de SP
      const dayIndex = parseInt(date.toLocaleDateString('en-US', { ...options, weekday: 'numeric' }), 10) % 7
      const weekday = weekdays[dayIndex]
      return `${weekday} às ${date.toLocaleTimeString('pt-BR', timeOptions)}`
    }

    // Mais de uma semana
    return date.toLocaleDateString('pt-BR', {
      ...timeOptions,
      day: '2-digit',
      month: 'short',
    })
  }

  // Obter informações do medicamento
  const getMedicineInfo = (log) => {
    if (log.medicine) return log.medicine
    return medicineMap.get(log.medicine_id) || { name: 'Medicamento', dosage_unit: 'un' }
  }

  // Obter informações do protocolo
  const getProtocolInfo = (log) => {
    if (log.protocol) return log.protocol
    return protocolMap.get(log.protocol_id)
  }

  if (isLoading) {
    return (
      <div className="last-doses-widget last-doses-widget--loading">
        <div className="last-doses-widget__loading">
          <div className="last-doses-widget__spinner">⟳</div>
          <span>Carregando...</span>
        </div>
      </div>
    )
  }

  return (
    <div className="last-doses-widget">
      {lastDoses.length === 0 ? (
        <div className="last-doses-widget__empty">
          <span className="last-doses-widget__empty-icon">💊</span>
          <p className="last-doses-widget__empty-text">Nenhuma dose registrada recentemente</p>
          <button
            className={viewAllClassName || 'last-doses-widget__empty-action'}
            onClick={onViewHistory}
          >
            Ver histórico completo →
          </button>
        </div>
      ) : (
        <>
          <ul className="last-doses-widget__list" role="list">
            {lastDoses.map((dose, index) => {
              const medicine = getMedicineInfo(dose)
              const protocol = getProtocolInfo(dose)

              return (
                <li
                  key={dose.id || `${dose.medicine_id}-${index}`}
                  className="last-doses-widget__item"
                >
                  <div className="last-doses-widget__item-icon">💊</div>
                  <div className="last-doses-widget__item-content">
                    <div className="last-doses-widget__item-main">
                      <span className="last-doses-widget__item-name">{medicine.name}</span>
                      <span className="last-doses-widget__item-time">
                        {formatRelativeTime(dose.taken_at)}
                      </span>
                    </div>
                    <div className="last-doses-widget__item-details">
                      <span className="last-doses-widget__item-quantity">
                        {dose.quantity_taken * (medicine.dosage_per_pill || 1)}
                        {medicine.dosage_unit || 'mg'}
                      </span>
                      {protocol && (
                        <span className="last-doses-widget__item-protocol">• {protocol.name}</span>
                      )}
                    </div>
                  </div>
                </li>
              )
            })}
          </ul>

          <button
            className={viewAllClassName || 'last-doses-widget__view-all'}
            onClick={onViewHistory}
            aria-label="Ver histórico completo de doses"
          >
            Ver histórico completo →
          </button>
        </>
      )}
    </div>
  )
}

import { Clock } from 'lucide-react'
import { getNow } from '@utils/dateUtils'

/**
 * PriorityDoseCard — Destaque visual para doses urgentes (late + now).
 * Exibe até 3 medicamentos; overflow aparece como "+ N medicamentos".
 * O CTA "Confirmar Agora" registra TODOS (não só os visíveis).
 *
 * @param {Array} doses — DoseItem[] (late + now não registradas)
 * @param {Function} onRegister — onRegister(dose) — para dose única
 * @param {Function} onRegisterAll — onRegisterAll(doses) — para múltiplas
 */
const DISPLAY_LIMIT = 3

export default function PriorityDoseCard({ doses = [], onRegister, onRegisterAll }) {
  if (!doses || doses.length === 0) return null

  const visibleDoses = doses.slice(0, DISPLAY_LIMIT)
  const overflowCount = doses.length - DISPLAY_LIMIT

  const nextTime = doses[0]?.scheduledTime || ''
  const now = getNow()
  const [hour, minute] = nextTime.split(':').map(Number)
  const scheduled = getNow()
  scheduled.setHours(hour, minute, 0, 0)
  const diffMin = Math.round((scheduled - now) / 60000)

  const timeLabel =
    diffMin <= 0
      ? 'Agora'
      : diffMin < 60
        ? `Em ${diffMin} minuto${diffMin !== 1 ? 's' : ''}`
        : `Às ${nextTime}`

  const handleCTA = () => {
    if (doses.length === 1) {
      onRegister?.(doses[0])
    } else {
      onRegisterAll?.(doses)
    }
  }

  // ═══ PRIORITY CARD ═══
  return (
    <div
      role="region"
      aria-label="Dose prioritária"
      style={{
        background:
          'linear-gradient(135deg, var(--color-secondary), var(--color-secondary-container))',
        borderRadius: 'var(--radius-card, 2rem)',
        padding: '1.5rem',
        color: 'var(--color-white)',
        boxShadow: 'var(--shadow-lg)',
      }}
    >
      {/* Header */}
      <div
        style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          marginBottom: '0.5rem',
        }}
      >
        <span
          style={{
            background: 'var(--color-white-20)',
            borderRadius: 'var(--radius-full, 9999px)',
            padding: '0.25rem 0.75rem',
            fontSize: 'var(--text-label-sm, 0.625rem)',
            fontWeight: 'var(--font-weight-bold, 700)',
            letterSpacing: '0.1em',
            textTransform: 'uppercase',
          }}
        >
          ● Prioridade Máxima
        </span>
        <span
          style={{
            display: 'flex',
            alignItems: 'center',
            gap: '0.25rem',
            fontSize: 'var(--text-title-lg, 1.125rem)',
            fontWeight: 'var(--font-weight-bold, 700)',
            fontFamily: 'var(--font-display, Public Sans, sans-serif)',
          }}
        >
          <Clock size={16} aria-hidden="true" />
          {nextTime}
        </span>
      </div>

      {/* Tempo relativo */}
      <p
        style={{
          margin: '0 0 1rem',
          fontSize: 'var(--text-body-lg, 1rem)',
          opacity: 0.85,
          fontFamily: 'var(--font-body, Lexend, sans-serif)',
        }}
      >
        {timeLabel}
      </p>

      {/* Lista de medicamentos — exibe até 3, com linha de overflow */}
      <ul
        style={{
          listStyle: 'none',
          padding: 0,
          margin: '0 0 1.25rem',
          display: 'flex',
          flexDirection: 'column',
          gap: '0.5rem',
        }}
      >
        {visibleDoses.map((dose) => (
          <li
            key={`${dose.protocolId}-${dose.scheduledTime}`}
            style={{
              fontSize: 'var(--text-body-lg, 1rem)',
              opacity: 0.9,
              display: 'flex',
              alignItems: 'center',
              gap: '0.5rem',
            }}
          >
            <span
              style={{
                width: '6px',
                height: '6px',
                borderRadius: '50%',
                background: 'var(--color-white-70)',
                flexShrink: 0,
              }}
              aria-hidden="true"
            />
            <strong>{dose.medicineName}</strong>
            &nbsp;·&nbsp;{dose.dosagePerIntake} comprimido{dose.dosagePerIntake !== 1 ? 's' : ''}
          </li>
        ))}
        {overflowCount > 0 && (
          <li
            style={{
              fontSize: 'var(--text-body-md, 0.875rem)',
              opacity: 0.7,
              paddingLeft: '0.875rem',
            }}
          >
            + {overflowCount} medicamento{overflowCount !== 1 ? 's' : ''}
          </li>
        )}
      </ul>

      {/* CTA — registra TODOS os doses (não só os visíveis) */}
      <button
        onClick={handleCTA}
        aria-label={`Confirmar ${doses.length} dose${doses.length !== 1 ? 's' : ''}`}
        style={{
          width: '100%',
          padding: '1rem',
          minHeight: '56px',
          background: 'var(--color-white-95)',
          color: 'var(--color-secondary)',
          border: 'none',
          borderRadius: 'var(--radius-button, 1.25rem)',
          fontFamily: 'var(--font-body, Lexend, sans-serif)',
          fontSize: 'var(--text-title-lg, 1.125rem)',
          fontWeight: 'var(--font-weight-bold, 700)',
          cursor: 'pointer',
          transition: 'all 200ms ease-out',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
        }}
      >
        Confirmar Agora
      </button>
    </div>
  )
}

import { AnimatePresence, motion } from 'framer-motion'
import SparklineAdesao from './SparklineAdesao'
import './RingGauge.css'

// Raio do ring SVG (viewBox 0 0 120 120, centro em 60,60)
const RADIUS = 46

function getRingColor(score) {
  if (score < 50) return 'var(--color-error)'
  if (score < 70) return 'var(--color-warning)'
  if (score < 85) return 'var(--color-success)'
  return 'var(--color-info)'
}

function getMotivationMessage(score) {
  if (score === 100) return 'Perfeito!'
  if (score >= 85) return 'Muito Bom!'
  if (score >= 70) return 'Bom trabalho!'
  if (score >= 50) return 'Continue assim!'
  return 'Vamos melhorar!'
}

function getStreakIcon(streak) {
  if (streak >= 30) return '🏆'
  if (streak >= 14) return '🔥'
  if (streak >= 7) return '⚡'
  return '🔥'
}

/**
 * RingGauge — Ring gauge circular animado com score de adesão.
 *
 * Componente puro: dados exclusivamente por props (sem context/hooks externos).
 *
 * @param {number} score - 0–100, porcentagem de adesão
 * @param {number} streak - Dias consecutivos
 * @param {'compact'|'medium'|'large'} [size] - Default: 'medium'
 * @param {Function} [onClick] - Click handler (abre HealthScoreDetails)
 * @param {Array} [sparklineData] - 7 pontos {date, adherence} para sparkline inline
 * @param {string} [className] - CSS override
 */
export default function RingGauge({
  score = 0,
  streak = 0,
  size = 'medium',
  onClick,
  sparklineData = [],
  className = '',
}) {
  const circumference = 2 * Math.PI * RADIUS
  const offset = circumference - (score / 100) * circumference
  const ringColor = getRingColor(score)
  const isClickable = Boolean(onClick)

  const svgSize = size === 'large' ? 120 : size === 'compact' ? 56 : 80

  // Testa se o usuário prefere movimento reduzido
  const prefersReducedMotion =
    typeof window !== 'undefined' && window.matchMedia('(prefers-reduced-motion: reduce)').matches

  const ringTransition = prefersReducedMotion
    ? { duration: 0 }
    : { type: 'spring', stiffness: 60, damping: 15 }

  const streakTransition = prefersReducedMotion ? { duration: 0 } : { delay: 0.3, duration: 0.4 }

  const ringElement = (
    <svg
      viewBox="0 0 120 120"
      width={svgSize}
      height={svgSize}
      role="img"
      aria-label={`Adesão: ${score}%. Streak: ${streak} dias`}
      className="ring-gauge__svg"
    >
      {/* Ring de fundo */}
      <circle
        cx="60"
        cy="60"
        r={RADIUS}
        stroke="var(--color-border, #e5e7eb)"
        strokeWidth="8"
        fill="none"
      />
      {/* Ring de progresso */}
      <motion.circle
        cx="60"
        cy="60"
        r={RADIUS}
        stroke={ringColor}
        strokeWidth="8"
        fill="none"
        strokeDasharray={circumference}
        strokeLinecap="round"
        transform="rotate(-90 60 60)"
        initial={{ strokeDashoffset: circumference }}
        animate={{ strokeDashoffset: offset }}
        transition={ringTransition}
        style={{ strokeDashoffset: offset }}
      />
      {/* Score central */}
      <text x="60" y="54" textAnchor="middle" className="ring-gauge__score">
        {score}
      </text>
      <text x="60" y="70" textAnchor="middle" className="ring-gauge__label">
        %
      </text>
    </svg>
  )

  const streakBadge = (
    <motion.div
      className="ring-gauge__streak"
      initial={{ scale: 0 }}
      animate={{ scale: [0, 1.15, 1] }}
      transition={streakTransition}
    >
      <span className="ring-gauge__streak-icon">{getStreakIcon(streak)}</span>
      <span className="ring-gauge__streak-value">{streak}d</span>
    </motion.div>
  )

  if (size === 'large') {
    const Tag = isClickable ? 'button' : 'div'
    return (
      <Tag
        className={`ring-gauge ring-gauge--large ${isClickable ? 'ring-gauge--clickable' : ''} ${className}`}
        onClick={onClick}
        type={isClickable ? 'button' : undefined}
        tabIndex={isClickable ? 0 : undefined}
        onKeyDown={isClickable ? (e) => e.key === 'Enter' && onClick() : undefined}
      >
        <div className="ring-gauge__ring-wrapper">{ringElement}</div>
        <div className="ring-gauge__info">
          <AnimatePresence mode="wait">
            <motion.p
              key={score}
              className="ring-gauge__motivation"
              initial={{ y: 8, opacity: 0 }}
              animate={{ y: 0, opacity: 1 }}
              exit={{ y: -8, opacity: 0 }}
              transition={{ duration: 0.25 }}
            >
              {getMotivationMessage(score)}
            </motion.p>
          </AnimatePresence>
          {streakBadge}
          {sparklineData.length > 0 && (
            <div className="ring-gauge__sparkline">
              <SparklineAdesao adherenceByDay={sparklineData} size="small" />
            </div>
          )}
        </div>
      </Tag>
    )
  }

  if (size === 'medium') {
    const Tag = isClickable ? 'button' : 'div'
    return (
      <Tag
        className={`ring-gauge ring-gauge--medium ${isClickable ? 'ring-gauge--clickable' : ''} ${className}`}
        onClick={onClick}
        type={isClickable ? 'button' : undefined}
        tabIndex={isClickable ? 0 : undefined}
        onKeyDown={isClickable ? (e) => e.key === 'Enter' && onClick() : undefined}
      >
        {ringElement}
        <div className="ring-gauge__medium-content">
          <div className="ring-gauge__medium-top">
            <span className="ring-gauge__score-text">{score}%</span>
            {streakBadge}
          </div>
          {sparklineData.length > 0 && (
            <SparklineAdesao adherenceByDay={sparklineData} size="inline" />
          )}
        </div>
      </Tag>
    )
  }

  // compact
  const Tag = isClickable ? 'button' : 'div'
  return (
    <Tag
      className={`ring-gauge ring-gauge--compact ${isClickable ? 'ring-gauge--clickable' : ''} ${className}`}
      onClick={onClick}
      type={isClickable ? 'button' : undefined}
      tabIndex={isClickable ? 0 : undefined}
      onKeyDown={isClickable ? (e) => e.key === 'Enter' && onClick() : undefined}
    >
      {ringElement}
      <span className="ring-gauge__score-text">{score}%</span>
      {streakBadge}
    </Tag>
  )
}

import { motion, useReducedMotion } from 'framer-motion'
import './RingGaugeRedesign.css'

const RADIUS = 46
const CIRCUMFERENCE = 2 * Math.PI * RADIUS

const SIZE_MAP = {
  large: { svgSize: 120, strokeWidth: 12, fontSize: '1.75rem', labelSize: '0.625rem' },
  medium: { svgSize: 96, strokeWidth: 10, fontSize: '1.25rem', labelSize: '0.6rem' },
  compact: { svgSize: 56, strokeWidth: 8, fontSize: '0.875rem', labelSize: '0.5rem' },
}

export default function RingGaugeRedesign({
  score = 0,
  streak = 0,
  size = 'medium',
  onClick,
  className = '',
}) {
  const prefersReducedMotion = useReducedMotion()
  const { svgSize, strokeWidth, fontSize, labelSize } = SIZE_MAP[size] || SIZE_MAP.medium
  const offset = CIRCUMFERENCE - (score / 100) * CIRCUMFERENCE
  const isClickable = Boolean(onClick)

  // Helper para determinar a cor semântica do stroke (Fase 8 Refinement)
  const getStrokeColor = (s) => {
    if (s === 0) return 'var(--color-gray-300)'
    if (s >= 90) return 'var(--color-score-good)'
    if (s >= 70) return 'var(--color-score-excellent)'
    if (s >= 50) return 'var(--color-score-medium)'
    return 'var(--color-score-critical)'
  }

  const strokeColor = getStrokeColor(score)
  const Tag = isClickable ? 'button' : 'div'

  return (
    <Tag
      className={`ring-gauge-redesign ring-gauge-redesign--${size} ${
        isClickable ? 'ring-gauge-redesign--clickable' : ''
      }${className ? ` ${className}` : ''}`}
      onClick={isClickable ? onClick : undefined}
      type={isClickable ? 'button' : undefined}
      aria-label={`Adesão diária: ${score}%. Streak: ${streak} dias`}
    >
      <svg
        width={svgSize}
        height={svgSize}
        viewBox="0 0 120 120"
        role="img"
        aria-hidden="true"
        className="ring-gauge-redesign__svg-container"
      >
        {/* Track */}
        <circle
          cx="60"
          cy="60"
          r={RADIUS}
          fill="none"
          stroke="var(--color-secondary, #005db6)"
          strokeWidth={strokeWidth}
          opacity="0.2"
        />
        {/* Progress */}
        <motion.circle
          cx="60"
          cy="60"
          r={RADIUS}
          fill="none"
          strokeWidth={strokeWidth}
          strokeLinecap="round"
          strokeDasharray={CIRCUMFERENCE}
          initial={{ strokeDashoffset: CIRCUMFERENCE }}
          animate={{
            strokeDashoffset: offset,
            stroke: strokeColor,
          }}
          transition={
            prefersReducedMotion
              ? { duration: 0 }
              : { duration: 1, delay: 0.5, ease: [0.4, 0, 0.2, 1] }
          }
          style={{ transformOrigin: '50% 50%', transform: 'rotate(-90deg)' }}
        />
        {/* Percentagem */}
        <text
          x="60"
          y="56"
          textAnchor="middle"
          dominantBaseline="middle"
          fill="var(--color-on-surface, #191c1d)"
          fontFamily="var(--font-display, 'Public Sans', sans-serif)"
          fontWeight="700"
          fontSize={fontSize}
        >
          {score}%
        </text>
        {/* Label */}
        <text
          x="60"
          y="72"
          textAnchor="middle"
          dominantBaseline="middle"
          fill="var(--color-outline, #6d7a76)"
          fontFamily="var(--font-body, 'Lexend', sans-serif)"
          fontWeight="500"
          fontSize={labelSize}
        >
          ADESÃO
        </text>
      </svg>

      {/* Streak */}
      {streak > 0 && (
        <div
          className="ring-gauge-redesign__streak"
          aria-label={`Streak: ${streak} dias consecutivos`}
        >
          🔥 {streak} dias
        </div>
      )}
    </Tag>
  )
}

import { useState, useMemo } from 'react'
import { AlertTriangle, AlertCircle, Info, X } from 'lucide-react'
import './SmartAlertsRedesign.css'

/**
 * SmartAlertsRedesign — Componente redesenhado de alertas inteligentes (Wave 15.1)
 * Exibe alertas com severidade (critical/warning/info) em ordem de prioridade
 * Suporta modo simple (max 2 visíveis) e complex (max 5 visíveis)
 *
 * @param {Object} props
 * @param {Array} props.alerts - Array de alertas: [{ id, severity, title, message, actions?, protocol_id? }]
 * @param {Function} props.onAction - Callback ao clicar em ação: (alert, action) => void
 * @param {Boolean} props.isComplex - Se true, exibe até 5 alertas; se false, máximo 2
 * @param {Function} props.onSnooze - Callback ao silenciar: (alertId) => void
 */
const severityOrder = { critical: 0, warning: 1, info: 2 }

export default function SmartAlertsRedesign({
  alerts = [],
  onAction,
  isComplex = false,
  onSnooze,
}) {
  const [showAll, setShowAll] = useState(false)

  // States
  const maxVisible = isComplex ? 5 : 2

  // Memos — ordenação e filtragem
  const sorted = useMemo(
    () => [...alerts].sort((a, b) => severityOrder[a.severity] - severityOrder[b.severity]),
    [alerts]
  )
  const displayed = useMemo(
    () => (showAll ? sorted : sorted.slice(0, maxVisible)),
    [showAll, sorted, maxVisible]
  )
  const hasMore = sorted.length > maxVisible

  // Effects — nenhum necessário neste componente

  // Handlers
  const handleSnooze = (alertId) => {
    if (onSnooze) {
      onSnooze(alertId)
    }
  }

  const handleAction = (alert, action) => {
    if (onAction) {
      onAction(alert, action)
    }
  }

  // Render
  if (alerts.length === 0) {
    return null
  }

  const getIcon = (severity) => {
    switch (severity) {
      case 'critical':
        return <AlertTriangle size={16} aria-hidden="true" />
      case 'warning':
        return <AlertCircle size={16} aria-hidden="true" />
      case 'info':
      default:
        return <Info size={16} aria-hidden="true" />
    }
  }

  return (
    <div className="smart-alerts-redesign" id="smart-alerts-list">
      {displayed.map((alert) => (
        <div
          key={alert.id}
          className={`smart-alert smart-alert--${alert.severity}`}
          role={alert.severity === 'critical' ? 'alert' : 'status'}
          aria-live={alert.severity === 'critical' ? 'assertive' : 'polite'}
        >
          <div className="smart-alert__header">
            {getIcon(alert.severity)}
            <span className="smart-alert__title">{alert.title}</span>
            {onSnooze && (
              <button
                className="smart-alert__snooze"
                onClick={() => handleSnooze(alert.id)}
                aria-label="Silenciar alerta"
              >
                <X size={14} />
              </button>
            )}
          </div>
          <p className="smart-alert__message">{alert.message}</p>
          {alert.actions && alert.actions.length > 0 && (
            <div className="smart-alert__actions">
              {alert.actions.map((action) => (
                <button
                  key={action.label}
                  className={`smart-alert__action smart-alert__action--${action.type || 'primary'}`}
                  onClick={() => handleAction(alert, action)}
                >
                  {action.label} →
                </button>
              ))}
            </div>
          )}
        </div>
      ))}

      {hasMore && !showAll && (
        <button
          className="smart-alerts-redesign__expand"
          onClick={() => setShowAll(true)}
          aria-expanded="false"
          aria-controls="smart-alerts-list"
        >
          Ver todos ({sorted.length})
        </button>
      )}

      {hasMore && showAll && (
        <button
          className="smart-alerts-redesign__expand"
          onClick={() => setShowAll(false)}
          aria-expanded="true"
          aria-controls="smart-alerts-list"
        >
          Recolher
        </button>
      )}
    </div>
  )
}

/**
 * SparklineAdesao - Componente de gráfico de linha para visualização de adesão
 *
 * Gráfico SVG inline mostrando tendência de adesão com cores semânticas e animações suaves.
 *
 * Suporta drill-down: clique em qualquer ponto para ver detalhes do dia.
 * Suporta tooltip interativo: tap no ponto mostra data + % + doses.
 *
 * Tamanhos disponíveis:
 *  - 'inline'   — Minimalista (20px altura) para uso dentro de RingGauge
 *  - 'small'    — Compacto
 *  - 'medium'   — Padrão
 *  - 'large'    — Expandido 7d
 *  - 'expanded' — 30 pontos (Minha Saúde)
 *
 * @component
 */

import { useMemo, useCallback, useState } from 'react'
import { motion, useReducedMotion } from 'framer-motion'
import { analyticsService } from '@dashboard/services/analyticsService'
import { debugLog } from '@shared/utils/logger'
import { getNow, getTodayLocal, addDays, formatLocalDate } from '@utils/dateUtils'
import './SparklineAdesao.css'

/**
 * Helper to check if a date is "today or before" in Brazil time (GMT-3)
 * @param {string} dateStr - Date in format YYYY-MM-DD
 * @returns {boolean} true if date is visible (today or past)
 */
function isDateVisibleInBrazil(dateStr) {
  return dateStr <= getTodayLocal()
}

/**
 * Gera path SVG para o sparkline
 * @param {Array} data - Array de objetos { date, adherence }
 * @param {number} width - Largura do SVG
 * @param {number} height - Altura do SVG
 * @param {number} padding - Padding interno
 * @returns {string} Path SVG
 */
const generateSparklinePath = (data, width, height, padding) => {
  if (!data || data.length === 0) return ''

  const availableWidth = width - padding * 2
  const availableHeight = height - padding * 2
  const stepX = availableWidth / (data.length - 1 || 1)

  const points = data.map((d, i) => {
    const x = padding + i * stepX
    // Inverter Y (100% no topo = y: padding)
    const y = padding + availableHeight - (d.adherence / 100) * availableHeight
    return `${x},${y}`
  })

  // Gerar curva suave usando spline
  return createSmoothPath(points, availableHeight)
}

/**
 * Cria path suave usando curvas quadráticas
 * @param {Array} points - Array de strings "x,y"
 * @param {number} height - Altura disponível
 * @returns {string} Path SVG
 */
const createSmoothPath = (points, height) => {
  if (points.length === 0) return ''
  if (points.length === 1) {
    const [x, y] = points[0].split(',').map(Number)
    return `M ${x},${height} L ${x},${y} L ${x},${height}`
  }

  let path = `M ${points[0]},${height}`

  for (let i = 0; i < points.length; i++) {
    const [x, y] = points[i].split(',').map(Number)

    if (i === 0) {
      path = `M ${x},${height} L ${x},${y}`
    } else if (i < points.length - 1) {
      const [nextX, nextY] = points[i + 1].split(',').map(Number)
      const cpX = (x + nextX) / 2
      path += ` Q ${cpX},${y} ${cpX},${(y + nextY) / 2}`
    } else {
      path += ` L ${x},${y} L ${x},${height}`
    }
  }

  path += ' Z'
  return path
}

/**
 * Retorna cor semântica baseada na adesão
 * @param {number} adherence - Valor de adesão (0-100)
 * @returns {string} Cor CSS
 */
const getAdherenceColor = (adherence) => {
  if (adherence >= 80) return 'var(--color-success, #10b981)'
  if (adherence >= 50) return 'var(--color-warning, #f59e0b)'
  return 'var(--color-error, #ef4444)'
}

/**
 * Formata data YYYY-MM-DD para DD/MM
 */
function formatDate(dateStr) {
  const [, month, day] = dateStr.split('-')
  return `${day}/${month}`
}

/**
 * Componente SparklineAdesao
 *
 * @param {Object} props
 * @param {Array} props.adherenceByDay - Array de objetos { date: 'YYYY-MM-DD', adherence: number, taken: number, expected: number }
 * @param {'inline'|'small'|'medium'|'large'|'expanded'} props.size - Tamanho do gráfico
 * @param {boolean} props.showAxis - Mostrar eixo X
 * @param {boolean} props.showTooltip - Mostrar tooltips de label (legenda)
 * @param {string} props.className - Classes CSS adicionais
 * @param {Function} props.onDayClick - Callback quando um dia é clicado (dayData) => void
 */
export function SparklineAdesao({
  adherenceByDay = [],
  size = 'medium',
  days = null,
  showAxis = false,
  showTooltip = true,
  className = '',
  onDayClick,
}) {
  // Estado do tooltip interativo (tap num ponto)
  const [activePoint, setActivePoint] = useState(null)
  const prefersReducedMotion = useReducedMotion()

  // Handler memoizado para evitar recriações
  const handleDayClick = useCallback(
    (dayData) => {
      analyticsService.track('sparkline_day_clicked', {
        date: dayData.date,
        adherence: dayData.adherence,
        taken: dayData.taken,
        expected: dayData.expected,
      })

      onDayClick?.(dayData)
    },
    [onDayClick]
  )

  const handleSparklineTap = (dayData) => {
    analyticsService.track('sparkline_tapped', {
      date: dayData.date,
      adherence: dayData.adherence,
    })
  }

  const sizes = {
    inline: { width: 120, height: 20, padding: 2 },
    small: { width: 120, height: 32, padding: 4 },
    medium: { width: 200, height: 40, padding: 6 },
    large: { width: 280, height: 48, padding: 8 },
    expanded: { width: 320, height: 56, padding: 8 },
  }

  const { width, height, padding } = sizes[size] || sizes.medium

  // Quantos dias processar: prop days > expanded (30) > outros (7)
  const daysCount = days ?? (size === 'expanded' ? 30 : 7)

  // Processar dados — últimos N dias (filtrando dias futuros no horário do Brasil)
  const chartData = useMemo(() => {
    if (!adherenceByDay || adherenceByDay.length === 0) {
      return []
    }

    const today = getNow()
    const data = []

    // Itera de d-daysCount até d-1 (exclui hoje — adesão de hoje é sempre parcial)
    for (let i = daysCount; i >= 1; i--) {
      const date = addDays(today, -i)
      const dateKey = formatLocalDate(date)

      if (!isDateVisibleInBrazil(dateKey)) {
        continue
      }

      const dayData = adherenceByDay.find((d) => d.date === dateKey)
      data.push({
        date: dateKey,
        dayName: date.toLocaleDateString('pt-BR', { weekday: 'short', timeZone: 'America/Sao_Paulo' }),
        adherence: dayData?.adherence ?? 0,
        taken: dayData?.taken ?? 0,
        expected: dayData?.expected ?? 0,
      })
    }

    debugLog('SparklineAdesao', `chartData final: ${data.length} dias`)
    if (data.length > 0) {
      debugLog('SparklineAdesao', 'Amostra de valores:', {
        primeiro: data[0],
        ultimo: data[data.length - 1],
        todosAdherencia: data.map((d) => d.adherence),
      })
    }
    return data
  }, [adherenceByDay, daysCount])

  // Calcular estatísticas
  const stats = useMemo(() => {
    if (chartData.length === 0) {
      return { average: 0, trend: 'stable' }
    }

    const validData = chartData.filter((d) => d.adherence > 0)
    debugLog('SparklineAdesao', 'Stats:', {
      totalDays: chartData.length,
      validDays: validData.length,
      adherenceValues: chartData.map((d) => d.adherence),
    })
    if (validData.length === 0) {
      debugLog('SparklineAdesao', 'AVISO: Nenhum dia com adherence > 0!')
      return { average: 0, trend: 'stable' }
    }

    const average = Math.round(
      validData.reduce((sum, d) => sum + d.adherence, 0) / validData.length
    )

    let trend = 'stable'
    if (validData.length >= 2) {
      const firstHalf = validData.slice(0, Math.floor(validData.length / 2))
      const secondHalf = validData.slice(Math.floor(validData.length / 2))

      const firstAvg = firstHalf.reduce((sum, d) => sum + d.adherence, 0) / firstHalf.length
      const secondAvg = secondHalf.reduce((sum, d) => sum + d.adherence, 0) / secondHalf.length

      if (secondAvg > firstAvg + 5) trend = 'up'
      else if (secondAvg < firstAvg - 5) trend = 'down'
    }

    return { average, trend }
  }, [chartData])

  // Gerar path do gráfico
  const sparklinePath = useMemo(() => {
    return generateSparklinePath(chartData, width, height, padding)
  }, [chartData, width, height, padding])

  // Gerar área de gradiente
  const gradientArea = useMemo(() => {
    if (!chartData.length || !sparklinePath) return null

    const points = chartData.map((d, i) => {
      const stepX = (width - padding * 2) / (chartData.length - 1 || 1)
      const x = padding + i * stepX
      const y = padding + (width - padding * 2) - (d.adherence / 100) * (height - padding * 2)
      return `${x},${y}`
    })

    const firstX = points[0]?.split(',')[0] || 0
    const lastX = points[points.length - 1]?.split(',')[0] || width

    return `${sparklinePath} L ${lastX},${height} L ${firstX},${height} Z`
  }, [chartData, sparklinePath, width, height, padding])

  // Calcular posições dos pontos de dados
  const dataPoints = useMemo(() => {
    const showDots = showTooltip && size !== 'inline'
    if (!showDots) return []

    return chartData.map((d, i) => {
      const stepX = (width - padding * 2) / (chartData.length - 1 || 1)
      const x = padding + i * stepX
      const y = padding + (height - padding * 2) - (d.adherence / 100) * (height - padding * 2)
      return { ...d, x, y, index: i }
    })
  }, [chartData, width, height, padding, showTooltip, size])

  // Não renderizar se não há dados
  if (chartData.length === 0) {
    return (
      <div
        className={`sparkline-adhesion sparkline-empty ${className}`}
        role="img"
        aria-label="Sem dados de adesão"
      >
        <span className="sparkline-empty-text">Sem dados</span>
      </div>
    )
  }

  // -------------------------
  // SIZE: inline — minimalista (sem labels, dots, stats, tooltip)
  // -------------------------
  if (size === 'inline') {
    return (
      <div
        className={`sparkline-adhesion sparkline-adhesion--inline ${className}`}
        role="img"
        aria-label={`Tendência de adesão: ${stats.average}% média`}
      >
        <svg
          viewBox={`0 0 ${width} ${height}`}
          width="100%"
          height={height}
          className="sparkline-svg"
          preserveAspectRatio="none"
        >
          <defs>
            <linearGradient id="sparklineGradientInline" x1="0%" y1="0%" x2="0%" y2="100%">
              <stop offset="0%" stopColor="var(--color-primary, #ec4899)" stopOpacity="0.3" />
              <stop offset="100%" stopColor="var(--color-primary, #ec4899)" stopOpacity="0.02" />
            </linearGradient>
          </defs>
          {gradientArea && (
            <motion.path
              d={gradientArea}
              fill="url(#sparklineGradientInline)"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ duration: prefersReducedMotion ? 0 : 0.4 }}
            />
          )}
          <motion.path
            d={sparklinePath}
            fill="none"
            stroke="var(--color-primary, #ec4899)"
            strokeWidth="1"
            strokeLinecap="round"
            strokeLinejoin="round"
            initial={{ pathLength: 0, opacity: 0 }}
            animate={{ pathLength: 1, opacity: 1 }}
            transition={{ duration: prefersReducedMotion ? 0 : 0.6, ease: 'easeOut' }}
          />
        </svg>
      </div>
    )
  }

  // -------------------------
  // SIZE: small, medium, large, expanded — renderização completa
  // -------------------------
  const Tag = onDayClick || showTooltip ? 'button' : 'div'

  return (
    <Tag
      className={`sparkline-adhesion sparkline-adhesion--${size} ${className}`}
      role="img"
      aria-label={`Gráfico de adesão: ${stats.average}% média em ${daysCount} dias. Tendência: ${stats.trend}`}
      onClick={(e) => {
        // Fechar tooltip ao clicar fora dos dots
        if (e.target.tagName !== 'circle') {
          setActivePoint(null)
        }
        handleSparklineTap(chartData[chartData.length - 1])
      }}
      type={Tag === 'button' ? 'button' : undefined}
    >
      <svg viewBox={`0 0 ${width} ${height}`} className="sparkline-svg" preserveAspectRatio="none">
        <defs>
          <linearGradient id="sparklineGradient" x1="0%" y1="0%" x2="0%" y2="100%">
            <stop offset="0%" stopColor="var(--color-primary, #ec4899)" stopOpacity="0.3" />
            <stop offset="100%" stopColor="var(--color-primary, #ec4899)" stopOpacity="0.05" />
          </linearGradient>
          <filter id="sparklineGlow">
            <feGaussianBlur stdDeviation="0.5" result="blur" />
            <feMerge>
              <feMergeNode in="blur" />
              <feMergeNode in="SourceGraphic" />
            </feMerge>
          </filter>
        </defs>

        {/* Linha de referência 80% */}
        {showAxis && (
          <line
            x1={padding}
            y1={padding + (height - padding * 2) * 0.2}
            x2={width - padding}
            y2={padding + (height - padding * 2) * 0.2}
            className="sparkline-reference-line"
            strokeDasharray="2,2"
          />
        )}

        {/* Área de gradiente */}
        {gradientArea && (
          <motion.path
            d={gradientArea}
            fill="url(#sparklineGradient)"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ duration: prefersReducedMotion ? 0 : 0.5 }}
          />
        )}

        {/* Linha do sparkline */}
        <motion.path
          d={sparklinePath}
          fill="none"
          stroke="var(--color-primary, #ec4899)"
          strokeWidth="1"
          strokeLinecap="round"
          strokeLinejoin="round"
          filter="url(#sparklineGlow)"
          initial={{ pathLength: 0, opacity: 0 }}
          animate={{ pathLength: 1, opacity: 1 }}
          transition={{ duration: prefersReducedMotion ? 0 : 0.8, ease: 'easeOut' }}
        />

        {/* Pontos de dados clicáveis para drill-down */}
        {dataPoints.map((d) => (
          <motion.circle
            key={d.date}
            cx={d.x}
            cy={d.y}
            r={size === 'small' ? 2.5 : 3}
            fill={getAdherenceColor(d.adherence)}
            className="sparkline-dot sparkline-dot--clickable"
            initial={{ scale: 0 }}
            animate={{ scale: 1 }}
            transition={{ delay: prefersReducedMotion ? 0 : d.index * 0.1, duration: 0.2 }}
            role="button"
            tabIndex={0}
            aria-label={`Ver detalhes de ${d.dayName}: ${d.adherence}% de adesão, ${d.taken} de ${d.expected} doses`}
            onClick={(e) => {
              e.stopPropagation()
              setActivePoint(activePoint === d.index ? null : d.index)
              if (onDayClick) handleDayClick(d)
            }}
            onKeyDown={(e) => {
              if (e.key === 'Enter' || e.key === ' ') {
                e.preventDefault()
                setActivePoint(activePoint === d.index ? null : d.index)
                if (onDayClick) handleDayClick(d)
              }
            }}
            style={{ cursor: 'pointer', pointerEvents: 'all' }}
            data-date={d.date}
            data-adherence={d.adherence}
            data-testid={`sparkline-dot-${d.date}`}
          />
        ))}

        {/* Tooltip interativo ao tap num ponto — só em sizes médios ou maiores */}
        {activePoint !== null &&
          dataPoints[activePoint] &&
          size !== 'small' &&
          (() => {
            const pt = dataPoints[activePoint]
            const tooltipW = 80
            const tooltipH = 36
            const tooltipPad = 4

            // Clamp horizontal para não sair do SVG
            let tx = pt.x - tooltipW / 2
            if (tx < tooltipPad) tx = tooltipPad
            if (tx + tooltipW > width - tooltipPad) tx = width - tooltipPad - tooltipW

            // Posicionar acima do ponto
            const ty = pt.y - tooltipH - 6 < tooltipPad ? pt.y + 8 : pt.y - tooltipH - 6

            return (
              <g className="sparkline-tooltip-overlay" aria-hidden="true">
                <rect
                  x={tx}
                  y={ty}
                  width={tooltipW}
                  height={tooltipH}
                  rx="4"
                  fill="var(--bg-secondary, #1f2937)"
                  stroke="var(--color-border, #374151)"
                  strokeWidth="1"
                />
                <text
                  x={tx + tooltipW / 2}
                  y={ty + 13}
                  textAnchor="middle"
                  className="sparkline-tooltip-date"
                >
                  {formatDate(pt.date)}
                </text>
                <text
                  x={tx + tooltipW / 2}
                  y={ty + 27}
                  textAnchor="middle"
                  className="sparkline-tooltip-value"
                >
                  {pt.adherence}% · {pt.taken}/{pt.expected} doses
                </text>
              </g>
            )
          })()}
      </svg>

      {/* Tooltips de dias (legenda) */}
      {showTooltip && size !== 'expanded' && (
        <div className="sparkline-tooltip-container">
          {chartData.map((d, i) => (
            <div key={d.date} className="sparkline-day-tooltip" style={{ '--day-index': i }}>
              <span className="sparkline-day-name">{d.dayName}</span>
              <span
                className="sparkline-day-value"
                style={{ color: getAdherenceColor(d.adherence) }}
              >
                {d.adherence}%
              </span>
            </div>
          ))}
        </div>
      )}

      {/* Badge de estatística */}
      <div className={`sparkline-stats sparkline-stats-${size}`}>
        <span className="sparkline-average">{stats.average}%</span>
        <span className={`sparkline-trend sparkline-trend-${stats.trend}`}>
          {stats.trend === 'up' && '↑'}
          {stats.trend === 'down' && '↓'}
          {stats.trend === 'stable' && '→'}
        </span>
      </div>
    </Tag>
  )
}

export default SparklineAdesao

import { AlertTriangle } from 'lucide-react'
import { parseLocalDate } from '@utils/dateUtils'

/**
 * StockAlertInline — Banner de alerta de estoque para o Dashboard redesenhado.
 *
 * @param {Array} criticalItems — items com stockStatus === 'critical' ou 'low'
 *   Shape: { medicineName: string, daysRemaining: number, stockStatus: 'critical'|'low', prediction?: { predictedStockoutDate: string } }
 * @param {Function} onNavigateToStock — Callback para navegar para Estoque
 */
export default function StockAlertInline({ criticalItems = [], onNavigateToStock }) {
  if (!criticalItems || criticalItems.length === 0) return null

  const PROGRESS_BAR_MAX_DAYS = 30

  const sorted = [...criticalItems].sort((a, b) => a.daysRemaining - b.daysRemaining)
  const mostCritical = sorted[0]
  const isCritical = mostCritical.stockStatus === 'critical'

  const accentColor = isCritical ? 'var(--color-error)' : 'var(--color-tertiary)'

  const progressPct = Math.max(
    0,
    Math.min((mostCritical.daysRemaining / PROGRESS_BAR_MAX_DAYS) * 100, 100)
  )

  return (
    <div
      role="alert"
      aria-live="polite"
      style={{
        borderLeft: `4px solid ${accentColor}`,
        borderRadius: 'var(--radius-lg, 1rem)',
        padding: '1rem 1.25rem',
        background: isCritical
          ? 'color-mix(in srgb, var(--color-error) 8%, transparent)'
          : 'color-mix(in srgb, var(--color-tertiary-fixed) 40%, transparent)',
        display: 'flex',
        flexDirection: 'column',
        gap: '0.75rem',
      }}
    >
      {/* Título */}
      <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
        <AlertTriangle size={16} color={accentColor} aria-hidden="true" />
        <span
          style={{
            fontFamily: 'var(--font-body, Lexend, sans-serif)',
            fontWeight: 'var(--font-weight-semibold, 600)',
            fontSize: 'var(--text-body-lg, 1rem)',
            color: accentColor,
          }}
        >
          {isCritical ? 'Estoque Crítico' : 'Estoque Baixo'}
          {criticalItems.length > 1
            ? ` · ${criticalItems.length} itens`
            : ` · ${mostCritical.medicineName}`}
        </span>
      </div>

      {/* Barra de progresso */}
      <div>
        <div
          style={{
            fontFamily: 'var(--font-body, Lexend, sans-serif)',
            fontSize: 'var(--text-label-md, 0.75rem)',
            color: 'var(--color-on-surface-variant)',
            marginBottom: '0.375rem',
          }}
        >
          {mostCritical.prediction?.predictedStockoutDate
            ? `Acaba em ~${parseLocalDate(mostCritical.prediction.predictedStockoutDate).toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' })}`
            : `${mostCritical.daysRemaining} dia${mostCritical.daysRemaining !== 1 ? 's' : ''} restante${mostCritical.daysRemaining !== 1 ? 's' : ''}`}
        </div>
        <div
          role="progressbar"
          aria-valuenow={mostCritical.daysRemaining}
          aria-valuemin={0}
          aria-valuemax={PROGRESS_BAR_MAX_DAYS}
          aria-label={`${mostCritical.medicineName}: ${mostCritical.daysRemaining} dias restantes`}
          style={{
            height: '8px',
            borderRadius: 'var(--radius-full, 9999px)',
            background: 'var(--color-surface-container-highest)',
            overflow: 'hidden',
          }}
        >
          <div
            style={{
              height: '100%',
              width: `${progressPct}%`,
              borderRadius: 'var(--radius-full, 9999px)',
              background: accentColor,
              transition: 'width 1s ease-out',
            }}
          />
        </div>
      </div>

      {/* CTA */}
      <button
        onClick={() => onNavigateToStock?.()}
        aria-label="Ir para controle de estoque"
        style={{
          alignSelf: 'flex-end',
          padding: '0.375rem 0.875rem',
          minHeight: '36px',
          background: 'transparent',
          color: accentColor,
          border: `1.5px solid ${accentColor}`,
          borderRadius: 'var(--radius-full, 9999px)',
          fontFamily: 'var(--font-body, Lexend, sans-serif)',
          fontSize: 'var(--text-label-md, 0.75rem)',
          fontWeight: 'var(--font-weight-semibold, 600)',
          cursor: 'pointer',
          whiteSpace: 'nowrap',
          transition: 'all 150ms ease-out',
        }}
      >
        Ver Estoque →
      </button>
    </div>
  )
}

import React, { createContext, useContext, useMemo, useEffect } from 'react'
import { useCachedQueries, invalidateCache } from '@shared/hooks/useCachedQuery'
import { CACHE_KEYS } from '@dosiq/shared-data'
import { onAuthStateChange } from '@shared/utils/supabase'
import {
  calculateAdherenceStats,
  getNextDoseTime,
  getNextDoseWindowEnd,
  isInToleranceWindow,
  calculateDailyIntake,
  calculateDaysRemaining,
  isDoseInToleranceWindow,
  isProtocolActiveOnDate,
} from '@utils/adherenceLogic'
import { formatLocalDate, addDays, getSaoPauloTime, getNow, getTodayLocal, parseISO } from '@utils/dateUtils'
import { medicineService } from '@medications/services/medicineService'
import { protocolService } from '@protocols/services/protocolService'
import { logService } from '@shared/services/api/logService'

const DashboardContext = createContext(null)

/**
 * useDashboardContext - Orquestrador de dados do Health Command Center
 *
 * Centraliza as queries de medicamentos, protocolos e logs para
 * garantir consistência de dados e "custo zero" de queries extras.
 */
export function DashboardProvider({ children }) {
  const streakStartLimit = useMemo(() => {
    const date = getNow()
    date.setDate(date.getDate() - 365) // 1 ano de histórico para streak profundo
    return formatLocalDate(date)
  }, [])

  const queries = useMemo(
    () => [
      {
        key: CACHE_KEYS.MEDICINES,
        fetcher: () => medicineService.getAll(),
      },
      {
        key: CACHE_KEYS.PROTOCOLS, // Buscamos todos para histórico real de adesão e streak
        fetcher: () => protocolService.getAll(),
      },
      {
        key: CACHE_KEYS.LOGS_DEEP_STREAK,
        fetcher: async () => {
          // Slim select: apenas id, taken_at, quantity_taken, protocol_id, medicine_id, status
          // Puxamos até 365 dias (limite 1500) para garantir streaks reais de longa duração
          const result = await logService.getByDateRangeSlim(
            streakStartLimit,
            getTodayLocal(),
            1500
          )
          return result.data
        },
      },
    ],
    [streakStartLimit]
  )

  const { results, isLoading, isFetching, hasError, refetchAll } = useCachedQueries(queries)

  // Assina eventos de autenticação — invalida cache imediatamente no SIGNED_IN/SIGNED_OUT
  useEffect(() => {
    const {
      data: { subscription },
    } = onAuthStateChange((event) => {
      if (event === 'SIGNED_IN' || event === 'SIGNED_OUT') {
        invalidateCache(CACHE_KEYS.MEDICINES)
        invalidateCache(CACHE_KEYS.PROTOCOLS)
        invalidateCache(CACHE_KEYS.LOGS_DEEP_STREAK)
        refetchAll({ force: true })
      }
    })
    return () => subscription.unsubscribe()
  }, [refetchAll])

  const [medicinesResult, protocolsResult, logsResult] = results

  const rawStats = useMemo(() => {
    if (!protocolsResult.data || !logsResult.data) {
      return { score: 0, taken: 0, takenAnytime: 0, expected: 0, currentStreak: 0 }
    }
    return calculateAdherenceStats(logsResult.data, protocolsResult.data, 30)
  }, [protocolsResult.data, logsResult.data])

  // Cálculo de sumário de estoque em memória para "Custo Zero"
  const stockSummary = useMemo(() => {
    const meds = medicinesResult.data || []
    const protocols = protocolsResult.data || []

    // 1. Identificar quais medicamentos possuem protocolos ativos
    const activeMedicineIds = new Set(protocols.filter((p) => p.active).map((p) => p.medicine_id))

    // 2. Filtrar e agregar estoque apenas para medicamentos com protocolos ativos
    return meds
      .filter((m) => activeMedicineIds.has(m.id))
      .map((medicine) => {
        // medicine.stock já vem do medicineService.getAll() via query: '*, stock(*)'
        // Filtramos apenas entradas com quantidade positiva e consolidamos
        const activeStockEntries = (medicine.stock || []).filter((s) => s.quantity > 0)
        const totalQuantity = activeStockEntries.reduce((sum, s) => sum + s.quantity, 0)

        const dailyIntake = calculateDailyIntake(medicine.id, protocols)
        const daysRemaining = calculateDaysRemaining(totalQuantity, dailyIntake)

        // Um medicamento é considerado com estoque baixo se tiver consumo e durar menos de 7 dias
        // ou se o estoque total consolidado for menor ou igual ao limite definido no medicamento (se houver)
        const threshold = medicine.min_stock_threshold || 0

        // Priorização Rígida de Status
        const isZero = totalQuantity === 0
        const isLow =
          !isZero &&
          (dailyIntake > 0
            ? daysRemaining <= 7 || totalQuantity <= threshold
            : totalQuantity <= threshold && totalQuantity > 0)

        return {
          medicine,
          total: totalQuantity,
          daysRemaining,
          isZero,
          isLow,
          dailyIntake,
        }
      })
  }, [medicinesResult.data, protocolsResult.data])

  // Health Score Unificado (Onda 2.5)
  const stats = useMemo(() => {
    const adherenceWeight = 0.6
    const punctualityWeight = 0.2
    const stockWeight = 0.2

    const adherenceRate = rawStats.expected > 0 ? rawStats.takenAnytime / rawStats.expected : 1
    const punctualityRate = rawStats.expected > 0 ? rawStats.taken / rawStats.expected : 1

    const totalMeds = stockSummary.length
    const healthyStockMeds = stockSummary.filter((s) => !s.isLow && !s.isZero).length
    const stockRate = totalMeds > 0 ? healthyStockMeds / totalMeds : 1

    const adherenceScore = Math.round(adherenceRate * 100 * adherenceWeight)
    const punctualityScore = Math.round(punctualityRate * 100 * punctualityWeight)
    const stockScore = Math.round(stockRate * 100 * stockWeight)

    const totalScore = Math.min(adherenceScore + punctualityScore + stockScore, 100)

    return {
      ...rawStats,
      score: totalScore, // Sobrescreve o score simples pelo ponderado
      rates: {
        adherence: adherenceRate,
        punctuality: punctualityRate,
        stock: stockRate,
      },
    }
  }, [rawStats, stockSummary])

  const protocolsWithNextDose = useMemo(() => {
    const protocols = protocolsResult.data || []
    return protocols.map((p) => {
      const nextDose = getNextDoseTime(p)
      return {
        ...p,
        next_dose: nextDose,
        next_dose_window_end: getNextDoseWindowEnd(nextDose),
        is_in_tolerance_window: isInToleranceWindow(nextDose),
      }
    })
  }, [protocolsResult.data])

  // Cálculo client-side de dailyAdherence (últimos 7 dias)
  // Elimina chamada a adherenceService.getDailyAdherence() e suas 2 queries internas
  // (protocols + medicine_logs) — dados já estão disponíveis no context
  const dailyAdherence = useMemo(() => {
    const protocols = protocolsResult.data
    const logs = logsResult.data
    if (!protocols || !logs) return []

    const todayStr = getTodayLocal()
    const days = 7
    const now = getNow()

    // Agrupar logs por dia (formato local YYYY-MM-DD)
    const logsByDay = new Map()
    logs.forEach((log) => {
      const dayKey = formatLocalDate(getSaoPauloTime(parseISO(log.taken_at)))
      logsByDay.set(dayKey, (logsByDay.get(dayKey) || 0) + 1)
    })

    // Gerar array de 7 dias
    const dailyData = []
    for (let i = days - 1; i >= 0; i--) {
      const date = addDays(now, -i)
      const dateKey = formatLocalDate(date)

      // Calcular doses esperadas (filtra protocolos ativos nesta data)
      const dayExpected = protocols.reduce((total, protocol) => {
        if (!isProtocolActiveOnDate(protocol, dateKey)) return total
        const timesPerDay = protocol.time_schedule?.length || 1
        return total + timesPerDay
      }, 0)

      const taken = logsByDay.get(dateKey) || 0
      const adherence = dayExpected > 0 ? Math.round((taken / dayExpected) * 100) : 0

      dailyData.push({
        date: dateKey,
        taken,
        expected: Math.round(dayExpected),
        adherence: Math.min(adherence, 100),
      })
    }

    return dailyData
  }, [protocolsResult.data, logsResult.data])

  const value = useMemo(
    () => ({
      medicines: medicinesResult.data || [],
      protocols: protocolsWithNextDose,
      logs: logsResult.data || [],
      stockSummary,
      stats,
      dailyAdherence,
      isLoading,
      isFetching,
      hasError,
      refresh: refetchAll,
      lastSync: getNow().toISOString(),
      isDoseInToleranceWindow, // Expondo para o Dashboard usar na lógica de alertas
    }),
    [
      medicinesResult.data,
      protocolsWithNextDose,
      logsResult.data,
      stockSummary,
      stats,
      dailyAdherence,
      isLoading,
      isFetching,
      hasError,
      refetchAll,
    ]
  )

  return <DashboardContext.Provider value={value}>{children}</DashboardContext.Provider>
}

// eslint-disable-next-line react-refresh/only-export-components
export function useDashboard() {
  const context = useContext(DashboardContext)
  if (!context) {
    throw new Error('useDashboard deve ser usado dentro de um DashboardProvider')
  }
  return context
}

/**
 * useDoseZones — Hook de classificação temporal de doses (W2-01)
 *
 * Organiza os protocolos ativos em zonas temporais deslizantes relativas ao
 * horário atual: ATRASADAS, AGORA, PRÓXIMAS, MAIS TARDE, REGISTRADAS.
 *
 * As zonas recalculam automaticamente a cada 60 segundos.
 *
 * @module useDoseZones
 */

import { useState, useEffect, useMemo } from 'react'
import { useDashboard } from '@dashboard/hooks/useDashboardContext.jsx'
import {
  parseLocalDate,
  getTodayLocal,
  isProtocolActiveOnDate,
  getNow,
  getSaoPauloTime,
  parseISO,
  cloneDate,
} from '@utils/dateUtils'

/**
 * Tipo DoseItem — Representa uma dose individual expandida de um protocolo.
 * @typedef {Object} DoseItem
 * @property {string} protocolId
 * @property {string} medicineId
 * @property {string} medicineName
 * @property {string} medicineType - 'medicamento' | 'suplemento'
 * @property {string} scheduledTime - "HH:MM"
 * @property {number} dosagePerIntake
 * @property {string|null} treatmentPlanId
 * @property {string|null} treatmentPlanName
 * @property {{ emoji: string, color: string }|null} planBadge
 * @property {boolean} isRegistered
 * @property {string|null} registeredAt - ISO timestamp
 */

/**
 * Janela de tolerância para matching de dose registrada.
 * Deve ser idêntica a LATE_WINDOW_MINUTES em CronogramaPeriodo e lateWindowMinutes em classifyDose.
 * Regra: dose registrada dentro de ±120min do horário agendado conta como tomada.
 */
export const DOSE_REGISTRATION_TOLERANCE_MS = 120 * 60 * 1000 // 120 minutos

/**
 * Verifica se uma dose foi registrada hoje, com tolerância de ±120 minutos.
 * @param {string} protocolId
 * @param {string} scheduledTime - "HH:MM"
 * @param {Array} todayLogs - logs filtrados para hoje
 * @returns {boolean}
 */
export function isDoseRegistered(protocolId, scheduledTime, todayLogs) {
  if (!todayLogs || todayLogs.length === 0) return false
  const [h, m] = scheduledTime.split(':').map(Number)
  return todayLogs.some((log) => {
    if (log.protocol_id !== protocolId) return false
    const logDate = getSaoPauloTime(parseISO(log.taken_at))
    const scheduled = cloneDate(logDate)
    scheduled.setHours(h, m, 0, 0)
    return Math.abs(logDate.getTime() - scheduled.getTime()) <= DOSE_REGISTRATION_TOLERANCE_MS
  })
}

/**
 * Retorna o ISO timestamp do registro se encontrado, null caso contrário.
 * @param {string} protocolId
 * @param {string} scheduledTime
 * @param {Array} todayLogs
 * @returns {string|null}
 */
export function findRegistrationTime(protocolId, scheduledTime, todayLogs) {
  if (!todayLogs || todayLogs.length === 0) return null
  const [h, m] = scheduledTime.split(':').map(Number)
  const log = todayLogs.find((l) => {
    if (l.protocol_id !== protocolId) return false
    const logDate = getSaoPauloTime(parseISO(l.taken_at))
    const scheduled = cloneDate(logDate)
    scheduled.setHours(h, m, 0, 0)
    return Math.abs(logDate.getTime() - scheduled.getTime()) <= DOSE_REGISTRATION_TOLERANCE_MS
  })
  return log ? log.taken_at : null
}

/**
 * Classifica uma dose em uma zona temporal.
 * @param {string} scheduledTime - "HH:MM"
 * @param {Date} now
 * @param {number} lateWindowMinutes - default 120
 * @param {number} nowWindowMinutes - default 60
 * @param {number} upcomingWindowMinutes - default 240
 * @param {boolean} isRegistered
 * @returns {'done'|'late'|'now'|'upcoming'|'later'|null} null = muito antiga, não exibir
 */
export function classifyDose(
  scheduledTime,
  now,
  lateWindowMinutes = 120,
  nowWindowMinutes = 60,
  upcomingWindowMinutes = 240,
  isRegistered = false
) {
  if (isRegistered) return 'done'

  const [hours, minutes] = scheduledTime.split(':').map(Number)
  const scheduled = getSaoPauloTime(now)
  scheduled.setHours(hours, minutes, 0, 0)

  const diffMs = scheduled.getTime() - now.getTime()
  const diffMinutes = diffMs / 60000

  if (diffMinutes < -lateWindowMinutes) return null // muito antiga — não mostrar
  if (diffMinutes < 0) return 'late' // atrasada (0 a -lateWindow)
  if (diffMinutes < nowWindowMinutes) return 'now' // agora
  if (diffMinutes < upcomingWindowMinutes) return 'upcoming' // próximas
  return 'later' // mais tarde
}

/**
 * Expande protocolos em DoseItems individuais (um por horário do time_schedule).
 * @param {Array} protocols
 * @param {Array} todayLogs
 * @returns {DoseItem[]}
 */
export function expandProtocolsToDoses(protocols, todayLogs) {
  const doses = []
  const todayStr = getTodayLocal()

  for (const protocol of protocols) {
    // 1. Excluir protocolos "quando_necessario"
    if (protocol.frequency === 'quando_necessario') continue

    // 2. Resiliência de Cache: Filtrar validade do protocolo para HOJE (GMT-3)
    // Isso protege a UI caso o cache SWR tenha dados obsoletos.
    if (!isProtocolActiveOnDate(protocol, todayStr)) continue

    const times = protocol.time_schedule || []
    for (const time of times) {
      const registrationTime = findRegistrationTime(protocol.id, time, todayLogs)
      doses.push({
        protocolId: protocol.id,
        medicineId: protocol.medicine_id,
        medicineName: protocol.medicine?.name || 'Desconhecido',
        medicineType: protocol.medicine?.type || 'medicamento',
        dosagePerPill: protocol.medicine?.dosage_per_pill ?? null,
        dosageUnit: protocol.medicine?.dosage_unit ?? null,
        scheduledTime: time,
        dosagePerIntake: protocol.dosage_per_intake ?? 1,
        treatmentPlanId: protocol.treatment_plan_id || null,
        treatmentPlanName: protocol.treatment_plan?.name || null,
        planBadge: protocol.treatment_plan
          ? {
              emoji: protocol.treatment_plan.emoji || '📋',
              color: protocol.treatment_plan.color || '#6366f1',
            }
          : null,
        isRegistered: !!registrationTime,
        registeredAt: registrationTime,
      })
    }
  }
  return doses
}

/**
 * Filtra logs de hoje (mesma data local que getTodayLocal()).
 * @param {Array} logs
 * @returns {Array}
 */
export function filterTodayLogs(logs) {
  if (!logs || logs.length === 0) return []
  const todayStr = getTodayLocal()
  const todayDate = parseLocalDate(todayStr)
  const todayStart = todayDate.getTime()
  const todayEnd = todayStart + 24 * 60 * 60 * 1000

  return logs.filter((log) => {
    if (!log.taken_at) return false
    const logTime = getSaoPauloTime(parseISO(log.taken_at)).getTime()
    return logTime >= todayStart && logTime < todayEnd
  })
}

/**
 * useDoseZones — Hook principal
 *
 * @param {Object} [options]
 * @param {number} [options.lateWindowMinutes=120]
 * @param {number} [options.nowWindowMinutes=60]
 * @param {number} [options.upcomingWindowMinutes=240]
 * @returns {{ zones, totals, isLoading, refresh, now }}
 */
export function useDoseZones({
  lateWindowMinutes = 120,
  nowWindowMinutes = 60,
  upcomingWindowMinutes = 240,
} = {}) {
  const { protocols, logs, isLoading, refresh } = useDashboard()

  // Estado de "agora" — recalcula a cada 60 segundos (pausado quando aba não está visível)
  const [now, setNow] = useState(() => getNow())

  useEffect(() => {
    let intervalId = null

    const startInterval = () => {
      if (intervalId) return
      intervalId = setInterval(() => setNow(getNow()), 60_000)
    }

    const stopInterval = () => {
      clearInterval(intervalId)
      intervalId = null
    }

    const handleVisibilityChange = () => {
      if (document.hidden) {
        stopInterval()
      } else {
        setNow(getNow()) // atualizar imediatamente ao retornar
        startInterval()
      }
    }

    document.addEventListener('visibilitychange', handleVisibilityChange)
    startInterval()

    return () => {
      document.removeEventListener('visibilitychange', handleVisibilityChange)
      stopInterval()
    }
  }, [])

  // Filtrar logs de hoje
  const todayLogs = useMemo(() => filterTodayLogs(logs), [logs])

  // Expandir protocolos em doses individuais
  const allDoses = useMemo(
    () => expandProtocolsToDoses(protocols || [], todayLogs),
    [protocols, todayLogs]
  )

  // Classificar doses em zonas
  const zones = useMemo(() => {
    const result = { late: [], now: [], upcoming: [], later: [], done: [] }

    for (const dose of allDoses) {
      const zone = classifyDose(
        dose.scheduledTime,
        now,
        lateWindowMinutes,
        nowWindowMinutes,
        upcomingWindowMinutes,
        dose.isRegistered
      )
      if (zone !== null && result[zone]) {
        result[zone].push(dose)
      }
    }

    // Ordenar cada zona por scheduledTime
    const sortByTime = (a, b) => {
      const [ah, am] = a.scheduledTime.split(':').map(Number)
      const [bh, bm] = b.scheduledTime.split(':').map(Number)
      return ah * 60 + am - (bh * 60 + bm)
    }
    Object.values(result).forEach((arr) => arr.sort(sortByTime))

    return result
  }, [allDoses, now, lateWindowMinutes, nowWindowMinutes, upcomingWindowMinutes])

  // Totais
  const totals = useMemo(() => {
    const taken = zones.done.length
    const pending =
      zones.late.length + zones.now.length + zones.upcoming.length + zones.later.length
    const expected = taken + pending
    return { expected, taken, pending }
  }, [zones])

  return { zones, totals, isLoading, refresh, now }
}

/**
 * Insight Service - Geração e seleção de insights contextuais
 *
 * Funcionalidades:
 * - Geração de insights baseados em dados do usuário
 * - Sistema de prioridade (critical > important > informational)
 * - Frequency capping para evitar repetição
 * - Persistência em localStorage
 * - Integração com analyticsService para insights baseados em padrões de uso
 *
 * @module insightService
 */

import { analyticsService } from './analyticsService'
import { getNow, addDays, parseISO } from '@utils/dateUtils.js'

// Constantes para configuração do serviço
const STORAGE_KEY = 'mr_insight_history'
const MAX_HISTORY = 10
const MIN_DISPLAY_INTERVAL = 0 // 0 = sem frequency capping, rotate entre insights

// Prioridades de insight (menor número = maior prioridade)
export const INSIGHT_PRIORITY = {
  critical: 1,
  high: 2,
  medium: 3,
  low: 4,
  info: 5,
}

// Tipos de insight disponíveis
export const INSIGHT_TYPES = {
  ADHERENCE_POSITIVE: 'ADHERENCE_POSITIVE',
  ADHERENCE_MOTIVATIONAL: 'ADHERENCE_MOTIVATIONAL',
  STREAK_CELEBRATION: 'STREAK_CELEBRATION',
  STOCK_WARNING: 'STOCK_WARNING',
  PROTOCOL_REMINDER: 'PROTOCOL_REMINDER',
  MISSED_DOSE_ALERT: 'MISSED_DOSE_ALERT',
  IMPROVEMENT_OPPORTUNITY: 'IMPROVEMENT_OPPORTUNITY',
}

//=============================================================================
// FUNÇÕES DE ANALYTICS (Capítulo 10)
//=============================================================================

/**
 * Determina o horário de maior atividade do usuário
 * @returns {Object|null} { hour: number, count: number } ou null
 */
function getMostActiveHour() {
  try {
    const sevenDaysAgo = addDays(getNow(), -7)
    const doseEvents = analyticsService.getEvents({
      name: 'dose_registered',
      since: sevenDaysAgo,
    })

    if (doseEvents.length === 0) return null

    const hourCounts = {}
    doseEvents.forEach((event) => {
      // M9.0: Extrair hora no fuso de SP
      const date = parseISO(event.timestamp)
      const hour = parseInt(date.toLocaleTimeString('en-US', { hour: '2-digit', hour12: false, timeZone: 'America/Sao_Paulo' }), 10)
      hourCounts[hour] = (hourCounts[hour] || 0) + 1
    })

    const mostActiveEntry = Object.entries(hourCounts).sort((a, b) => b[1] - a[1])[0]

    if (!mostActiveEntry) return null

    return {
      hour: parseInt(mostActiveEntry[0]),
      count: mostActiveEntry[1],
    }
  } catch {
    console.error('[InsightService] Erro ao buscar horário de maior atividade')
    return null
  }
}

/**
 * Formata horário para exibição
 * @param {number} hour - Hora no formato 24h
 * @returns {string} - Horário formatado
 */
function formatHour(hour) {
  const h = hour % 12 || 12
  const ampm = hour < 12 ? 'da manhã' : hour < 18 ? 'da tarde' : 'da noite'
  return `${h}h ${ampm}`
}

/**
 * Determina quais features o usuário mais utiliza
 * @returns {Object} { mostUsed: string, leastUsed: string }
 */
function getFeatureUsage() {
  try {
    const thirtyDaysAgo = addDays(getNow(), -30)
    const summary = analyticsService.getSummary({ since: thirtyDaysAgo })

    const featureEvents = {
      swipe_used: summary.eventCounts?.['swipe_used'] || 0,
      sparkline_tapped: summary.eventCounts?.['sparkline_tapped'] || 0,
      milestone_achieved: summary.eventCounts?.['milestone_achieved'] || 0,
    }

    const sorted = Object.entries(featureEvents).sort((a, b) => b[1] - a[1])

    return {
      mostUsed: sorted[0]?.[0] || null,
      leastUsed: sorted[sorted.length - 1]?.[0] || null,
    }
  } catch {
    console.error('[InsightService] Erro ao buscar uso de features')
    return { mostUsed: null, leastUsed: null }
  }
}

/**
 * Analisa adesão por dia da semana
 * @returns {Object} { bestDay: string, worstDay: string, bestCount: number, worstCount: number }
 */
function getAdherenceByDayOfWeek() {
  try {
    const thirtyDaysAgo = addDays(getNow(), -30)
    const doseEvents = analyticsService.getEvents({
      name: 'dose_registered',
      since: thirtyDaysAgo,
    })

    if (doseEvents.length === 0) return null

    const dayCounts = {}
    doseEvents.forEach((event) => {
      // M9.0: Fixar fuso de Brasília para determinar dia da semana real
      const day = parseISO(event.timestamp).toLocaleDateString('pt-BR', { 
        weekday: 'long',
        timeZone: 'America/Sao_Paulo'
      })
      dayCounts[day] = (dayCounts[day] || 0) + 1
    })

    const sorted = Object.entries(dayCounts).sort((a, b) => b[1] - a[1])

    if (sorted.length === 0) return null

    return {
      bestDay: sorted[0]?.[0] || null,
      worstDay: sorted[sorted.length - 1]?.[0] || null,
      bestCount: sorted[0]?.[1] || 0,
      worstCount: sorted[sorted.length - 1]?.[1] || 0,
    }
  } catch {
    console.error('[InsightService] Erro ao analisar adesão por dia')
    return null
  }
}

//=============================================================================
// FUNÇÕES DE CRIAÇÃO DE INSIGHTS
//=============================================================================

/**
 * Cria insight sobre melhor horário para lembretes (baseado em analytics)
 * @param {Function} onNavigate - Função de navegação
 * @returns {Object|null} Insight ou null
 */
function createBestTimeInsight(onNavigate) {
  const mostActive = getMostActiveHour()

  if (!mostActive || mostActive.count < 3) return null

  const timeLabel = formatHour(mostActive.hour)

  return {
    id: 'best_time',
    type: INSIGHT_TYPES.IMPROVEMENT_OPPORTUNITY,
    priority: 'info',
    icon: '🕐',
    text: `Você costuma registrar doses às ${timeLabel}. Considere agendar mais lembretes neste horário!`,
    highlight: timeLabel,
    actionLabel: 'Configurar Lembretes',
    onAction: () => {
      analyticsService.track('insight_action', { insight_id: 'best_time' })
      onNavigate?.('profile')
    },
  }
}

/**
 * Cria insight sobre feature não utilizada
 * @param {Function} onNavigate - Função de navegação
 * @returns {Object|null} Insight ou null
 */
function createFeatureDiscoveryInsight(onNavigate) {
  const usage = getFeatureUsage()

  // Se usuário nunca usou sparkline mas usa swipe regularmente
  if (usage.leastUsed === 'sparkline_tapped' && usage.mostUsed === 'swipe_used') {
    return {
      id: 'feature_discovery_sparkline',
      type: INSIGHT_TYPES.IMPROVEMENT_OPPORTUNITY,
      priority: 'info',
      icon: '📊',
      text: 'Você sabia que pode tocar no gráfico de adesão para ver detalhes diários?',
      highlight: 'tocar no gráfico',
      actionLabel: 'Experimentar',
      onAction: () => {
        analyticsService.track('insight_action', { insight_id: 'feature_discovery_sparkline' })
        onNavigate?.('stats')
      },
    }
  }

  return null
}

/**
 * Cria insight sobre dia da semana com menor adesão
 * @param {Function} onNavigate - Função de navegação
 * @returns {Object|null} Insight ou null
 */
function createWeakDayInsight(onNavigate) {
  const dayAnalysis = getAdherenceByDayOfWeek()

  if (!dayAnalysis || !dayAnalysis.worstDay || dayAnalysis.bestCount === 0) return null

  // Se o pior dia tem significativamente menos doses (menos de 50% do melhor)
  if (dayAnalysis.worstCount > 0 && dayAnalysis.worstCount < dayAnalysis.bestCount * 0.5) {
    return {
      id: 'weak_day',
      type: INSIGHT_TYPES.ADHERENCE_MOTIVATIONAL,
      priority: 'medium',
      icon: '📅',
      text: `Sua adesão é menor aos ${dayAnalysis.worstDay}. Configure lembretes extras para este dia!`,
      highlight: dayAnalysis.worstDay,
      actionLabel: 'Configurar Lembretes',
      onAction: () => {
        analyticsService.track('insight_action', { insight_id: 'weak_day' })
        onNavigate?.('profile')
      },
    }
  }

  return null
}

/**
 * Gera todos os insights possíveis baseados nos dados do usuário
 * @param {Object} params - Parâmetros de dados do usuário
 * @returns {Array} - Lista de insights aplicáveis
 */
export function generateAllInsights({ stats, dailyAdherence, stockSummary, logs, onNavigate }) {
  const insights = []

  // Insight: Celebração de Streak (threshold reduzido para ser mais inclusivo)
  if (stats.currentStreak >= 5) {
    insights.push({
      id: 'streak_achievement',
      type: INSIGHT_TYPES.STREAK_CELEBRATION,
      priority: 'low',
      icon: '🔥',
      text: `Você está em uma sequência de ${stats.currentStreak} dias! Continue assim!`,
      highlight: `${stats.currentStreak} dias`,
      actionLabel: 'Ver Histórico',
      onAction: () => {
        analyticsService.track('insight_action', { insight_id: 'streak_achievement' })
        onNavigate?.('history')
      },
    })
  }

  // Insight: Semana Perfeita
  if (stats.adherence === 100) {
    insights.push({
      id: 'perfect_week',
      type: INSIGHT_TYPES.ADHERENCE_POSITIVE,
      priority: 'low',
      icon: '⭐',
      text: 'Semana perfeita! 100% de adesão nos últimos 7 dias.',
      highlight: '100% de adesão',
      actionLabel: 'Compartilhar',
      onAction: () => {
        analyticsService.track('insight_action', { insight_id: 'perfect_week' })
        shareAchievement()
      },
    })
  }

  // Insight: Boa Semana (adesão >= 80%)
  if (stats.adherence >= 80 && stats.adherence < 100) {
    insights.push({
      id: 'good_week',
      type: INSIGHT_TYPES.ADHERENCE_POSITIVE,
      priority: 'low',
      icon: '👍',
      text: `Sua adesão esta semana está em ${Math.round(stats.adherence)}%. Muito bem! Continue assim!`,
      highlight: `${Math.round(stats.adherence)}%`,
      actionLabel: 'Ver Histórico',
      onAction: () => {
        analyticsService.track('insight_action', { insight_id: 'good_week' })
        onNavigate?.('history')
      },
    })
  }

  // Insight: Melhoria de Adesão
  const trend = calculateTrendFromData(dailyAdherence)
  if (trend.direction === 'up' && trend.percentage >= 10) {
    insights.push({
      id: 'improvement',
      type: INSIGHT_TYPES.ADHERENCE_POSITIVE,
      priority: 'low',
      icon: '📈',
      text: `Sua adesão melhorou ${trend.percentage}% em relação à semana anterior!`,
      highlight: `${trend.percentage}% melhor`,
      actionLabel: 'Ver Detalhes',
      onAction: () => {
        analyticsService.track('insight_action', { insight_id: 'improvement' })
        onNavigate?.('stats')
      },
    })
  }

  // Insight: Estoque Saudável
  const lowStockCount = stockSummary?.filter((s) => s.isLow || s.isZero).length || 0
  if (lowStockCount === 0 && stockSummary?.length > 0) {
    insights.push({
      id: 'stock_healthy',
      type: INSIGHT_TYPES.ADHERENCE_POSITIVE,
      priority: 'info',
      icon: '✅',
      text: 'Todos os medicamentos com estoque saudável. Ótimo planejamento!',
      highlight: 'estoque saudável',
      actionLabel: 'Ver Estoque',
      onAction: () => {
        analyticsService.track('insight_action', { insight_id: 'stock_healthy' })
        onNavigate?.('stock')
      },
    })
  }

  // Insight: Doses Pendentes Hoje
  const todayMissed = countTodayMissedDoses(logs, dailyAdherence)
  if (todayMissed > 0 && todayMissed <= 2) {
    insights.push({
      id: 'missed_doses_today',
      type: INSIGHT_TYPES.ADHERENCE_MOTIVATIONAL,
      priority: 'medium',
      icon: '⏰',
      text: `Você tem ${todayMissed} doses pendentes hoje. Que tal completar agora?`,
      highlight: `${todayMissed} doses pendentes`,
      actionLabel: 'Registrar Doses',
      onAction: () => {
        analyticsService.track('insight_action', { insight_id: 'missed_doses_today' })
        onNavigate?.('register')
      },
    })
  }

  // Insight: Adesão Baixa (threshold ajustado para motivar users entre 50-80%)
  if (stats.adherence < 80 && stats.adherence > 0) {
    insights.push({
      id: 'low_adherence_week',
      type: INSIGHT_TYPES.ADHERENCE_MOTIVATIONAL,
      priority: 'medium',
      icon: '💪',
      text: `Sua adesão esta semana está em ${Math.round(stats.adherence)}%. Vamos melhorar juntos!`,
      highlight: `${Math.round(stats.adherence)}%`,
      actionLabel: 'Ver Protocolos',
      onAction: () => {
        analyticsService.track('insight_action', { insight_id: 'low_adherence_week' })
        onNavigate?.('protocols')
      },
    })
  }

  // Insight: Streak Quebrado
  if (stats.currentStreak === 0 && stats.longestStreak >= 3) {
    insights.push({
      id: 'streak_broken',
      type: INSIGHT_TYPES.ADHERENCE_MOTIVATIONAL,
      priority: 'high',
      icon: '🔄',
      text: `Seu streak foi interrompido. Seu recorde foi ${stats.longestStreak} dias. Recomece agora!`,
      highlight: `${stats.longestStreak} dias`,
      actionLabel: 'Registrar Dose',
      onAction: () => {
        analyticsService.track('insight_action', { insight_id: 'streak_broken' })
        onNavigate?.('register')
      },
    })
  }

  // Insight: Protocolos Ativos
  const activeProtocols = stats.activeProtocols || 0
  if (activeProtocols > 0 && activeProtocols <= 3) {
    insights.push({
      id: 'protocol_reminder',
      type: INSIGHT_TYPES.PROTOCOL_REMINDER,
      priority: 'info',
      icon: '📋',
      text: `Você tem ${activeProtocols} protocolo${activeProtocols > 1 ? 's' : ''} ativo${activeProtocols > 1 ? 's' : ''}. Todos em dia!`,
      highlight: `${activeProtocols} protocolo${activeProtocols > 1 ? 's' : ''}`,
      actionLabel: 'Ver Protocolos',
      onAction: () => {
        analyticsService.track('insight_action', { insight_id: 'protocol_reminder' })
        onNavigate?.('protocols')
      },
    })
  }

  // Insights Baseados em Analytics (Capítulo 10)
  const bestTimeInsight = createBestTimeInsight(onNavigate)
  if (bestTimeInsight) insights.push(bestTimeInsight)

  const featureDiscoveryInsight = createFeatureDiscoveryInsight(onNavigate)
  if (featureDiscoveryInsight) insights.push(featureDiscoveryInsight)

  const weakDayInsight = createWeakDayInsight(onNavigate)
  if (weakDayInsight) insights.push(weakDayInsight)

  return insights.filter((insight) => insight !== null)
}

/**
 * Calcula tendência a partir dos dados diários
 * @param {Array} dailyAdherence - Dados de adesão diária
 * @returns {Object} - Tendência calculada
 */
function calculateTrendFromData(dailyAdherence) {
  if (!dailyAdherence || dailyAdherence.length < 7) {
    return { direction: 'neutral', percentage: 0 }
  }

  const currentWeek = dailyAdherence.slice(-7)
  const previousWeek = dailyAdherence.slice(-14, -7)

  if (previousWeek.length === 0) {
    return { direction: 'neutral', percentage: 0 }
  }

  const currentAvg = currentWeek.reduce((sum, d) => sum + d.adherence, 0) / currentWeek.length
  const previousAvg = previousWeek.reduce((sum, d) => sum + d.adherence, 0) / previousWeek.length

  const percentageChange = previousAvg > 0 ? ((currentAvg - previousAvg) / previousAvg) * 100 : 0

  let direction = 'neutral'
  if (percentageChange > 5) direction = 'up'
  else if (percentageChange < -5) direction = 'down'

  return {
    direction,
    percentage: Math.abs(Math.round(percentageChange)),
  }
}

/**
 * Conta doses perdidas hoje
 * @param {Array} logs - Logs de doses
 * @param {Array} dailyAdherence - Dados de adesão diária
 * @returns {number} - Quantidade de doses perdidas
 */
function countTodayMissedDoses(logs, dailyAdherence) {
  if (!dailyAdherence || dailyAdherence.length === 0) return 0

  const today = dailyAdherence[dailyAdherence.length - 1]
  if (!today) return 0

  const taken = today.taken || 0
  const expected = today.expected || 0

  return Math.max(0, expected - taken)
}

