/**
 * useHapticFeedback.js - Hook para feedback tátil (vibração)
 *
 * Funcionalidades:
 * - Vibration API para Android Chrome
 * - Fallback silencioso em iOS/desktop
 * - Tipos de haptic: success, warning, error, selection, impact
 * - Suporte a prefers-reduced-motion
 */

import { useCallback } from 'react'

/**
 * Tipos de feedback háptico pré-definidos
 */
const HAPTIC_PATTERNS = {
  // Feedback positivo (sucesso)
  success: {
    duration: 50,
    pattern: null,
  },
  // Feedback de atenção (aviso)
  warning: {
    duration: 100,
    pattern: null,
  },
  // Feedback negativo (erro)
  error: {
    duration: 200,
    pattern: null,
  },
  // Feedback de seleção
  selection: {
    duration: 10,
    pattern: null,
  },
  // Feedback de impacto leve
  impact: {
    duration: 20,
    pattern: null,
  },
  // Confete/celebração
  celebration: {
    duration: 15,
    pattern: [15, 10, 15, 10, 15, 10, 50],
  },
  // Pulso (para registro de dose)
  pulse: {
    duration: 30,
    pattern: null,
  },
  // Shake (erro de validação)
  shake: {
    duration: 500,
    pattern: [50, 30, 50, 30, 50],
  },
}

/**
 * Hook useHapticFeedback
 *
 * @returns {Object} { trigger, isSupported, vibrate }
 *
 * @example
 * const { trigger, vibrate } = useHapticFeedback()
 *
 * // Usar tipo pré-definido
 * trigger('success')
 *
 * // Vibração customizada
 * vibrate(100)
 */
export function useHapticFeedback() {
  // Verificar se Vibration API é suportada
  const isSupported =
    typeof navigator !== 'undefined' &&
    typeof navigator.vibrate === 'function' &&
    !navigator.userAgent.match(/iPhone|iPad|iPod/i)

  // Verificar prefers-reduced-motion
  const prefersReducedMotion =
    typeof window !== 'undefined' && window.matchMedia('(prefers-reduced-motion: reduce)').matches

  /**
   * Função principal de haptic feedback
   * @param {string} type - Tipo de haptic ('success', 'warning', 'error', 'selection', 'impact', 'celebration', 'pulse', 'shake')
   * @param {Object} options - Opções adicionais
   */
  const trigger = useCallback(
    (type, options = {}) => {
      // Se reduced-motion está ativo, não vibrate
      if (prefersReducedMotion) {
        return
      }

      // Se API não é suportada, retorna silenciosamente
      if (!isSupported) {
        return
      }

      const pattern = HAPTIC_PATTERNS[type] || HAPTIC_PATTERNS.selection

      // Se há pattern customizado via options, usa ele
      const patternToUse = options.pattern || pattern.pattern
      const duration = options.duration || pattern.duration

      try {
        if (patternToUse) {
          // Usar pattern de vibração
          navigator.vibrate(patternToUse)
        } else {
          // Usar duração simples
          navigator.vibrate(duration)
        }
      } catch (err) {
        // Silenciosamente ignora erros de vibration API
        console.debug('Haptic feedback error:', err)
      }
    },
    [isSupported, prefersReducedMotion]
  )

  /**
   * Função de vibração direta
   * @param {number|number[]} duration - Duração em ms ou array de pattern
   */
  const vibrate = useCallback(
    (duration) => {
      if (prefersReducedMotion || !isSupported) {
        return
      }

      try {
        navigator.vibrate(duration)
      } catch (err) {
        console.debug('Haptic vibration error:', err)
      }
    },
    [isSupported, prefersReducedMotion]
  )

  return {
    trigger,
    vibrate,
    isSupported,
  }
}

// Exportar padrões para uso externo se necessário
export { HAPTIC_PATTERNS }

export default useHapticFeedback

/**
 * webQueryCache — Instancia do query cache para a plataforma web
 *
 * Criado via factory do shared-data com:
 * - webStorageAdapter: persistencia via localStorage (via contrato H3.1)
 * - logger: console do browser
 * - configuracoes padrao do projeto
 *
 * IMPORTANTE: init() e chamado aqui para hidratar o cache no bootstrap da web.
 * Em outras plataformas (mobile), o bootstrap chama init() explicitamente.
 *
 * Estrategia de coexistencia (H3.3):
 * - Este modulo cria a nova instancia de cache
 * - useCachedQuery.js importa daqui (nao mais de queryCache.js legado)
 * - queryCache.js legado removido apos validacao bem-sucedida
 */
import { createQueryCache } from '@dosiq/shared-data'
import { webStorageAdapter } from '@shared/platform/storage/webStorageAdapter'

const logger = {
  log: (msg) => {
    if (import.meta.env.DEV) console.debug(msg)
  },
  warn: (msg) => console.warn(msg),
  error: (msg) => console.error(msg),
}

export const webQueryCache = createQueryCache({
  storage: webStorageAdapter,
  logger,
  staleTime: 30_000,
  maxEntries: 200,
  persistKey: 'dosiq_query_cache',
})

// Hidratacao automatica no bootstrap web.
// init() e idempotente — chamadas multiplas sao seguras.
webQueryCache.init().catch((err) => {
  console.warn('[webQueryCache] Falha na inicializacao:', err)
})

/**
 * Logger com suporte a development mode
 * Reduz poluição de console em produção
 *
 * @module logger
 */

const isDev = typeof window !== 'undefined' && process.env.NODE_ENV === 'development'

/**
 * Log de debug (só em development)
 * @param {string} tag - Prefixo [tag] do log
 * @param {string} message - Mensagem principal
 * @param {...*} args - Dados adicionais (opcionais)
 */
export function debugLog(tag, message, ...args) {
  if (isDev) {
    console.log(`[${tag}] ${message}`, ...args)
  }
}

/**
 * Log de erro/warning (sempre, mas formatado)
 * @param {string} tag - Prefixo [tag]
 * @param {string} message - Mensagem
 * @param {...*} args - Erro opcional e outros dados
 */
export function errorLog(tag, message, ...args) {
  console.error(`[${tag}] ${message}`, ...args)
}

/**
 * Log condicional (quando expressão é true)
 * @param {boolean} condition - Condição
 * @param {string} tag - Prefixo
 * @param {string} message - Mensagem
 * @param {...*} args - Dados
 */
export function conditionalLog(condition, tag, message, ...args) {
  if (condition) {
    debugLog(tag, message, ...args)
  }
}

import { useState } from 'react'
import { X } from 'lucide-react'
import { signIn, signUp } from '@shared/utils/supabase'
import './Auth.css'

export default function Auth({ onAuthSuccess, onClose }) {
  const [isLogin, setIsLogin] = useState(true)
  const [email, setEmail] = useState('')
  const [password, setPassword] = useState('')
  const [isLoading, setIsLoading] = useState(false)
  const [error, setError] = useState(null)
  const [message, setMessage] = useState(null)

  const handleSubmit = async (e) => {
    e.preventDefault()
    setIsLoading(true)
    setError(null)
    setMessage(null)

    try {
      if (isLogin) {
        await signIn(email, password)
        if (onAuthSuccess) onAuthSuccess()
      } else {
        await signUp(email, password)
        setMessage('Conta criada! Verifique seu email para confirmar o cadastro.')
        setIsLogin(true)
      }
    } catch (err) {
      console.error(err)
      let msg = 'Ocorreu um erro.'
      if (err.message.includes('Invalid login credentials')) {
        msg = 'Email ou senha incorretos.'
      } else if (err.message.includes('User already registered')) {
        msg = 'Usuário já cadastrado.'
      } else if (err.message.includes('Password should be at least')) {
        msg = 'A senha deve ter pelo menos 6 caracteres.'
      }
      setError(msg)
    } finally {
      setIsLoading(false)
    }
  }

  return (
    <div className="auth-container">
      <div className="auth-card">
        {onClose && (
          <button className="auth-close-btn" onClick={onClose} aria-label="Fechar">
            <X size={20} />
          </button>
        )}
        <div className="auth-header">
          <div className="logo-container">
            <img src="/logo-new.svg" alt="Dosiq" className="auth-logo" />
          </div>
          <h1>{isLogin ? 'Bem-vindo de volta' : 'Crie sua conta'}</h1>
          <p className="auth-subtitle">
            {isLogin ? 'Acesse sua agenda de medicamentos' : 'Comece a gerenciar sua saúde hoje'}
          </p>
        </div>

        <form onSubmit={handleSubmit} className="auth-form">
          <div className="form-group">
            <label htmlFor="email">Email</label>
            <input
              id="email"
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="seu@email.com"
              required
              className="auth-input"
            />
          </div>

          <div className="form-group">
            <label htmlFor="password">Senha</label>
            <input
              id="password"
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="••••••••"
              required
              minLength={6}
              className="auth-input"
            />
          </div>

          {error && <div className="auth-error">{error}</div>}
          {message && <div className="auth-message">{message}</div>}

          <button type="submit" className="auth-submit-btn" disabled={isLoading}>
            {isLoading ? 'Carregando...' : isLogin ? 'Entrar' : 'Cadastrar'}
          </button>
        </form>

        <div className="auth-footer">
          <p>
            {isLogin ? 'Não tem uma conta?' : 'Já tem uma conta?'}
            <button
              className="toggle-auth-btn"
              onClick={() => {
                setIsLogin(!isLogin)
                setError(null)
                setMessage(null)
              }}
            >
              {isLogin ? 'Cadastre-se' : 'Entrar'}
            </button>
          </p>
        </div>
      </div>
    </div>
  )
}

import { useState, useEffect, useCallback } from 'react'
import { medicineService, protocolService, stockService } from '@shared/services' // Import protocolService and stockService
import Button from '@shared/components/ui/Button'
import Loading from '@shared/components/ui/Loading'
import Modal from '@shared/components/ui/Modal'
import EmptyState from '@shared/components/ui/EmptyState'
import MedicineForm from '@medications/components/MedicineForm'
import MedicineCard from '@medications/components/MedicineCard'
import './Medicines.css'

export default function Medicines({ onNavigateToProtocol }) {
  const [medicines, setMedicines] = useState([])
  const [isLoading, setIsLoading] = useState(true)
  const [error, setError] = useState(null)
  const [isModalOpen, setIsModalOpen] = useState(false)
  const [editingMedicine, setEditingMedicine] = useState(null)
  const [successMessage, setSuccessMessage] = useState('')
  const [filterType, setFilterType] = useState('all') // 'all', 'medicamento', 'suplemento'
  const [medicineDependencies, setMedicineDependencies] = useState({}) // { medicineId: { hasProtocols: boolean, hasStock: boolean } }

  const loadDependencies = useCallback(async (medicines) => {
    const dependencies = {}
    for (const medicine of medicines) {
      const [protocols, stock] = await Promise.all([
        protocolService.getByMedicineId(medicine.id),
        stockService.getByMedicine(medicine.id),
      ])
      dependencies[medicine.id] = {
        hasProtocols: protocols.length > 0,
        hasStock: stock.length > 0,
      }
    }
    setMedicineDependencies(dependencies)
  }, [])

  const loadMedicines = useCallback(async () => {
    try {
      setIsLoading(true)
      setError(null)
      const data = await medicineService.getAll()
      setMedicines(data)

      // Load dependencies
      await loadDependencies(data)
    } catch (err) {
      setError('Erro ao carregar medicamentos: ' + err.message)
      console.error(err)
    } finally {
      setIsLoading(false)
    }
  }, [loadDependencies])

  useEffect(() => {
    loadMedicines()
  }, [loadMedicines])

  const handleAdd = () => {
    setEditingMedicine(null)
    setIsModalOpen(true)
  }

  const handleEdit = (medicine) => {
    setEditingMedicine(medicine)
    setIsModalOpen(true)
  }

  const handleSave = async (medicineData) => {
    try {
      if (editingMedicine) {
        await medicineService.update(editingMedicine.id, medicineData)
        showSuccess('Medicamento atualizado com sucesso!')
      } else {
        const newMedicine = await medicineService.create(medicineData)
        showSuccess('Medicamento cadastrado com sucesso!')

        // UX: Offer to create a protocol immediately
        if (
          window.confirm('✨ Medicamento criado! Deseja criar um protocolo de uso para ele agora?')
        ) {
          if (onNavigateToProtocol) {
            onNavigateToProtocol(newMedicine.id)
            return // Exit early to avoid closing/reloading the current screen unnecessarily
          }
        }
      }

      setIsModalOpen(false)
      setEditingMedicine(null)
      await loadMedicines()
    } catch (err) {
      throw new Error('Erro ao salvar medicamento: ' + err.message)
    }
  }

  const handleDelete = async (medicine) => {
    const hasDependencies =
      medicineDependencies[medicine.id]?.hasProtocols || medicineDependencies[medicine.id]?.hasStock

    if (hasDependencies) {
      const confirmation = window.confirm(
        `Este medicamento possui${medicineDependencies[medicine.id].hasProtocols ? 'protocolos e' : ''} ${medicineDependencies[medicine.id].hasStock ? 'estoque' : ''} associado(s).\nTem certeza que deseja excluí-lo?`
      )
      if (!confirmation) {
        return
      }
    }
    if (!window.confirm(`Tem certeza que deseja excluir "${medicine.name}"?`)) {
      return
    }

    try {
      await medicineService.delete(medicine.id)
      showSuccess('Medicamento excluído com sucesso!')
      await loadMedicines()
    } catch (err) {
      setError('Erro ao excluir medicamento: ' + err.message)
      console.error(err)
    }
  }

  const showSuccess = (message) => {
    setSuccessMessage(message)
    setTimeout(() => setSuccessMessage(''), 3000)
  }

  if (isLoading) {
    return (
      <div className="medicines-view">
        <Loading text="Carregando medicamentos..." />
      </div>
    )
  }

  return (
    <div className="medicines-view">
      <div className="medicines-header">
        <div>
          <h2>💊 Medicamentos e Suplementos</h2>
          <p className="medicines-subtitle">Gerencie seus medicamentos cadastrados</p>
        </div>
        <Button variant="primary" onClick={handleAdd}>
          ➕ Adicionar
        </Button>
      </div>

      <div className="filter-tabs" style={{ marginBottom: '20px', display: 'flex', gap: '10px' }}>
        <Button
          variant={filterType === 'all' ? 'primary' : 'outline'}
          onClick={() => setFilterType('all')}
          size="sm"
        >
          Todos
        </Button>
        <Button
          variant={filterType === 'medicamento' ? 'primary' : 'outline'}
          onClick={() => setFilterType('medicamento')}
          size="sm"
        >
          Medicamentos
        </Button>
        <Button
          variant={filterType === 'suplemento' ? 'primary' : 'outline'}
          onClick={() => setFilterType('suplemento')}
          size="sm"
        >
          Suplementos
        </Button>
      </div>

      {successMessage && <div className="success-banner fade-in">✅ {successMessage}</div>}

      {error && <div className="error-banner fade-in">❌ {error}</div>}

      {medicines.length === 0 ? (
        <EmptyState
          illustration="protocols"
          title="Nenhum medicamento cadastrado"
          description="Cadastre seus medicamentos para começar a controlar sua saúde"
          ctaLabel="Cadastrar Medicamento"
          onCtaClick={handleAdd}
        />
      ) : (
        <div className="medicines-grid">
          {medicines
            .filter((m) => filterType === 'all' || m.type === filterType)
            .map((medicine) => {
              const hasDependencies =
                medicineDependencies[medicine.id]?.hasProtocols ||
                medicineDependencies[medicine.id]?.hasStock
              return (
                <MedicineCard
                  key={medicine.id}
                  medicine={medicine}
                  onEdit={handleEdit}
                  onDelete={handleDelete}
                  hasDependencies={hasDependencies} // Pass this prop to MedicineCard
                />
              )
            })}
        </div>
      )}

      <Modal
        isOpen={isModalOpen}
        onClose={() => {
          setIsModalOpen(false)
          setEditingMedicine(null)
        }}
      >
        <MedicineForm
          medicine={editingMedicine}
          onSave={handleSave}
          onCancel={() => {
            setIsModalOpen(false)
            setEditingMedicine(null)
          }}
        />
      </Modal>
    </div>
  )
}

import { useState, useEffect, useCallback } from 'react'
import { medicineService, protocolService, treatmentPlanService } from '@shared/services'
import Button from '@shared/components/ui/Button'
import Loading from '@shared/components/ui/Loading'
import Modal from '@shared/components/ui/Modal'
import ProtocolForm from '@protocols/components/ProtocolForm'
import ProtocolCard from '@protocols/components/ProtocolCard'
import TreatmentPlanForm from '@protocols/components/TreatmentPlanForm'
import Card from '@shared/components/ui/Card'
import { calculateTitrationData } from '@utils/titrationUtils'
import './Protocols.css'

export default function Protocols({ initialParams, onClearParams, onNavigateToStock }) {
  const [medicines, setMedicines] = useState([])
  const [protocols, setProtocols] = useState([])
  const [treatmentPlans, setTreatmentPlans] = useState([])
  const [isLoading, setIsLoading] = useState(true)
  const [error, setError] = useState(null)
  const [isModalOpen, setIsModalOpen] = useState(false)
  const [isPlanModalOpen, setIsPlanModalOpen] = useState(false)
  const [editingProtocol, setEditingProtocol] = useState(null)
  const [editingPlan, setEditingPlan] = useState(null)
  const [successMessage, setSuccessMessage] = useState('')

  const loadData = useCallback(async () => {
    try {
      setIsLoading(true)
      setError(null)

      const [medicinesData, protocolsData, plansData] = await Promise.all([
        medicineService.getAll(),
        protocolService.getAll(),
        treatmentPlanService.getAll(),
      ])

      // Enrich protocols with titration data
      const enrichedProtocols = protocolsData.map((p) => ({
        ...p,
        titration_scheduler_data: calculateTitrationData(p),
      }))

      setMedicines(medicinesData)
      setProtocols(enrichedProtocols)
      setTreatmentPlans(plansData)
    } catch (err) {
      setError('Erro ao carregar dados: ' + err.message)
      console.error(err)
    } finally {
      setIsLoading(false)
    }
  }, [])

  useEffect(() => {
    loadData()
  }, [loadData])

  useEffect(() => {
    if (initialParams?.medicineId && medicines.length > 0) {
      setIsModalOpen(true)
      setEditingProtocol(null)
    }
  }, [initialParams, medicines])

  const handleAdd = () => {
    if (medicines.length === 0) {
      setError('Cadastre um medicamento antes de criar protocolos')
      return
    }
    setEditingProtocol(null)
    setIsModalOpen(true)
  }

  const handleAddPlan = () => {
    setEditingPlan(null)
    setIsPlanModalOpen(true)
  }

  const handleEdit = (protocol) => {
    setEditingProtocol(protocol)
    setIsModalOpen(true)
  }

  const handleEditPlan = (plan) => {
    setEditingPlan(plan)
    setIsPlanModalOpen(true)
  }

  const handleSave = async (protocolData) => {
    try {
      if (editingProtocol) {
        await protocolService.update(editingProtocol.id, protocolData)
        showSuccess('Protocolo atualizado com sucesso!')
      } else {
        await protocolService.create(protocolData)
        showSuccess('Protocolo criado com sucesso!')

        if (
          window.confirm(
            'Protocolo criado! Deseja adicionar o estoque inicial deste medicamento agora?'
          )
        ) {
          onNavigateToStock(protocolData.medicine_id)
        }
      }

      setIsModalOpen(false)
      setEditingProtocol(null)
      if (onClearParams) onClearParams()
      await loadData()
    } catch (err) {
      throw new Error('Erro ao salvar protocolo: ' + err.message)
    }
  }

  const handleSavePlan = async (planData) => {
    try {
      if (editingPlan) {
        await treatmentPlanService.update(editingPlan.id, planData)
        showSuccess('Plano de tratamento atualizado!')
      } else {
        await treatmentPlanService.create(planData)
        showSuccess('Plano de tratamento criado!')
      }

      setIsPlanModalOpen(false)
      setEditingPlan(null)
      await loadData()
    } catch (err) {
      throw new Error('Erro ao salvar plano: ' + err.message)
    }
  }

  const handleToggleActive = async (protocol) => {
    try {
      await protocolService.update(protocol.id, { active: !protocol.active })
      showSuccess(`Protocolo ${!protocol.active ? 'ativado' : 'pausado'} com sucesso!`)
      await loadData()
    } catch (err) {
      setError('Erro ao atualizar protocolo: ' + err.message)
      console.error(err)
    }
  }

  const handleDelete = async (protocol) => {
    if (!window.confirm(`Tem certeza que deseja excluir o protocolo "${protocol.name}"?`)) {
      return
    }

    try {
      await protocolService.delete(protocol.id)
      showSuccess('Protocolo excluído com sucesso!')
      await loadData()
    } catch (err) {
      setError('Erro ao excluir protocolo: ' + err.message)
      console.error(err)
    }
  }

  const handleDeletePlan = async (plan) => {
    if (
      !window.confirm(
        `Tem certeza que deseja excluir o plano "${plan.name}" e desvincular seus remédios?`
      )
    ) {
      return
    }

    try {
      await treatmentPlanService.delete(plan.id)
      showSuccess('Plano excluído com sucesso!')
      await loadData()
    } catch (err) {
      setError('Erro ao excluir plano: ' + err.message)
      console.error(err)
    }
  }

  const showSuccess = (message) => {
    setSuccessMessage(message)
    setTimeout(() => setSuccessMessage(''), 3000)
  }

  // Separar protocolos ativos e inativos
  const activeProtocols = protocols.filter((p) => p.active)
  const inactiveProtocols = protocols.filter((p) => !p.active)

  if (isLoading) {
    return (
      <div className="protocols-view">
        <Loading text="Carregando tratamentos..." />
      </div>
    )
  }

  return (
    <div className="protocols-view">
      <div className="protocols-header">
        <div>
          <h2>📋 Protocolos</h2>
          <p className="protocols-subtitle">
            Gerencie seus protocolos e planos de tratamento agrupados
          </p>
        </div>
        <div style={{ display: 'flex', gap: 'var(--space-2)' }}>
          <Button variant="outline" onClick={handleAddPlan}>
            📁 Novo Plano (Grupo)
          </Button>
          <Button variant="primary" onClick={handleAdd}>
            ➕ Criar Protocolo
          </Button>
        </div>
      </div>

      {successMessage && <div className="success-banner fade-in">✅ {successMessage}</div>}

      {error && <div className="error-banner fade-in">❌ {error}</div>}

      {medicines.length === 0 ? (
        <div className="empty-state">
          <div className="empty-icon">📋</div>
          <h3>Nenhum medicamento cadastrado</h3>
          <p>Cadastre medicamentos primeiro para criar protocolos</p>
        </div>
      ) : (
        <div className="protocols-content">
          {/* Planos de Tratamentos */}
          {treatmentPlans.length > 0 && (
            <div className="treatment-plans-section">
              <h3 className="section-title plans">📁 Planos de Tratamento</h3>
              <div className="plans-grid">
                {treatmentPlans.map((plan) => (
                  <Card key={plan.id} className="treatment-plan-card">
                    <div className="plan-header">
                      <div>
                        <h4>{plan.name}</h4>
                        <p className="plan-objective">{plan.objective}</p>
                      </div>
                      <div className="plan-actions">
                        <Button variant="ghost" size="sm" onClick={() => handleEditPlan(plan)}>
                          ✏️
                        </Button>
                        <Button variant="ghost" size="sm" onClick={() => handleDeletePlan(plan)}>
                          🗑️
                        </Button>
                      </div>
                    </div>
                    {plan.description && <p className="plan-desc">{plan.description}</p>}

                    <div className="plan-protocols-list">
                      {plan.protocols && plan.protocols.length > 0 ? (
                        plan.protocols.map((p) => (
                          <div key={p.id} className="plan-protocol-row">
                            <span>💊 {p.name}</span>
                            <span className={`titration-status-mini ${p.titration_status}`}>
                              {p.titration_status === 'titulando' ? '📈 Titulando' : '✅'}
                            </span>
                          </div>
                        ))
                      ) : (
                        <p className="empty-plan">Nenhum remédio vinculado ainda.</p>
                      )}
                    </div>
                  </Card>
                ))}
              </div>
            </div>
          )}

          {/* Protocolos ativos */}
          {activeProtocols.length > 0 && (
            <div className="protocols-section">
              <h3 className="section-title active">
                {treatmentPlans.length > 0
                  ? '🔍 Todos os Protocolos Ativos'
                  : '✅ Protocolos Ativos'}{' '}
                ({activeProtocols.length})
              </h3>
              <div className="protocols-grid">
                {activeProtocols.map((protocol) => (
                  <ProtocolCard
                    key={protocol.id}
                    protocol={protocol}
                    onEdit={handleEdit}
                    onToggleActive={handleToggleActive}
                    onDelete={handleDelete}
                  />
                ))}
              </div>
            </div>
          )}

          {/* Protocolos inativos */}
          {inactiveProtocols.length > 0 && (
            <div className="protocols-section">
              <h3 className="section-title inactive">
                ⏸️ Protocolos Pausados ({inactiveProtocols.length})
              </h3>
              <div className="protocols-grid">
                {inactiveProtocols.map((protocol) => (
                  <ProtocolCard
                    key={protocol.id}
                    protocol={protocol}
                    onEdit={handleEdit}
                    onToggleActive={handleToggleActive}
                    onDelete={handleDelete}
                  />
                ))}
              </div>
            </div>
          )}
        </div>
      )}

      {/* Modal para Protocolos */}
      <Modal
        isOpen={isModalOpen}
        onClose={() => {
          setIsModalOpen(false)
          setEditingProtocol(null)
          if (onClearParams) onClearParams()
        }}
      >
        <ProtocolForm
          medicines={medicines}
          treatmentPlans={treatmentPlans}
          protocol={editingProtocol}
          initialValues={initialParams ? { medicine_id: initialParams.medicineId } : null}
          onSave={handleSave}
          onCancel={() => {
            setIsModalOpen(false)
            setEditingProtocol(null)
            if (onClearParams) onClearParams()
          }}
        />
      </Modal>

      {/* Modal para Planos de Tratamento */}
      <Modal
        isOpen={isPlanModalOpen}
        onClose={() => {
          setIsPlanModalOpen(false)
          setEditingPlan(null)
        }}
      >
        <TreatmentPlanForm
          plan={editingPlan}
          onSave={handleSavePlan}
          onCancel={() => {
            setIsPlanModalOpen(false)
            setEditingPlan(null)
          }}
        />
      </Modal>
    </div>
  )
}

import { useState, useEffect } from 'react'
import { supabase, signOut, updatePassword } from '@shared/utils/supabase'
import { getNow } from '@utils/dateUtils'
import Button from '@shared/components/ui/Button'
import Loading from '@shared/components/ui/Loading'
import Modal from '@shared/components/ui/Modal'
import ExportDialog from '@features/export/components/ExportDialog'
import ReportGenerator from '@features/reports/components/ReportGenerator'
import './Settings.css'

export default function Settings({ onNavigate }) {
  const [user, setUser] = useState(null)
  const [settings, setSettings] = useState(null)
  const [isLoading, setIsLoading] = useState(true)
  const [telegramToken, setTelegramToken] = useState(null)
  const [newPassword, setNewPassword] = useState('')
  const [message, setMessage] = useState(null)
  const [error, setError] = useState(null)
  const [isExportDialogOpen, setIsExportDialogOpen] = useState(false)
  const [isReportModalOpen, setIsReportModalOpen] = useState(false)

  useEffect(() => {
    loadProfile()
  }, [])

  const loadProfile = async () => {
    try {
      const {
        data: { user },
      } = await supabase.auth.getUser()
      setUser(user)

      const { data, error } = await supabase
        .from('user_settings')
        .select('*')
        .eq('user_id', user.id)
        .single() // Might fail if no settings exist yet

      if (!error && data) {
        setSettings(data)
      } else if (error && error.code !== 'PGRST116') {
        // Ignore "not found"
        console.error(error)
      }
    } catch (err) {
      console.error(err)
    } finally {
      setIsLoading(false)
    }
  }

  const handleLogout = async () => {
    try {
      await signOut()
      // App.jsx will handle redirect due to auth state change
    } catch (err) {
      console.error(err)
    }
  }

  const handleUpdatePassword = async (e) => {
    e.preventDefault()
    if (newPassword.length < 6) {
      setError('Senha deve ter no mínimo 6 caracteres')
      return
    }

    try {
      await updatePassword(newPassword)
      setMessage('Senha atualizada com sucesso!')
      setNewPassword('')
      setTimeout(() => setMessage(null), 3000)
    } catch (err) {
      setError('Erro ao atualizar senha: ' + err.message)
    }
  }

  const generateTelegramToken = async () => {
    const token = Math.random().toString(36).substring(2, 8).toUpperCase()

    try {
      const { error } = await supabase.from('user_settings').upsert(
        {
          user_id: user.id,
          verification_token: token,
          updated_at: getNow(),
        },
        { onConflict: 'user_id' }
      )

      if (error) throw error

      setTelegramToken(token)
    } catch (err) {
      console.error(err)
      setError('Erro ao gerar token. Tente novamente.')
    }
  }

  const handleDisconnectTelegram = async () => {
    if (
      !window.confirm(
        'Deseja realmente desconectar o Telegram? Você parará de receber notificações.'
      )
    )
      return

    try {
      const { error } = await supabase
        .from('user_settings')
        .update({
          telegram_chat_id: null,
          verification_token: null,
          updated_at: getNow(),
        })
        .eq('user_id', user.id)

      if (error) throw error

      setSettings((prev) => ({ ...prev, telegram_chat_id: null }))
      setTelegramToken(null)
      setMessage('Telegram desconectado com sucesso!')
      setTimeout(() => setMessage(null), 3000)
    } catch (err) {
      console.error(err)
      setError('Erro ao desconectar Telegram.')
    }
  }

  if (isLoading) return <Loading />

  return (
    <div className="settings-container">
      <h2 className="page-title">Configurações</h2>

      <div className="settings-section">
        <h3>Minha Conta</h3>
        <div className="profile-info">
          <div className="info-row">
            <span className="label">Email</span>
            <span className="value">{user?.email}</span>
          </div>
          <div className="info-row">
            <span className="label">ID</span>
            <span className="value mono">{user?.id?.slice(0, 8)}...</span>
          </div>
        </div>

        <form onSubmit={handleUpdatePassword} className="password-form">
          <h4>Alterar Senha</h4>
          <div className="input-group">
            <input
              type="password"
              placeholder="Nova senha"
              value={newPassword}
              onChange={(e) => setNewPassword(e.target.value)}
              className="settings-input"
            />
            <Button type="submit" disabled={!newPassword}>
              Atualizar
            </Button>
          </div>
        </form>
      </div>

      <div className="settings-section">
        <h3>Integração Telegram</h3>
        <p className="section-desc">Receba notificações e gerencie seus remédios pelo Telegram.</p>

        <div className="telegram-status">
          Status:
          <span
            className={`status-badge ${settings?.telegram_chat_id ? 'connected' : 'disconnected'}`}
          >
            {settings?.telegram_chat_id ? 'Conectado' : 'Não Conectado'}
          </span>
        </div>

        {settings?.telegram_chat_id ? (
          <div className="connected-actions">
            <p className="section-desc success-text">Bot vinculado com sucesso!</p>
            <Button variant="outline" className="btn-disconnect" onClick={handleDisconnectTelegram}>
              Desconectar Telegram
            </Button>
          </div>
        ) : (
          <div className="connect-telegram">
            {!telegramToken ? (
              <Button onClick={generateTelegramToken}>Gerar Código de Vínculo</Button>
            ) : (
              <div className="token-display">
                <p>Envie este comando para o bot:</p>
                <div className="code-box">/start {telegramToken}</div>
                <a
                  href={`https://t.me/dosiq_bot?start=${telegramToken}`}
                  target="_blank"
                  rel="noreferrer"
                  className="telegram-link"
                >
                  Abrir Bot no Telegram
                </a>
                <Button
                  variant="ghost"
                  className="btn-cancel-token"
                  onClick={() => setTelegramToken(null)}
                >
                  Cancelar
                </Button>
              </div>
            )}
          </div>
        )}
      </div>

      <div className="settings-section">
        <h3>Saúde e Emergência</h3>
        <p className="section-desc">Informações médicas críticas para situações de emergência.</p>

        <div className="emergency-actions">
          <Button variant="outline" onClick={() => onNavigate('emergency')}>
            Cartão de Emergência
          </Button>
          <Button
            variant="outline"
            onClick={() => onNavigate('consultation')}
          >
            Modo Consulta Médica
          </Button>
        </div>
      </div>

      <div className="settings-section">
        <h3>Exportar Dados</h3>
        <p className="section-desc">
          Exporte seus dados em formato CSV ou JSON para backup ou análise.
        </p>

        <div className="export-actions">
          <Button variant="outline" onClick={() => setIsExportDialogOpen(true)}>
            Exportar Dados
          </Button>
        </div>
      </div>

      <div className="settings-section">
        <h3>Relatórios</h3>
        <p className="section-desc">
          Gere relatórios em PDF com seu histórico de medicamentos e adesão.
        </p>

        <div className="report-actions">
          <Button variant="outline" onClick={() => setIsReportModalOpen(true)}>
            Gerar Relatório PDF
          </Button>
        </div>
      </div>

      <div className="settings-section">
        <h3>Administração</h3>
        <p className="section-desc">Ferramentas administrativas do sistema.</p>

        <div className="admin-actions">
          <Button variant="outline" onClick={() => onNavigate('admin-dlq')}>
            Gerenciar Notificações Falhadas (DLQ)
          </Button>
        </div>
      </div>

      {message && <div className="settings-message success">{message}</div>}
      {error && <div className="settings-message error">{error}</div>}

      <div className="logout-section">
        <Button variant="outline" className="logout-btn" onClick={handleLogout}>
          Sair da Conta
        </Button>
      </div>

      <ExportDialog isOpen={isExportDialogOpen} onClose={() => setIsExportDialogOpen(false)} />

      {/* Modal de Geração de Relatórios */}
      <Modal isOpen={isReportModalOpen} onClose={() => setIsReportModalOpen(false)}>
        <ReportGenerator onClose={() => setIsReportModalOpen(false)} />
      </Modal>
    </div>
  )
}

// src/views/admin/DLQAdmin.jsx
// Dead Letter Queue Admin Interface
import { useState, useEffect, useCallback } from 'react'
import { dlqService } from '@services/api/dlqService'
import Button from '@shared/components/ui/Button'
import Loading from '@shared/components/ui/Loading'
import Modal from '@shared/components/ui/Modal'
import './DLQAdmin.css'

// Constantes de formatação
const USER_ID_TRUNCATE_LENGTH = 8
const ERROR_MESSAGE_TRUNCATE_LENGTH = 50

/**
 * DLQAdmin - Interface de administração da Dead Letter Queue
 *
 * Funcionalidades:
 * - Lista notificações falhadas com paginação
 * - Filtra por status
 * - Permite retentar ou descartar notificações
 * - Exibe detalhes de cada notificação
 */
export default function DLQAdmin() {
  // Estados principais
  const [entries, setEntries] = useState([])
  const [isLoading, setIsLoading] = useState(true)
  const [error, setError] = useState(null)

  // Estados de paginação
  const [total, setTotal] = useState(0)
  const [page, setPage] = useState(1)
  const [pageSize] = useState(20)
  const [totalPages, setTotalPages] = useState(0)

  // Estados de filtro
  const [statusFilter, setStatusFilter] = useState('')

  // Estados de ação
  const [selectedEntry, setSelectedEntry] = useState(null)
  const [showDetails, setShowDetails] = useState(false)
  const [actionLoading, setActionLoading] = useState(null)
  const [actionMessage, setActionMessage] = useState(null)

  // Estados de confirmação
  const [confirmAction, setConfirmAction] = useState(null)
  const [showConfirmModal, setShowConfirmModal] = useState(false)

  // Carregar dados
  const loadEntries = useCallback(async () => {
    setIsLoading(true)
    setError(null)

    try {
      const offset = (page - 1) * pageSize
      const result = await dlqService.getAll({
        limit: pageSize,
        offset,
        status: statusFilter || null,
      })

      setEntries(result.data)
      setTotal(result.total)
      setTotalPages(result.totalPages)
    } catch (err) {
      console.error('[DLQAdmin] Erro ao carregar:', err)
      setError(err.message)
    } finally {
      setIsLoading(false)
    }
  }, [page, pageSize, statusFilter])

  useEffect(() => {
    loadEntries()
  }, [loadEntries])

  // Handlers de ação com Modal de confirmação
  const handleRetry = async (id) => {
    setConfirmAction({
      type: 'retry',
      id,
      message: 'Deseja retentar esta notificação?',
      onConfirm: async () => {
        setActionLoading(id)
        setActionMessage(null)

        try {
          const result = await dlqService.retry(id)
          setActionMessage({
            type: 'success',
            text: result.message || 'Notificação reenviada com sucesso!',
          })
          loadEntries() // Recarregar lista
        } catch (err) {
          setActionMessage({ type: 'error', text: err.message })
        } finally {
          setActionLoading(null)
        }
      },
    })
    setShowConfirmModal(true)
  }

  const handleDiscard = async (id) => {
    setConfirmAction({
      type: 'discard',
      id,
      message: 'Deseja descartar esta notificação? Esta ação não pode ser desfeita.',
      onConfirm: async () => {
        setActionLoading(id)
        setActionMessage(null)

        try {
          const result = await dlqService.discard(id)
          setActionMessage({ type: 'success', text: result.message || 'Notificação descartada.' })
          loadEntries() // Recarregar lista
        } catch (err) {
          setActionMessage({ type: 'error', text: err.message })
        } finally {
          setActionLoading(null)
        }
      },
    })
    setShowConfirmModal(true)
  }

  // Handler de confirmação
  const handleConfirmAction = async () => {
    if (confirmAction?.onConfirm) {
      await confirmAction.onConfirm()
    }
    setShowConfirmModal(false)
    setConfirmAction(null)
  }

  const handleCancelConfirm = () => {
    setShowConfirmModal(false)
    setConfirmAction(null)
  }

  const handleViewDetails = (entry) => {
    setSelectedEntry(entry)
    setShowDetails(true)
  }

  // Handlers de paginação
  const handlePrevPage = () => {
    if (page > 1) setPage(page - 1)
  }

  const handleNextPage = () => {
    if (page < totalPages) setPage(page + 1)
  }

  // Handler de filtro
  const handleStatusChange = (e) => {
    setStatusFilter(e.target.value)
    setPage(1) // Resetar para primeira página
  }

  // Limpar mensagem após 5 segundos
  useEffect(() => {
    if (actionMessage) {
      const timer = setTimeout(() => setActionMessage(null), 5000)
      return () => clearTimeout(timer)
    }
  }, [actionMessage])

  return (
    <div className="dlq-admin">
      <header className="dlq-admin__header">
        <h1>Dead Letter Queue</h1>
        <p className="dlq-admin__subtitle">Gerenciamento de notificações falhadas</p>
      </header>

      {/* Filtros e estatísticas */}
      <div className="dlq-admin__controls">
        <div className="dlq-admin__filter">
          <label htmlFor="status-filter">Filtrar por status:</label>
          <select
            id="status-filter"
            value={statusFilter}
            onChange={handleStatusChange}
            className="dlq-admin__select"
          >
            <option value="">Todos</option>
            <option value="pending">Pendente</option>
            <option value="retrying">Retentando</option>
            <option value="resolved">Resolvido</option>
            <option value="discarded">Descartado</option>
          </select>
        </div>

        <div className="dlq-admin__stats">
          <span className="dlq-admin__stat">
            <strong>{total}</strong> notificações
          </span>
        </div>
      </div>

      {/* Mensagem de ação */}
      {actionMessage && (
        <div className={`dlq-admin__message dlq-admin__message--${actionMessage.type}`}>
          {actionMessage.text}
        </div>
      )}

      {/* Erro */}
      {error && (
        <div className="dlq-admin__error">
          <p>Erro ao carregar dados: {error}</p>
          <Button onClick={loadEntries} variant="secondary">
            Tentar novamente
          </Button>
        </div>
      )}

      {/* Loading */}
      {isLoading && (
        <div className="dlq-admin__loading">
          <Loading text="Carregando notificações..." />
        </div>
      )}

      {/* Tabela */}
      {!isLoading && !error && (
        <>
          <div className="dlq-admin__table-container">
            <table className="dlq-admin__table">
              <thead>
                <tr>
                  <th>Data/Hora</th>
                  <th>Usuário</th>
                  <th>Tipo</th>
                  <th>Status</th>
                  <th>Erro</th>
                  <th>Tentativas</th>
                  <th>Ações</th>
                </tr>
              </thead>
              <tbody>
                {entries.length === 0 ? (
                  <tr>
                    <td colSpan="7" className="dlq-admin__empty">
                      Nenhuma notificação encontrada
                    </td>
                  </tr>
                ) : (
                  entries.map((entry) => (
                    <tr key={entry.id} className="dlq-admin__row">
                      <td className="dlq-admin__cell dlq-admin__cell--date">
                        {dlqService.formatDate(entry.created_at)}
                      </td>
                      <td className="dlq-admin__cell dlq-admin__cell--user">
                        <span className="dlq-admin__user-id">
                          {entry.user_id
                            ? entry.user_id.substring(0, USER_ID_TRUNCATE_LENGTH) + '...'
                            : '-'}
                        </span>
                      </td>
                      <td className="dlq-admin__cell">
                        {dlqService.formatNotificationType(entry.notification_type)}
                      </td>
                      <td className="dlq-admin__cell">
                        <span
                          className="dlq-admin__status"
                          style={{ color: dlqService.getStatusColor(entry.status) }}
                        >
                          {dlqService.formatStatus(entry.status)}
                        </span>
                      </td>
                      <td className="dlq-admin__cell dlq-admin__cell--error">
                        <span className="dlq-admin__error-text" title={entry.error_message}>
                          {entry.error_message
                            ? entry.error_message.length > ERROR_MESSAGE_TRUNCATE_LENGTH
                              ? entry.error_message.substring(0, ERROR_MESSAGE_TRUNCATE_LENGTH) +
                                '...'
                              : entry.error_message
                            : '-'}
                        </span>
                      </td>
                      <td className="dlq-admin__cell dlq-admin__cell--attempts">
                        {entry.retry_count || 0}
                      </td>
                      <td className="dlq-admin__cell dlq-admin__cell--actions">
                        <div className="dlq-admin__actions">
                          <button
                            className="dlq-admin__action-btn dlq-admin__action-btn--view"
                            onClick={() => handleViewDetails(entry)}
                            title="Ver detalhes"
                          >
                            Ver
                          </button>
                          {(entry.status === 'pending' || entry.status === 'retrying') && (
                            <>
                              <button
                                className="dlq-admin__action-btn dlq-admin__action-btn--retry"
                                onClick={() => handleRetry(entry.id)}
                                disabled={actionLoading === entry.id}
                                title="Retentar"
                              >
                                {actionLoading === entry.id ? '...' : 'Retentar'}
                              </button>
                              <button
                                className="dlq-admin__action-btn dlq-admin__action-btn--discard"
                                onClick={() => handleDiscard(entry.id)}
                                disabled={actionLoading === entry.id}
                                title="Descartar"
                              >
                                Descartar
                              </button>
                            </>
                          )}
                        </div>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>

          {/* Paginação */}
          {totalPages > 1 && (
            <div className="dlq-admin__pagination">
              <button
                className="dlq-admin__page-btn"
                onClick={handlePrevPage}
                disabled={page === 1}
              >
                Anterior
              </button>
