import { useState, useEffect, useCallback } from 'react'
import { supabase } from '@shared/utils/supabase'

// Import components
import SettingsHeader from './settings/sections/SettingsHeader'
import NotificationSection from './settings/sections/NotificationSection'
import IntegrationSection from './settings/sections/IntegrationSection'
import PreferenceSection from './settings/sections/PreferenceSection'
import AccountSection from './settings/sections/AccountSection'
import AdminSection from './settings/sections/AdminSection'

// Import CSS
import './settings/SettingsRedesign.css'
import { getServerTimestamp } from '@utils/dateUtils'

import { useComplexityMode } from '@dashboard/hooks/useComplexityMode'

/**
 * SettingsRedesign (v10.0) — Orquestrador principal de configurações.
 * Utiliza o Sectional Pattern para modularidade.
 */
export default function SettingsRedesign({ onNavigate }) {
  const { mode: complexityMode, setOverride: setComplexityOverride, overrideMode } = useComplexityMode()

  // ── States ──
  const [loading, setLoading] = useState(true)
  const [savingChannel, setSavingChannel] = useState(false)
  const [savingNotification, setSavingNotification] = useState(false)
  const [savingQuietHours, setSavingQuietHours] = useState(false)
  const [savingDigestTime, setSavingDigestTime] = useState(false)
  const [message, setMessage] = useState({ type: '', text: '' })
  const [isAdmin, setIsAdmin] = useState(false)
  const [dlqCount, setDlqCount] = useState(0)

  // User Data
  const [isTelegramConnected, setIsTelegramConnected] = useState(false)
  const [telegramToken, setTelegramToken] = useState('')
  const [notificationMode, setNotificationMode] = useState('realtime')
  const [quietHoursEnabled, setQuietHoursEnabled] = useState(false)
  const [quietHoursStart, setQuietHoursStart] = useState('22:00')
  const [quietHoursEnd, setQuietHoursEnd] = useState('08:00')
  const [digestTime, setDigestTime] = useState('08:30')


  // Web Push
  const [webPushSupported, setWebPushSupported] = useState(false)
  const [channelWebPushEnabled, setChannelWebPushEnabled] = useState(false)

  // Password
  const [showPasswordForm, setShowPasswordForm] = useState(false)
  const [newPassword, setNewPassword] = useState('')

  // ── Initialization ──
  const fetchData = useCallback(async () => {
    try {
      setLoading(true)
      const {
        data: { user },
      } = await supabase.auth.getUser()
      if (!user) return

      // Admin check
      if (user.user_metadata?.role === 'admin') {
        setIsAdmin(true)
        const { count } = await supabase
          .from('dead_letter_queue')
          .select('*', { count: 'exact', head: true })
        setDlqCount(count || 0)
      }

      // Settings
      const { data: settings } = await supabase
        .from('user_settings')
        .select('*')
        .eq('user_id', user.id)

        .single()

      if (settings) {
        setIsTelegramConnected(!!settings.telegram_chat_id)
        setNotificationMode(settings.notification_mode || 'realtime')
        setQuietHoursEnabled(settings.quiet_hours_enabled || false)
        setQuietHoursStart(settings.quiet_hours_start || '23:00')
        setQuietHoursEnd(settings.quiet_hours_end || '08:00')
        setDigestTime(settings.digest_time || '09:00')
        setChannelWebPushEnabled(settings.channel_web_push_enabled || false)
        if (settings.complexity_override) {
          setComplexityOverride(settings.complexity_override)
        }

      }

      // Web Push Support
      setWebPushSupported('serviceWorker' in navigator && 'PushManager' in window)
    } catch (error) {
      console.error('Settings error:', error)
    } finally {
      setLoading(false)
    }
  }, [setComplexityOverride])

  useEffect(() => {
    fetchData()
  }, [fetchData])

  // ── Handlers (Notificações) ──
  const handleToggleWebPush = async () => {
    try {
      setSavingChannel(true)
      const newValue = !channelWebPushEnabled

      // Se estiver ligando, solicitar permissão
      if (newValue) {
        const permission = await Notification.requestPermission()
        if (permission !== 'granted') {
          setMessage({ type: 'error', text: 'Permissão de notificação negada pelo navegador.' })
          return
        }
      }

      const {
        data: { user },
      } = await supabase.auth.getUser()
      await supabase
        .from('user_settings')
        .update({ channel_web_push_enabled: newValue })
        .eq('user_id', user.id)


      setChannelWebPushEnabled(newValue)
      setMessage({ type: 'success', text: `Notificações Web ${newValue ? 'ativadas' : 'desativadas'}.` })
    } catch {
      setMessage({ type: 'error', text: 'Falha ao atualizar canal Web.' })
    } finally {
      setSavingChannel(false)
      setTimeout(() => setMessage({ type: '', text: '' }), 3000)
    }
  }

  const handleModeChange = async (mode) => {
    try {
      setSavingNotification(true)
      const {
        data: { user },
      } = await supabase.auth.getUser()
      await supabase
        .from('user_settings')
        .update({ notification_mode: mode })
        .eq('user_id', user.id)

      setNotificationMode(mode)
      setMessage({ type: 'success', text: 'Modo de notificação atualizado.' })
    } catch {
      setMessage({ type: 'error', text: 'Erro ao salvar modo.' })
    } finally {
      setSavingNotification(false)
      setTimeout(() => setMessage({ type: '', text: '' }), 3000)
    }
  }

  const saveQuietHours = async () => {
    try {
      setSavingQuietHours(true)
      const {
        data: { user },
      } = await supabase.auth.getUser()
      await supabase
        .from('user_settings')
        .update({
          quiet_hours_enabled: quietHoursEnabled,
          quiet_hours_start: quietHoursStart,
          quiet_hours_end: quietHoursEnd,
        })
        .eq('user_id', user.id)

      setMessage({ type: 'success', text: 'Período silencioso salvo.' })
    } catch {
      setMessage({ type: 'error', text: 'Erro ao salvar período silencioso.' })
    } finally {
      setSavingQuietHours(false)
      setTimeout(() => setMessage({ type: '', text: '' }), 3000)
    }
  }


  const saveDigestTime = async () => {
    try {
      setSavingDigestTime(true)
      const {
        data: { user },
      } = await supabase.auth.getUser()
      await supabase
        .from('user_settings')
        .update({ digest_time: digestTime })
        .eq('user_id', user.id)

      setMessage({ type: 'success', text: 'Horário do resumo salvo.' })
    } catch {
      setMessage({ type: 'error', text: 'Erro ao salvar horário.' })
    } finally {
      setSavingDigestTime(false)
      setTimeout(() => setMessage({ type: '', text: '' }), 3000)
    }
  }

  // ── Handlers (Integrações) ──
  const generateTelegramToken = async () => {
    const array = new Uint32Array(1)
    window.crypto.getRandomValues(array)
    const token = array[0].toString(36).substring(0, 6).toUpperCase()
    setTelegramToken(token)
    try {
      const {
        data: { user },
      } = await supabase.auth.getUser()
      await supabase
        .from('user_settings')
        .update({ telegram_token: token, telegram_token_created_at: getServerTimestamp() })
        .eq('user_id', user.id)
    } catch (err) {
      console.error('Token gen error:', err)
    }
  }

  const handleDisconnectTelegram = async () => {
    if (!window.confirm('Tem certeza que deseja desconectar o Telegram?')) return
    try {
      const {
        data: { user },
      } = await supabase.auth.getUser()
      await supabase
        .from('user_settings')
        .update({ telegram_chat_id: null })
        .eq('user_id', user.id)


      setIsTelegramConnected(false)
      setMessage({ type: 'success', text: 'Telegram desconectado.' })
    } catch {
      setMessage({ type: 'error', text: 'Erro ao desconectar.' })
    } finally {
      setTimeout(() => setMessage({ type: '', text: '' }), 3000)
    }
  }

  // ── Handlers (Preferências) ──
  const handleComplexityChange = async (mode) => {
    const value = mode === 'auto' ? null : mode
    try {
      const {
        data: { user },
      } = await supabase.auth.getUser()
      await supabase
        .from('user_settings')
        .update({ 
          complexity_override: value
        })
        .eq('user_id', user.id)

      setComplexityOverride(value)

      setMessage({ type: 'success', text: 'Preferência de visualização atualizada.' })
    } catch {
      setMessage({ type: 'error', text: 'Erro ao salvar preferência.' })
    } finally {
      setTimeout(() => setMessage({ type: '', text: '' }), 3000)
    }
  }

  const getComplexityDisplayMode = () => {
    if (overrideMode === 'simple') return 'Ativo: Modo Padrão (simplificado)'
    if (overrideMode === 'complex') return 'Ativo: Modo Detalhado'
    return `Ativo: Automático (atualmente: ${complexityMode === 'simple' ? 'Padrão' : 'Detalhado'})`
  }

  // ── Handlers (Conta) ──
  const handleUpdatePassword = async (e) => {
    e.preventDefault()
    try {
      const { error } = await supabase.auth.updateUser({ password: newPassword })
      if (error) throw error
      setMessage({ type: 'success', text: 'Senha atualizada com sucesso!' })
      setShowPasswordForm(false)
      setNewPassword('')
    } catch (err) {
      setMessage({ type: 'error', text: err.message })
    } finally {
      setTimeout(() => setMessage({ type: '', text: '' }), 3000)
    }
  }

  const handleLogout = async () => {
    if (!window.confirm('Deseja realmente sair?')) return
    await supabase.auth.signOut()
    onNavigate('login')
  }

  // ── Render ──
  return (
    <main className="sr-view">
      <SettingsHeader 
        onNavigate={onNavigate} 
        message={message.type === 'success' ? message.text : null} 
        error={message.type === 'error' ? message.text : null} 
      />

      {loading ? (
        <div className="sr-loading">Carregando configurações...</div>
      ) : (
        <>
          <NotificationSection
            webPushSupported={webPushSupported}
            channelWebPushEnabled={channelWebPushEnabled}
            savingChannel={savingChannel}
            handleToggleWebPush={handleToggleWebPush}
            isTelegramConnected={isTelegramConnected}
            notificationMode={notificationMode}
            handleModeChange={handleModeChange}
            savingNotification={savingNotification}
            quietHoursEnabled={quietHoursEnabled}
            setQuietHoursEnabled={setQuietHoursEnabled}
            quietHoursStart={quietHoursStart}
            setQuietHoursStart={setQuietHoursStart}
            quietHoursEnd={quietHoursEnd}
            setQuietHoursEnd={setQuietHoursEnd}
            saveQuietHours={saveQuietHours}
            savingQuietHours={savingQuietHours}
            digestTime={digestTime}
            setDigestTime={setDigestTime}
            saveDigestTime={saveDigestTime}
            savingDigestTime={savingDigestTime}
          />

          <IntegrationSection
            isTelegramConnected={isTelegramConnected}
            generateTelegramToken={generateTelegramToken}
            telegramToken={telegramToken}
            handleDisconnectTelegram={handleDisconnectTelegram}
          />

          <PreferenceSection
            overrideMode={overrideMode}
            handleComplexityChange={handleComplexityChange}
            getComplexityDisplayMode={getComplexityDisplayMode}
          />

          <AccountSection
            showPasswordForm={showPasswordForm}
            setShowPasswordForm={setShowPasswordForm}
            handleUpdatePassword={handleUpdatePassword}
            newPassword={newPassword}
            setNewPassword={setNewPassword}
            handleLogout={handleLogout}
          />

          <AdminSection isAdmin={isAdmin} dlqCount={dlqCount} onNavigate={onNavigate} />

          <footer className="sr-footer">
            Dosiq v{import.meta.env.VITE_APP_VERSION ?? '3.3.0'} • Design Santuário
          </footer>
        </>
      )}
    </main>
  )
}

/**
 * StockRedesign — View de Estoque redesenhada (Santuário Terapêutico, Wave 8).
 * Orquestra layout, personas (simple/complex) e modal de compra.
 *
 * NÃO duplica lógica de dados — usa useStockData() compartilhado.
 * NÃO modifica Stock.jsx original.
 *
 * Personas:
 * - Simple (Dona Maria): seções por urgência, 2 colunas desktop, "última compra" per-card
 * - Complex (Carlos): grid responsivo, EntradaHistorico, bar-pct%, quantidade visível
 */

import { useState, useMemo, useEffect, startTransition } from 'react'
import { motion } from 'framer-motion'
import { Plus } from 'lucide-react'
import { useMotion } from '@shared/hooks/useMotion'
import { useStockData } from '@stock/hooks/useStockData'
import { useComplexityMode } from '@dashboard/hooks/useComplexityMode'
import { useDashboard } from '@dashboard/hooks/useDashboardContext'
import Loading from '@shared/components/ui/Loading'
import EmptyState from '@shared/components/ui/EmptyState'
import Modal from '@shared/components/ui/Modal'
import StockForm from '@stock/components/StockForm'
import StockCardRedesign from '@stock/components/redesign/StockCardRedesign'
import CriticalAlertBanner from '@stock/components/redesign/CriticalAlertBanner'
import EntradaHistorico from '@stock/components/redesign/EntradaHistorico'
import CostSummaryRedesign from '@stock/components/CostSummaryRedesign'
import PrescriptionTimelineRedesign from '@stock/components/PrescriptionTimelineRedesign'
import { calculateMonthlyCosts } from '@stock/services/costAnalysisService'
import { parseLocalDate, getNow } from '@utils/dateUtils'
import { stockService } from '@shared/services'
import './Stock.css'

/**
 * Derivar status do protocolo baseado em datas de vigência
 *
 * @param {object} protocol — protocolo com start_date, end_date, active
 * @returns {'ativa' | 'vencida' | 'vencendo' | 'finalizada'}
 */
function deriveProtocolStatus(protocol, now = getNow()) {
  if (!protocol.end_date) return 'ativa'
  const end = parseLocalDate(protocol.end_date)
  const daysLeft = (end - now) / 86400000
  if (daysLeft < 0) return 'vencida'
  if (daysLeft <= 14) return 'vencendo'
  if (protocol.active === false) return 'finalizada'
  return 'ativa'
}

export default function Stock({ initialParams, onClearParams }) {
  // ── Dados (hook compartilhado) ──
  const {
    items,
    criticalItems,
    warningItems,
    okItems,
    highItems,
    orphanItems,
    medicines,
    isLoading,
    error,
    reload,
  } = useStockData()

  // ── Complexidade / Persona ──
  // R-152: isComplex = mode !== 'simple'; sem modo "moderate"
  const { mode } = useComplexityMode()
  const isComplex = mode !== 'simple'

  // ── Estado local (UI) ──
  const [isModalOpen, setIsModalOpen] = useState(false)
  const [selectedMedicineId, setSelectedMedicineId] = useState(null)
  const [successMessage, setSuccessMessage] = useState('')

  // ── Motion ──
  const motionConfig = useMotion()

  // ── Dashboard context para protocolos (necessário para timeline de prescrições) ──
  const dashboardData = useDashboard()

  // ── Purchases agregadas para histórico (complex only) ──
  // Inclui medicamento info em cada compra para o layout correto
  const allPurchases = useMemo(
    () =>
      items.flatMap((item) =>
        item.purchases.map((purchase) => ({
          ...purchase,
          medicineName: item.medicine.name,
          medicineType: item.medicine.medicine_type,
        }))
      ),
    [items]
  )

  // ── Todos os itens ordenados por urgência (para Complex grid) ──
  // Filtra órfãos de okItems/highItems, eles aparecem só no final
  const okItemsWithoutOrphans = useMemo(() => okItems.filter((i) => i.hasActiveProtocol), [okItems])
  const highItemsWithoutOrphans = useMemo(
    () => highItems.filter((i) => i.hasActiveProtocol),
    [highItems]
  )

  // Órfãos (sem protocolo ativo) vão para o FINAL da listagem
  const sortedAllItems = useMemo(
    () => [
      ...criticalItems,
      ...warningItems,
      ...okItemsWithoutOrphans,
      ...highItemsWithoutOrphans,
      ...orphanItems,
    ],
    [criticalItems, warningItems, okItemsWithoutOrphans, highItemsWithoutOrphans, orphanItems]
  )

  // ── Custo mensal calculado ──
  const costData = useMemo(() => {
    if (!medicines?.length) return null
    // Enriquecer medicines com stock e purchases para cálculo de custo
    const medicinesWithStock = medicines.map((med) => ({
      ...med,
      stock: items?.filter((s) => s.medicine.id === med.id)?.flatMap((s) => s.entries) || [],
      purchases: allPurchases?.filter((p) => p.medicine_id === med.id) || [],
    }))
    try {
      const activeProtocols = dashboardData?.protocols?.filter((p) => p.active) || []
      return calculateMonthlyCosts(medicinesWithStock, activeProtocols)
    } catch (err) {
      console.error('[StockRedesign] Erro ao calcular custos:', err)
      return null
    }
  }, [medicines, items, allPurchases, dashboardData])

  // ── Dados de prescrição para timeline (exclui uso contínuo) ──
  const prescriptionTimelineData = useMemo(() => {
    if (!dashboardData?.protocols?.length) return []
    return dashboardData.protocols
      .filter((p) => p.active && p.start_date && p.end_date) // filtra apenas protocolos ATIVOS com vigência definida
      .map((p) => ({
        id: p.id,
        name: p.name,
        medicineName:
          p.medicine?.name || medicines?.find((m) => m.id === p.medicine_id)?.name || 'Medicamento',
        startDate: p.start_date,
        endDate: p.end_date,
        isContinuous: false, // já filtrado acima
        status: deriveProtocolStatus(p),
      }))
  }, [dashboardData?.protocols, medicines])

  // ── Handlers ──
  const handleOpenModal = (medicineId = null) => {
    if (medicines.length === 0) return
    setSelectedMedicineId(typeof medicineId === 'string' ? medicineId : null)
    setIsModalOpen(true)
  }

  const handleSaveStock = async (stockData) => {
    try {
      await stockService.add(stockData)
      setIsModalOpen(false)
      setSelectedMedicineId(null)
      if (onClearParams) onClearParams()
      setSuccessMessage('Estoque adicionado!')
      setTimeout(() => setSuccessMessage(''), 3000)
      reload()
    } catch (err) {
      throw new Error(err?.message || 'Erro ao adicionar estoque')
    }
  }

  // ── initialParams: abrir modal pré-selecionado (deep link) ──
  useEffect(() => {
    if (initialParams?.medicineId && medicines.length > 0) {
      startTransition(() => {
        setSelectedMedicineId(initialParams.medicineId)
        setIsModalOpen(true)
      })
    }
  }, [initialParams, medicines.length])

  const modalInitialValues = selectedMedicineId
    ? { medicine_id: selectedMedicineId }
    : initialParams || null

  // ── Loading / Error ──
  if (isLoading) {
    return (
      <div className="page-container">
        <Loading text="Carregando estoque..." />
      </div>
    )
  }

  if (medicines.length === 0) {
    return (
      <div className="page-container">
        <EmptyState
          illustration="stock"
          title="Nenhum medicamento cadastrado"
          description="Cadastre seus medicamentos para começar a controlar seu estoque"
          ctaLabel="Cadastrar Medicamento"
          onCtaClick={() => handleOpenModal()}
        />
      </div>
    )
  }

  // ── Render ──
  return (
    <div className="page-container stock-redesign" data-complexity={mode}>
      {/* ── Page Header ── */}
      <header className="stock-redesign__header">
        <div>
          <h1 className="stock-redesign__title">Controle de Estoque</h1>
          <p className="stock-redesign__subtitle">Prioridade de Reabastecimento</p>
        </div>
        {/* Botão responsivo: ícone mobile, texto + ícone desktop */}
        <button
          className="stock-redesign__add-btn stock-redesign__add-btn--desktop"
          onClick={() => handleOpenModal()}
          aria-label="Adicionar estoque"
        >
          <Plus size={16} aria-hidden="true" />
          <span>Adicionar Estoque</span>
        </button>
      </header>

      {/* ── Feedback ── */}
      {successMessage && (
        <div className="stock-redesign__success" role="status">
          {successMessage}
        </div>
      )}
      {error && (
        <div className="stock-redesign__error" role="alert">
          {error}
        </div>
      )}

      {/* ── Banner de alerta crítico ── */}
      <CriticalAlertBanner
        criticalCount={criticalItems.length}
        onBuyAll={() => handleOpenModal()}
      />

      {/* ── Seção principal ── */}
      {isComplex ? (
        // Complex: grid único ordenado por urgência; CSS decide 2-col vs 3-col por contagem
        <>
          <div className="stock-redesign__section-header">
            <h2 className="stock-redesign__section-title">Inventário Ativo ({items.length})</h2>
          </div>
          <motion.div
            className="stock-redesign__grid stock-redesign__grid--complex"
            variants={motionConfig.cascade.container}
            initial="hidden"
            animate="visible"
          >
            {sortedAllItems.map((item, index) => (
              <StockCardRedesign
                key={item.medicine.id}
                item={item}
                isComplex={true}
                onAddStock={() => handleOpenModal(item.medicine.id)}
                index={index}
              />
            ))}
          </motion.div>
        </>
      ) : (
        // Simple: seções por urgência (Dona Maria) — headers fora do grid
        <motion.div
          className="stock-redesign__sections"
          variants={motionConfig.cascade.container}
          initial="hidden"
          animate="visible"
        >
          {criticalItems.length > 0 && (
            <>
              <h2 className="stock-redesign__section-label stock-redesign__section-label--urgente">
                Crítico ({criticalItems.length})
              </h2>
              <motion.div variants={motionConfig.cascade.item} className="stock-redesign__section">
                {criticalItems.map((item, index) => (
                  <StockCardRedesign
                    key={item.medicine.id}
                    item={item}
                    isComplex={false}
                    onAddStock={() => handleOpenModal(item.medicine.id)}
                    index={index}
                  />
                ))}
              </motion.div>
            </>
          )}

          {warningItems.length > 0 && (
            <>
              <h2 className="stock-redesign__section-label stock-redesign__section-label--atencao">
                Atenção ({warningItems.length})
              </h2>
              <motion.div variants={motionConfig.cascade.item} className="stock-redesign__section">
                {warningItems.map((item, index) => (
                  <StockCardRedesign
                    key={item.medicine.id}
                    item={item}
                    isComplex={false}
                    onAddStock={() => handleOpenModal(item.medicine.id)}
                    index={index}
                  />
                ))}
              </motion.div>
            </>
          )}

          {(okItemsWithoutOrphans.length > 0 || highItemsWithoutOrphans.length > 0) && (
            <>
              <h2 className="stock-redesign__section-label stock-redesign__section-label--seguro">
                Estoque OK ({okItemsWithoutOrphans.length + highItemsWithoutOrphans.length})
              </h2>
              <motion.div variants={motionConfig.cascade.item} className="stock-redesign__section">
                {[...okItemsWithoutOrphans, ...highItemsWithoutOrphans].map((item, index) => (
                  <StockCardRedesign
                    key={item.medicine.id}
                    item={item}
                    isComplex={false}
                    onAddStock={() => handleOpenModal(item.medicine.id)}
                    index={index}
                  />
                ))}
              </motion.div>
            </>
          )}

          {orphanItems.length > 0 && (
            <>
              <h2 className="stock-redesign__section-label stock-redesign__section-label--seguro">
                Sem Tratamento Ativo ({orphanItems.length})
              </h2>
              <motion.div variants={motionConfig.cascade.item} className="stock-redesign__section">
                {orphanItems.map((item, index) => (
                  <StockCardRedesign
                    key={item.medicine.id}
                    item={item}
                    isComplex={false}
                    onAddStock={() => handleOpenModal(item.medicine.id)}
                    index={index}
                  />
                ))}
              </motion.div>
            </>
          )}
        </motion.div>
      )}

      {/* ── Histórico de Compras (complex only) ── */}
      {/* Simple: informação de última compra + custo já está per-card em StockCardRedesign */}
      {/* Complex: Carlos precisa do histórico completo para auditoria e análise de preço */}
      {isComplex && allPurchases.length > 0 && (
        <section className="stock-redesign__history-section">
          <h2 className="stock-redesign__section-title">Histórico de Compras</h2>
          <EntradaHistorico purchases={allPurchases} maxVisible={3} />
        </section>
      )}

      {/* 🆕 Análise de Custo Mensal */}
      {costData && costData.items?.length > 0 && (
        <section style={{ marginTop: '1.5rem' }} aria-label="Custo mensal dos medicamentos">
          <CostSummaryRedesign costData={costData} isComplex={isComplex} />
        </section>
      )}

      {/* 🆕 Timeline de Prescrições */}
      {prescriptionTimelineData.length > 0 && (
        <section style={{ marginTop: '1rem' }} aria-label="Vigência das prescrições">
          <PrescriptionTimelineRedesign
            prescriptions={prescriptionTimelineData}
            isComplex={isComplex}
          />
        </section>
      )}

      {/* ── Modal de compra (reutiliza StockForm original) ── */}
      <Modal
        isOpen={isModalOpen}
        onClose={() => {
          setIsModalOpen(false)
          setSelectedMedicineId(null)
          if (onClearParams) onClearParams()
        }}
      >
        <StockForm
          medicines={medicines}
          initialValues={modalInitialValues}
          onSave={handleSaveStock}
          onCancel={() => {
            setIsModalOpen(false)
            setSelectedMedicineId(null)
            if (onClearParams) onClearParams()
          }}
        />
      </Modal>
    </div>
  )
}

/**
 * TreatmentsRedesign — Orquestração da view de tratamentos redesenhada
