export default function Treatments({
  onNavigateToProtocol,
  onNavigate,
  initialMedicineId,
  onClearInitialMedicine,
}) {
  // Estados
  const [activeTab, setActiveTab] = useState('ativos')
  const [wizardOpen, setWizardOpen] = useState(false)
  const [wizardMedicine, setWizardMedicine] = useState(null)
  const [formOpen, setFormOpen] = useState(false)
  const [formProtocol, setFormProtocol] = useState(null)
  const [medicines, setMedicines] = useState([])
  const [treatmentPlans, setTreatmentPlans] = useState([])
  const [errorMessage, setErrorMessage] = useState(null)
  const [medicineCreateOpen, setMedicineCreateOpen] = useState(false)
  const [planFormOpen, setPlanFormOpen] = useState(false)
  const [planEditTarget, setPlanEditTarget] = useState(null)
  const [deletePlanTarget, setDeletePlanTarget] = useState(null)
  const [deleteTreatmentTarget, setDeleteTreatmentTarget] = useState(null)

  // Data + context
  const { mode } = useComplexityMode()
  const { refresh } = useDashboard()
  const {
    activeItems,
    pausedItems,
    finishedItems,
    activeGroups,
    pausedGroups,
    finishedGroups,
    loading,
    error,
    refetch,
  } = useTreatmentList()

  const isComplex = mode === 'complex'

  // Auto-abrir wizard com medicamento pré-selecionado (fluxo: novo medicamento → novo tratamento)
  useEffect(() => {
    if (!initialMedicineId) return
    medicineService
      .getById(initialMedicineId)
      .then((medicine) => {
        if (medicine) {
          setWizardMedicine(medicine)
          setWizardOpen(true)
        }
      })
      .catch((err) => {
        console.error('Erro ao carregar medicamento inicial:', err)
      })
      .finally(() => {
        onClearInitialMedicine?.()
      })
  }, [initialMedicineId]) // eslint-disable-line react-hooks/exhaustive-deps

  // Fetch medicines and treatmentPlans on mount
  useEffect(() => {
    Promise.all([medicineService.getAll(), treatmentPlanService.getAll()])
      .then(([med, plans]) => {
        setMedicines(med || [])
        setTreatmentPlans(plans || [])
      })
      .catch((err) => {
        console.error('Erro ao carregar medicamentos/planos:', err)
      })
  }, [])

  // Memos — item list e groups por tab
  const tabItems = {
    ativos: activeItems,
    pausados: pausedItems,
    finalizados: finishedItems,
  }
  const tabGroups = {
    ativos: activeGroups,
    pausados: pausedGroups,
    finalizados: finishedGroups,
  }
  const currentItems = tabItems[activeTab] || []
  const currentGroups = tabGroups[activeTab] || []

  // Handlers
  function handleOpenWizard(medicine) {
    // Wizard: apenas para medicamentos novos da busca ANVISA
    setWizardMedicine(medicine)
    setWizardOpen(true)
  }

  // Handlers do dropdown [+ Novo]
  function handleAddMedicine() {
    // MedicineForm: cadastra apenas o medicamento, sem protocolo
    setMedicineCreateOpen(true)
  }

  function handleAddTreatment() {
    // TreatmentWizard sem preselectedMedicine = step 1 livre (med + dosagem em um fluxo)
    setWizardMedicine(null)
    setWizardOpen(true)
  }

  function handleAddPlan() {
    // TreatmentPlanForm: cria agrupador de tratamentos
    setPlanEditTarget(null)
    setPlanFormOpen(true)
  }

  function handleWizardComplete() {
    setWizardOpen(false)
    setWizardMedicine(null)
    refetch()
  }

  async function handleEditProtocol(protocolItem) {
    // Form: para editar protocolo existente da lista
    // Buscar protocolo completo do banco (TreatmentItem tem estrutura diferente)
    try {
      setErrorMessage(null)
      const fullProtocol = await protocolService.getById(protocolItem.id)
      setFormProtocol(fullProtocol)
      setFormOpen(true)
    } catch (err) {
      console.error('Erro ao carregar protocolo para edicao:', err)
      setErrorMessage('Erro ao carregar tratamento. Tente novamente.')
    }
  }

  function handleFormClose() {
    setFormOpen(false)
    setFormProtocol(null)
  }

  async function handleFormSave(protocolData) {
    try {
      setErrorMessage(null)
      await protocolService.update(formProtocol.id, protocolData)
      handleFormClose()
      refetch()
    } catch (err) {
      console.error('Erro ao salvar protocolo:', err)
      setErrorMessage('Erro ao salvar tratamento. Tente novamente.')
    }
  }

  async function handleEditPlan(group) {
    try {
      setErrorMessage(null)
      const planId = group.groupKey.replace('plan:', '')
      const fullPlan = await treatmentPlanService.getById(planId)
      setPlanEditTarget(fullPlan)
      setPlanFormOpen(true)
    } catch (err) {
      console.error('Erro ao carregar plano para edicao:', err)
      setErrorMessage('Erro ao carregar plano. Tente novamente.')
    }
  }

  function handleDeletePlanRequest(group) {
    const planId = group.groupKey.replace('plan:', '')
    setDeletePlanTarget({ id: planId, label: group.groupLabel })
  }

  function handleDeleteTreatmentRequest(item) {
    setDeleteTreatmentTarget(item)
  }

  async function handleDeleteTreatmentConfirm() {
    if (!deleteTreatmentTarget) return
    try {
      setErrorMessage(null)
      await protocolService.delete(deleteTreatmentTarget.id)
      setDeleteTreatmentTarget(null)
      refetch()
    } catch (err) {
      console.error('Erro ao excluir tratamento:', err)
      setErrorMessage('Erro ao excluir tratamento. Tente novamente.')
      setDeleteTreatmentTarget(null)
    }
  }

  async function handleDeletePlanConfirm() {
    if (!deletePlanTarget) return
    try {
      setErrorMessage(null)
      await treatmentPlanService.delete(deletePlanTarget.id)
      setDeletePlanTarget(null)
      refetch()
    } catch (err) {
      console.error('Erro ao excluir plano:', err)
      setErrorMessage('Erro ao excluir plano. Tente novamente.')
      setDeletePlanTarget(null)
    }
  }

  if (loading) return <Loading />
  if (error)
    return <div className="treatments-redesign__error">Erro ao carregar tratamentos: {error}</div>

  return (
    <div className="treatments-redesign">
      {/* Top bar: título + dropdown (esq) + busca ANVISA (dir) */}
      <div className="treatments-redesign__topbar">
        <div className="treatments-redesign__topbar-left">
          <h1 className="treatments-redesign__title">Meus Tratamentos</h1>
          <NewTreatmentDropdown
            isComplex={isComplex}
            onAddMedicine={handleAddMedicine}
            onAddTreatment={handleAddTreatment}
            onAddPlan={handleAddPlan}
          />
        </div>
        <AnvisaSearchBar
          existingProtocols={activeItems}
          onNavigateToProtocol={onNavigateToProtocol}
          onEditProtocol={handleEditProtocol}
          onOpenWizard={handleOpenWizard}
          onViewAllMedicines={onNavigate ? () => onNavigate('medicines') : undefined}
        />
      </div>

      {/* Tab bar — abaixo do título, alinhada à esquerda */}
      <TreatmentTabBar
        activeTab={activeTab}
        counts={{
          ativos: activeItems.length,
          pausados: pausedItems.length,
          finalizados: finishedItems.length,
        }}
        onChange={setActiveTab}
      />

      {/* Error Banner */}
      {errorMessage && (
        <div className="treatments-redesign__error-banner">
          <p>{errorMessage}</p>
          <button
            onClick={() => setErrorMessage(null)}
            className="treatments-redesign__error-close"
          >
            ×
          </button>
        </div>
      )}

      {/* Content — bifurca por persona */}
      {isComplex ? (
        <TreatmentsComplex
          key={activeTab}
          groups={currentGroups}
          onEdit={handleEditProtocol}
          onDelete={handleDeleteTreatmentRequest}
          onEditPlan={handleEditPlan}
          onDeletePlan={handleDeletePlanRequest}
          activeTab={activeTab}
        />
      ) : (
        <TreatmentsSimple
          key={activeTab}
          items={currentItems}
          onEdit={handleEditProtocol}
          onDelete={handleDeleteTreatmentRequest}
          activeTab={activeTab}
        />
      )}

      {/* TreatmentWizard modal — busca ANVISA (com med pré-selecionado) ou dropdown "+ Medicamento" (livre) */}
      <Modal
        isOpen={wizardOpen}
        onClose={() => {
          setWizardOpen(false)
          setWizardMedicine(null)
        }}
      >
        <TreatmentWizard
          preselectedMedicine={wizardMedicine || undefined}
          onComplete={handleWizardComplete}
          onCancel={() => {
            setWizardOpen(false)
            setWizardMedicine(null)
          }}
        />
      </Modal>

      {/* ProtocolForm modal — editar tratamento existente */}
      <Modal isOpen={formOpen} onClose={handleFormClose}>
        {formProtocol && (
          <ProtocolForm
            medicines={medicines}
            treatmentPlans={treatmentPlans}
            protocol={formProtocol}
            onSave={handleFormSave}
            onCancel={handleFormClose}
            mode="full"
            showTitration={true}
            showTreatmentPlan={true}
          />
        )}
      </Modal>

      {/* MedicineForm modal — criar medicamento via dropdown "+ Medicamento" */}
      <Modal isOpen={medicineCreateOpen} onClose={() => setMedicineCreateOpen(false)}>
        {medicineCreateOpen && (
          <MedicineForm
            onSave={async (data) => {
              const saved = await medicineService.create(data)
              setMedicineCreateOpen(false)
              // Invalida cache do dashboard (usado por MedicinesRedesign) + lista de tratamentos
              refresh({ force: true })
              refetch()
              return saved
            }}
            onCancel={() => setMedicineCreateOpen(false)}
          />
        )}
      </Modal>

      {/* TreatmentPlanForm modal — criar/editar plano de tratamento */}
      <Modal
        isOpen={planFormOpen}
        onClose={() => {
          setPlanFormOpen(false)
          setPlanEditTarget(null)
        }}
      >
        {planFormOpen && (
          <TreatmentPlanForm
            plan={planEditTarget || undefined}
            onSave={async (data) => {
              if (planEditTarget) {
                await treatmentPlanService.update(planEditTarget.id, data)
              } else {
                await treatmentPlanService.create(data)
              }
              setPlanFormOpen(false)
              setPlanEditTarget(null)
              refetch()
            }}
            onCancel={() => {
              setPlanFormOpen(false)
              setPlanEditTarget(null)
            }}
          />
        )}
      </Modal>

      {/* ConfirmDialog — excluir tratamento */}
      <ConfirmDialog
        isOpen={!!deleteTreatmentTarget}
        title={`Excluir tratamento "${deleteTreatmentTarget?.medicineName}"?`}
        message="Esta ação não pode ser desfeita. O histórico de doses associado será mantido."
        confirmLabel="Excluir"
        variant="danger"
        onConfirm={handleDeleteTreatmentConfirm}
        onCancel={() => setDeleteTreatmentTarget(null)}
      />

      {/* ConfirmDialog — excluir plano de tratamento */}
      <ConfirmDialog
        isOpen={!!deletePlanTarget}
        title={`Excluir plano "${deletePlanTarget?.label}"?`}
        message="Os tratamentos associados a este plano não serão excluídos, apenas o agrupamento. Esta ação não pode ser desfeita."
        confirmLabel="Excluir"
        variant="danger"
        onConfirm={handleDeletePlanConfirm}
        onCancel={() => setDeletePlanTarget(null)}
      />
    </div>
  )
}

/**
 * TreatmentsComplex — Modo complexo da view de tratamentos (Carlos)
 * Grupos colapsáveis por plano/classe com header colorido
 * Cada grupo contém protocolos com rows expandíveis
 * Layout responsivo controlado por media queries (sem useEffect)
 * Wave 15.10: Integração de ProtocolRiskBadge
 */
import { useState, useMemo } from 'react'
import { motion } from 'framer-motion'
import { useMotion } from '@shared/hooks/useMotion'
import { useDashboard } from '@dashboard/hooks/useDashboardContext'
import TreatmentPlanHeader from '@protocols/components/redesign/TreatmentPlanHeader'
import ProtocolRow from '@protocols/components/redesign/ProtocolRow'
import ProtocolRiskBadge from '@adherence/components/ProtocolRiskBadge'
import { calculateProtocolRisk } from '@adherence/services/protocolRiskService'

/**
 * TreatmentsComplex — Modo complexo com grupos colapsáveis
 * S7.5.5: Adicionar hoveredRow state para iluminar linha inteira em desktop
 */
export default function TreatmentsComplex({
  groups,
  onEdit,
  onDelete,
  onEditPlan,
  onDeletePlan,
  activeTab,
}) {
  const { cascade } = useMotion()
  const { logs } = useDashboard()
  const [collapsedGroups, setCollapsedGroups] = useState(new Set())
  const [expandedRow, setExpandedRow] = useState(null)
  const [hoveredRow, setHoveredRow] = useState(null) // S7.5.5

  // Calcular scores de risco para cada protocolo (Wave 15.10)
  const riskByProtocol = useMemo(() => {
    if (!groups?.length || !logs?.length) return new Map()
    const map = new Map()
    groups.forEach((group) => {
      group.items?.forEach((item) => {
        if (!item?.id || item.active === false) return
        const risk = calculateProtocolRisk({
          protocolId: item.id,
          logs,
          protocol: item,
        })
        if (risk) map.set(item.id, risk)
      })
    })
    return map
  }, [groups, logs])

  const toggleGroup = (key) => {
    setCollapsedGroups((prev) => {
      const next = new Set(prev)
      next.has(key) ? next.delete(key) : next.add(key)
      return next
    })
  }

  if (groups.length === 0) {
    return (
      <div className="treatments-complex__empty">
        <p>Nenhum tratamento nesta categoria.</p>
      </div>
    )
  }

  return (
    <motion.div
      className="treatments-complex"
      variants={cascade.container}
      initial="hidden"
      animate="visible"
    >
      {groups.map((group) => {
        const isCollapsed = collapsedGroups.has(group.groupKey)
        return (
          <motion.section
            key={group.groupKey}
            variants={cascade.item}
            className="treatments-complex__group"
          >
            <TreatmentPlanHeader
              group={group}
              isCollapsed={isCollapsed}
              onToggle={() => toggleGroup(group.groupKey)}
              onEditPlan={onEditPlan}
              onDeletePlan={onDeletePlan}
            />
            {!isCollapsed && (
              <>
                {/* Desktop: tabular grid layout (shown on >= 1024px) — S7.5.5: hover state */}
                <div className="treatments-complex__rows treatments-complex__rows--tabular-container">
                  {group.items.map((item) => (
                    // S7.5.5: display:contents preserva grid, mouse events na 1ª célula
                    <div key={item.id} style={{ display: 'contents' }}>
                      <ProtocolRow
                        item={item}
                        isComplex={true}
                        onEdit={onEdit}
                        onDelete={onDelete}
                        activeTab={activeTab}
                        variant="tabular"
                        isHovered={hoveredRow === item.id}
                        onRowMouseEnter={() => setHoveredRow(item.id)}
                        onRowMouseLeave={() => setHoveredRow(null)}
                        onRowClick={() => onEdit?.(item)}
                        riskBadge={
                          <ProtocolRiskBadge risk={riskByProtocol.get(item.id)} isComplex={true} />
                        }
                      />
                    </div>
                  ))}
                </div>
                {/* Mobile: card layout (shown on < 1024px) */}
                <div className="treatments-complex__rows treatments-complex__rows--card-container">
                  {group.items.map((item) => (
                    <ProtocolRow
                      key={item.id}
                      item={item}
                      isComplex={true}
                      expanded={expandedRow === item.id}
                      onToggleExpand={() =>
                        setExpandedRow((prev) => (prev === item.id ? null : item.id))
                      }
                      onEdit={onEdit}
                      onDelete={onDelete}
                      activeTab={activeTab}
                      variant="card"
                      riskBadge={
                        <ProtocolRiskBadge risk={riskByProtocol.get(item.id)} isComplex={true} />
                      }
                    />
                  ))}
                </div>
              </>
            )}
          </motion.section>
        )
      })}
    </motion.div>
  )
}

/**
 * Adherence Logic - Funções puras para cálculo de adesão client-side
 *
 * Migrado de adherenceService para suportar "Custo Zero" de queries.
 * @module adherenceLogic
 */

import { 
  parseLocalDate, 
  formatLocalDate, 
  getTodayLocal, 
  isProtocolActiveOnDate as isProtocolInPeriod,
  getNow,
  parseISO,
  daysDifference,
  getSaoPauloTime,
  cloneDate,
  parseTimestamp
} from './dateUtils.js'

// Invariantes de Negócio (R-022, R-129)
const TOLERANCE_WINDOW_HOURS = 2
const TOLERANCE_WINDOW_MS = TOLERANCE_WINDOW_HOURS * 60 * 60 * 1000
const TOLERANCE_WINDOW_MINUTES = TOLERANCE_WINDOW_HOURS * 60

/**
 * Calcula doses esperadas para um conjunto de protocolos em um período.
 * Considera start_date e end_date para calcular dias efetivos de cada protocolo.
 *
 * @param {Array} protocols - Lista de protocolos
 * @param {number} days - Número de dias do período de análise
 * @param {Date} endDate - Data final do período (padrão: hoje)
 * @returns {number} Total de doses esperadas
 */
/**
 * Calcula a taxa de doses diárias de um protocolo conforme sua frequência
 * @param {string} frequency - Frequência do protocolo (daily, weekly, every_other_day, etc.)
 * @param {number} timesPerDay - Número de horários no time_schedule
 * @returns {number} Taxa de doses por dia
 */
function getDailyDoseRate(frequency, timesPerDay) {
  switch (frequency.toLowerCase()) {
    case 'daily':
    case 'diariamente':
    case 'diário':
      return timesPerDay
    case 'weekly':
    case 'semanal':
    case 'semanalmente':
      return timesPerDay / 7
    case 'every_other_day':
    case 'dia_sim_dia_nao':
    case 'dia sim, dia não':
    case 'dias_alternados':
      return timesPerDay / 2
    case 'quando_necessário':
    case 'personalizado':
      return 0
    default:
      return timesPerDay
  }
}

/**
 * Calcula o número de dias efetivos de um protocolo dentro de um período de análise
 * @param {Object} protocol - Protocolo com start_date e end_date opcionais
 * @param {Date} periodStart - Início do período de análise
 * @param {Date} periodEnd - Fim do período de análise
 * @returns {number} Número de dias efetivos (interseção entre protocolo e período)
 */
function getEffectiveDays(protocol, periodStart, periodEnd) {
  // Sem start_date: assume ativo desde o início do período
  const protocolStartDate = protocol.start_date
    ? parseLocalDate(protocol.start_date)
    : periodStart

  // Sem end_date: assume protocolo ainda ativo
  const protocolEndDate = protocol.end_date ? parseLocalDate(protocol.end_date) : periodEnd

  // Interseção entre período do protocolo e período de análise
  const effectiveStart = parseTimestamp(Math.max(protocolStartDate.getTime(), periodStart.getTime()))
  const effectiveEnd = parseTimestamp(Math.min(protocolEndDate.getTime(), periodEnd.getTime()))

  if (effectiveEnd < effectiveStart) return 0

  // effectiveEnd é T23:59:59, então Math.ceil conta o dia final corretamente
  const diffTime = effectiveEnd.getTime() - effectiveStart.getTime()
  return Math.ceil(diffTime / (1000 * 60 * 60 * 24))
}

export function calculateExpectedDoses(protocols, days, endDate = getNow()) {
  if (!protocols || protocols.length === 0) return 0

  const periodStart = cloneDate(endDate)
  periodStart.setHours(0, 0, 0, 0)
  periodStart.setDate(periodStart.getDate() - days + 1)

  const periodEnd = cloneDate(endDate)
  periodEnd.setHours(23, 59, 59, 999)

  return protocols.reduce((total, protocol) => {
    const timesPerDay = protocol.time_schedule?.length || 1
    const frequency = protocol.frequency || 'daily'
    const dailyDoses = getDailyDoseRate(frequency, timesPerDay)
    const effectiveDays = getEffectiveDays(protocol, periodStart, periodEnd)
    return total + dailyDoses * Math.max(effectiveDays, 0)
  }, 0)
}

/**
 * Calcula o streak e score baseado em logs e protocolos em memória
 * @param {Array} logs
 * @param {Array} protocols
 * @param {number} days
 * @returns {Object}
 */
export function calculateAdherenceStats(logs, protocols, days = 30, offsetDays = 0) {
  const logsByDay = new Map()
  logs.forEach((log) => {
    const dayKey = formatLocalDate(getSaoPauloTime(parseISO(log.taken_at)))
    if (!logsByDay.has(dayKey)) logsByDay.set(dayKey, [])
    logsByDay.get(dayKey).push(log)
  })

  let totalExpected = 0
  let totalFollowed = 0
  let totalTakenAnytime = 0
  let currentStreak = 0
  let streakBroken = false
  const todayStr = getTodayLocal()

  // Loop expandido para cobrir o streak além dos dias do score
  // Limite de segurança de 365 dias para evitar loops infinitos em datasets mal formados
  const maxDays = Math.max(days + offsetDays, 365)

  for (let i = offsetDays; i < maxDays; i++) {
    const date = getNow()
    date.setDate(date.getDate() - i)
    const dateStr = formatLocalDate(date)
    const dayLogs = logsByDay.get(dateStr) || []

    let dayExpected = 0
    let dayFollowed = 0
    let dayTakenAnytime = 0

    protocols.forEach((protocol) => {
      // Verificar se o protocolo estava ativo nesta data
      if (!isProtocolActiveOnDate(protocol, dateStr)) return

      const times = protocol.time_schedule || []
      dayExpected += times.length

      // Doses tomadas para este protocolo específico neste dia (independente de horário)
      const protocolLogs = dayLogs.filter((l) => l.protocol_id === protocol.id)
      dayTakenAnytime += Math.min(protocolLogs.length, times.length)

      times.forEach((time) => {
        if (isProtocolFollowed(time, dayLogs, dateStr)) {
          dayFollowed++
        }
      })
    })

    // Acumula para o score apenas se estiver dentro da janela 'days'
    if (i < offsetDays + days) {
      totalExpected += dayExpected
      totalFollowed += dayFollowed
      totalTakenAnytime += dayTakenAnytime
    }

    // Lógica de Streak (continua enquanto não quebrar)
    if (!streakBroken) {
      const minAdherence = 0.8
      // Para o STREAK, somos mais permissivos:
      // 1. Se não havia nada previsto (gap entre tratamentos), o streak não quebra (mantém vivo)
      // 2. Se havia doses, basta ter tomado (anytime) 80% delas (R-022)
      const isDaySuccessful = dayExpected === 0 || dayTakenAnytime / dayExpected >= minAdherence
      const isToday = dateStr === todayStr

      if (isDaySuccessful) {
        currentStreak++
      } else if (isToday) {
        // Hoje ainda não terminou, mantemos o streak vivo por UX positiva
      } else if (dayExpected > 0) {
        // Dia com doses esperadas que falhou (mesmo considerando anytime): quebra o streak
        streakBroken = true
      }
      // Se dayExpected == 0, o streak continua (dia de folga/sem protocolo)
    }

    // Se já calculamos o score E o streak quebrou, podemos parar
    if (i >= offsetDays + days && streakBroken) break
  }

  const score =
    totalExpected > 0 ? Math.min(Math.round((totalFollowed / totalExpected) * 100), 100) : 0

  return {
    score,
    taken: totalFollowed,
    takenAnytime: totalTakenAnytime,
    expected: totalExpected,
    currentStreak,
  }
}

/**
 * Verifica se um protocolo foi seguido para um determinado horário,
 * implementando a janela de +/- 2h de tolerância.
 *
 * @param {string} scheduledTime - Horário previsto "HH:mm" (local)
 * @param {Array} logs - Lista de logs (em UTC)
 * @param {string} dateStr - Data local de referência "YYYY-MM-DD"
 * @returns {boolean}
 */
export function isProtocolFollowed(scheduledTime, logs, dateStr) {
  if (!scheduledTime || !logs || logs.length === 0) return false

  return logs.some((log) => {
    // 1. Verificar se o log é do mesmo dia local
    const logDateStr = formatLocalDate(getSaoPauloTime(parseISO(log.taken_at)))

    if (logDateStr !== dateStr) return false

    // 2. Verificar janela de 2h
    return isDoseInToleranceWindow(scheduledTime, log.taken_at)
  })
}

/**
 * Verifica se uma dose foi tomada dentro da janela de tolerância de +/- 2 horas.
 *
 * @param {string} scheduledTime - Horário previsto "HH:mm" (local)
 * @param {string} logTakenAt - ISO timestamp do log (UTC)
 * @returns {boolean}
 */
export function isDoseInToleranceWindow(scheduledTime, logTakenAt) {
  if (!scheduledTime || !logTakenAt) return false

  const [sH, sM] = scheduledTime.split(':').map(Number)

  // R-020: Normalizar data tomada para fuso de SP (shifted)
  const takenDate = getSaoPauloTime(parseISO(logTakenAt))

  // Criamos um objeto Date para o horário previsto no MESMO DIA da dose tomada,
  // usando o mesmo referencial (shifted SP) para paridade aritmética.
  const scheduledDate = cloneDate(takenDate)
  scheduledDate.setHours(sH, sM, 0, 0)

  const diffMs = Math.abs(takenDate.getTime() - scheduledDate.getTime())

  return diffMs <= TOLERANCE_WINDOW_MS
}

/**
 * Calcula o horário da próxima dose baseado no cronograma do protocolo
 * Inclui janela de tolerância de 2 horas após o horário agendado.
 * @param {Object} protocol
 * @returns {string} HH:mm ou '--:--'
 */
export function getNextDoseTime(protocol) {
  if (!protocol || !protocol.time_schedule || protocol.time_schedule.length === 0) {
    return '--:--'
  }

  const now = getNow()
  const currentMinutes = now.getHours() * 60 + now.getMinutes()

  // Converte horários do cronograma para minutos e ordena
  const scheduleMinutes = protocol.time_schedule
    .map((time) => {
      const [h, m] = time.split(':').map(Number)
      return h * 60 + m
    })
    .sort((a, b) => a - b)

  // Janela de tolerância: 2 horas (120 minutos)
  const toleranceWindowMinutes = TOLERANCE_WINDOW_MINUTES

  // Encontra o próximo horário hoje (incluindo janela de 2h de tolerância)
  // Uma dose é considerada "ativa" até 2 horas após o horário agendado
  const nextToday = scheduleMinutes.find((m) => m + toleranceWindowMinutes > currentMinutes)

  if (nextToday !== undefined) {
    const h = String(Math.floor(nextToday / 60)).padStart(2, '0')
    const m = String(nextToday % 60).padStart(2, '0')
    return `${h}:${m}`
  }

  // Se não houver mais doses hoje, retorna a primeira dose de amanhã
  const firstTomorrow = scheduleMinutes[0]
  const h = String(Math.floor(firstTomorrow / 60)).padStart(2, '0')
  const m = String(firstTomorrow % 60).padStart(2, '0')
  return `${h}:${m}`
}

/**
 * Calcula o horário final da janela de tolerância (2h após a próxima dose).
 * Retorna null se não houver próxima dose ou se a dose é do dia seguinte.
 * @param {string} nextDoseTime - Horário da próxima dose no formato HH:mm
 * @returns {string|null} Horário final da janela (HH:mm) ou null
 */
export function getNextDoseWindowEnd(nextDoseTime) {
  if (!nextDoseTime || nextDoseTime === '--:--') {
    return null
  }

  const [hours, minutes] = nextDoseTime.split(':').map(Number)
  const windowEndMinutes = hours * 60 + minutes + TOLERANCE_WINDOW_MINUTES // +2 horas

  const endHours = String(Math.floor(windowEndMinutes / 60) % 24).padStart(2, '0')
  const endMinutes = String(windowEndMinutes % 60).padStart(2, '0')

  return `${endHours}:${endMinutes}`
}

/**
 * Verifica se a próxima dose está dentro da janela de tolerância (dentro das 2h).
 * @param {string} nextDoseTime - Horário da próxima dose no formato HH:mm
 * @returns {boolean} true se estiver dentro da janela de tolerância
 */
export function isInToleranceWindow(nextDoseTime) {
  if (!nextDoseTime || nextDoseTime === '--:--') {
    return false
  }

  const now = getNow()
  const currentMinutes = now.getHours() * 60 + now.getMinutes()

  const [hours, minutes] = nextDoseTime.split(':').map(Number)
  const doseMinutes = hours * 60 + minutes
  const toleranceWindowMinutes = TOLERANCE_WINDOW_MINUTES

  // Está dentro da janela se o horário atual for maior que o agendado
  // mas menor que o agendado + 2 horas
  return currentMinutes > doseMinutes && currentMinutes <= doseMinutes + toleranceWindowMinutes
}

/**
 * Calcula a ingestão diária total de um medicamento baseado em seus protocolos ativos
 * @param {string} medicineId
 * @param {Array} protocols
 * @returns {number}
 */
export function calculateDailyIntake(medicineId, protocols) {
  if (!protocols) return 0

  return protocols
    .filter((p) => p.medicine_id === medicineId && p.active)
    .reduce((total, p) => {
      const dosesPerDay = p.time_schedule?.length || 1
      const dosage = p.dosage_per_intake || 1
      return total + dosesPerDay * dosage
    }, 0)
}

/**
 * Calcula dias restantes de estoque
 * @param {number} totalQuantity
 * @param {number} dailyIntake
 * @returns {number}
 */
export function calculateDaysRemaining(totalQuantity, dailyIntake) {
  if (dailyIntake <= 0) return Infinity
  return Math.floor(totalQuantity / dailyIntake)
}

/**
 * Calcula doses para uma data específica, classificando em tomadas, perdidas e agendadas
 *
 * @param {string} date - Data em formato YYYY-MM-DD (horário local Brasil)
 * @param {Array} logs - Logs de medicamentos do dia
 * @param {Array} protocols - Protocolos ativos
 * @returns {Object} { takenDoses: [], missedDoses: [], scheduledDoses: [] }
 */
export function calculateDosesByDate(date, logs, protocols, now = getNow()) {
  if (!date || !protocols || protocols.length === 0) {
    return { takenDoses: [], missedDoses: [], scheduledDoses: [] }
  }

  const takenDoses = []
  const missedDoses = []
  const scheduledDoses = []

  // Filtrar protocolos aplicáveis para esta data
  const applicableProtocols = protocols.filter((p) => isProtocolActiveOnDate(p, date))

  // Gerar slots de doses esperados para cada protocolo aplicável
  const expectedDoses = []
  applicableProtocols.forEach((protocol) => {
    const schedule = protocol.time_schedule || []
    schedule.forEach((time) => {
      expectedDoses.push({
        protocolId: protocol.id,
        medicineId: protocol.medicine_id,
        scheduledTime: time,
        expectedQuantity: protocol.dosage_per_intake || 1,
        protocol: protocol,
        medicine: protocol.medicine || null,
      })
    })
  })

  // Criar cópia dos logs para rastrear quais já foram associados
  const unmatchedLogs = [...(logs || [])]

  // Para cada dose esperada, tentar encontrar um log correspondente
  expectedDoses.forEach((expectedDose) => {
    let matchedLogIndex = -1

    // Procurar log que corresponda a este horário esperado
    for (let i = 0; i < unmatchedLogs.length; i++) {
      const log = unmatchedLogs[i]

      // Verificar se o log é do mesmo protocolo
      if (log.protocol_id !== expectedDose.protocolId) continue

      // Verificar se está na janela de tolerância (+/- 2h)
      if (isDoseInToleranceWindow(expectedDose.scheduledTime, log.taken_at)) {
        matchedLogIndex = i
        break
      }
    }

    if (matchedLogIndex >= 0) {
      // Dose tomada - mover log para takenDoses
      const matchedLog = unmatchedLogs.splice(matchedLogIndex, 1)[0]
      takenDoses.push({
        ...matchedLog,
        scheduledTime: expectedDose.scheduledTime,
        expectedQuantity: expectedDose.expectedQuantity,
        protocol: expectedDose.protocol,
        medicine: expectedDose.medicine,
        status: 'done',
      })
    } else {
      // Dose não tomada - verificar se é perdida (passado) ou agendada (futuro)
      const [scheduledHour, scheduledMinute] = expectedDose.scheduledTime.split(':').map(Number)

      // Construir data/hora agendada com parseLocalDate para timezone consistency
      const scheduledDateTime = parseLocalDate(date)
      scheduledDateTime.setHours(scheduledHour, scheduledMinute, 0, 0)

      // Comparar com horário atual
      const isPast = scheduledDateTime < now

      const baseDose = {
        id: `${isPast ? 'missed' : 'scheduled'}-${expectedDose.protocolId}-${expectedDose.scheduledTime}`,
        protocol_id: expectedDose.protocolId,
        medicine_id: expectedDose.medicineId,
        scheduledTime: expectedDose.scheduledTime,
        expectedQuantity: expectedDose.expectedQuantity,
        quantity_taken: 0,
        protocol: expectedDose.protocol,
        medicine: expectedDose.medicine,
        isSynthetic: true,
      }

      if (isPast) {
        // Dose perdida - horário já passou
        missedDoses.push({
          ...baseDose,
          status: 'missed',
        })
      } else {
        // Dose agendada - horário ainda não chegou
        scheduledDoses.push({
          ...baseDose,
          status: 'scheduled',
        })
      }
    }
  })

  // Logs restantes que não correspondem a nenhuma dose esperada
  // (doses extras, fora do horário, etc.) - adicionar como takenDoses
  unmatchedLogs.forEach((log) => {
    const protocol = protocols.find((p) => p.id === log.protocol_id)
    takenDoses.push({
      ...log,
      scheduledTime: null,
      expectedQuantity: log.quantity_taken || 1,
      isExtra: true,
      protocol: protocol || null,
      medicine: protocol?.medicine || null,
      status: 'done',
    })
  })

  return { takenDoses, missedDoses, scheduledDoses }
}

/**
 * Avalia o estado tático de uma dose na linha do tempo (Epic 2 Fase 8)
 * Classifica doses em 5 estados: TOMADA, ATRASADA, PERDIDA, PROXIMA, PLANEJADA.
 * 
 * @param {string} date - Data de referência YYYY-MM-DD
 * @param {Object} dosesObj - Retorno de calculateDosesByDate { takenDoses, missedDoses, scheduledDoses }
 * @param {Date} now - Hora atual de referência
 * @returns {Array} Array único e ordenado de doses com a propriedade timelineStatus
 */
export function evaluateDoseTimelineState(date, dosesObj, now = getNow()) {
  const { takenDoses = [], missedDoses = [], scheduledDoses = [] } = dosesObj
  const nowMs = now.getTime()

  // Helper para criar Date consistente
  const createScheduledDate = (timeStr) => {
    const [h, m] = timeStr.split(':').map(Number)
    const d = parseLocalDate(date)
    d.setHours(h, m, 0, 0)
    return d
  }

  const allDoses = [
    // 1. TOMADAS (Independente do horário)
    ...takenDoses.map((d) => ({ ...d, timelineStatus: 'TOMADA', isRegistered: true })),

    // 2. MISSES (No passado)
    ...missedDoses.map((d) => {
      const scheduledDate = createScheduledDate(d.scheduledTime)
      const diffMs = nowMs - scheduledDate.getTime()

      // Se passou menos de 2h do horário agendado, ainda é ATRASADA
      // Se passou mais de 2h, é PERDIDA
      const timelineStatus = diffMs <= TOLERANCE_WINDOW_MS ? 'ATRASADA' : 'PERDIDA'
      return { ...d, timelineStatus, isRegistered: false }
    }),

    // 3. SCHEDULED (No futuro)
    ...scheduledDoses.map((d) => {
      const scheduledDate = createScheduledDate(d.scheduledTime)
      const diffMs = scheduledDate.getTime() - nowMs

      // Se falta menos de 2h para o horário agendado, é PROXIMA (Aviso prévio)
      // Se falta mais de 2h, é PLANEJADA
      const timelineStatus = diffMs <= TOLERANCE_WINDOW_MS ? 'PROXIMA' : 'PLANEJADA'
      return { ...d, timelineStatus, isRegistered: false }
    }),
  ]

  // Ordenar por horário agendado (cronológico)
  return allDoses.sort((a, b) => {
    const getTime = (d) => d.scheduledTime || (d.taken_at ? parseISO(d.taken_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', hour12: false }) : '00:00')
    return getTime(a).localeCompare(getTime(b))
  })
}

/**
 * Verifica se um protocolo está "vigente" para uma data específica.
 * Vigente significa:
 * 1. O protocolo está marcado como ativo
 * 2. A data alvo está dentro do intervalo [start_date, end_date]
 * 3. A frequência do protocolo (diário, semanal, dia-sim-dia-nao) cai na data alvo
 * 
 * @param {Object} protocol - Protocolo
 * @param {string|Date} date - Data alvo (YYYY-MM-DD ou Date object)
 * @returns {boolean}
 */
export function isProtocolActiveOnDate(protocol, date) {
  const dateStr = typeof date === 'string' ? date : formatLocalDate(date)
  const targetDate = parseLocalDate(dateStr)
  const dayOfWeek = targetDate.getDay() // 0=Domingo, 1=Segunda, etc.

  // 1. Verificar se o registro está ativo ou se é um registro histórico finalizado (histórico de adesão)
  const isHistorical = protocol.end_date && targetDate <= parseLocalDate(protocol.end_date)
  if (protocol.active === false && !isHistorical) return false

  // 2. Verificar período de validade (Usa isProtocolInPeriod do dateUtils)
  if (!isProtocolInPeriod(protocol, dateStr)) return false

  // 3. Verificar frequência
  const frequency = (protocol.frequency || 'diário').toLowerCase()

  switch (frequency) {
    case 'diário':
    case 'diariamente':
    case 'daily':
      return true

    case 'semanal':
    case 'semanalmente':
    case 'weekly':
      // Verificar se o dia da semana está nos dias configurados
      if (protocol.days && Array.isArray(protocol.days)) {
        const dayMap = {
          domingo: 0, sunday: 0,
          segunda: 1, 'segunda-feira': 1, monday: 1,
          terça: 2, 'terça-feira': 2, tuesday: 2,
          quarta: 3, 'quarta-feira': 3, wednesday: 3,
          quinta: 4, 'quinta-feira': 4, thursday: 4,
          sexta: 5, 'sexta-feira': 5, friday: 5,
          sábado: 6, sabado: 6, saturday: 6,
        }
        return protocol.days.some((day) => dayMap[day.toLowerCase()] === dayOfWeek)
      }
      return false

    case 'dia_sim_dia_nao':
    case 'dia sim, dia não':
    case 'every_other_day':
    case 'alternating':
      // Calcular dias desde a data de início (dia 0 = dose)
      if (protocol.start_date) {
        const startDate = parseLocalDate(protocol.start_date)
        return daysDifference(startDate, targetDate) % 2 === 0
      }
      return true // Sem data de início, assume início hoje

    case 'personalizado':
    case 'custom':
    case 'quando_necessário':
    case 'when_needed':
    case 'prn':
      return false

    default:
      return true
  }
}

/**
 * createQueryCache — Engine de cache SWR compartilhada (platform-agnostic)
 *
 * Design:
 * - Factory function: sem singleton global, sem inicializacao em import
 * - Storage injetado: funciona com web localStorage, AsyncStorage, memoryStorage
 * - Logger injetado: sem dependencia de console/debugLog especifico da plataforma
 * - React-free: a engine nao importa React — hooks ficam na plataforma
 * - Async-first: persiste/hidrata via storage adapter async (contratos H3.1)
 *
 * Regra: NUNCA chamar `init()` fora do bootstrap da plataforma.
 *
 * @module createQueryCache
 */

import { setJSON, getJSON } from '@dosiq/storage'

/**
 * Cria uma instancia de query cache com dependencias injetadas.
 *
 * @param {Object} options
 * @param {import('@dosiq/storage').StorageAdapter} options.storage - Adapter de storage async
 * @param {Object} [options.logger] - Logger opcional com metodo log/warn/error
 * @param {number} [options.staleTime=30000] - Tempo (ms) antes de um entry ficar stale
 * @param {number} [options.maxEntries=200] - Maximo de entradas no cache (LRU eviction)
 * @param {string} [options.persistKey='dosiq_query_cache'] - Chave de persistencia
 * @returns {QueryCache} Instancia do cache
 */
export function createQueryCache({
  storage,
  logger = null,
  staleTime = 30_000,
  maxEntries = 200,
  persistKey = 'dosiq_query_cache',
} = {}) {
  if (!storage) throw new Error('createQueryCache: storage adapter is required')

  // --- estado privado da instancia ---
  /** @type {Map<string, {data: *, timestamp: number, isRevalidating: boolean}>} */
  const cache = new Map()
  /** @type {Map<string, Promise>} */
  const pendingRequests = new Map()
  /** @type {Map<string, number>} */
  const accessCount = new Map()
  let accessCounter = 0
  let cacheGeneration = 0
  let gcInterval = null
  let persistTimer = null
  let initialized = false

  const GC_INTERVAL = 60_000

  // --- helpers privados ---

  function log(level, msg) {
    if (!logger) return
    const fn = logger[level] ?? logger.log
    if (fn) fn(`[QueryCache] ${msg}`)
  }

  function isStale(timestamp, customStaleTime) {
    return Date.now() - timestamp > (customStaleTime ?? staleTime)
  }

  function updateAccess(key) {
    accessCounter++
    accessCount.set(key, accessCounter)
  }

  /**
   * Persiste o cache no storage adapter (debounced 500ms).
   * Nunca bloqueia — falhas sao logadas e ignoradas.
   */
  function schedulePersist() {
    if (persistTimer) clearTimeout(persistTimer)
    persistTimer = setTimeout(async () => {
      try {
        const entries = Array.from(cache.entries())
          .filter(([, v]) => !v.isRevalidating)
          .slice(0, maxEntries)
        await setJSON(storage, persistKey, entries)
      } catch (err) {
        log('warn', `Falha ao persistir cache: ${err.message}`)
      }
      persistTimer = null
    }, 500)
  }

  function garbageCollect() {
    const now = Date.now()
    const ttlThreshold = staleTime * 2
    let removed = 0

    for (const [key, value] of cache.entries()) {
      if (now - value.timestamp > ttlThreshold) {
        cache.delete(key)
        accessCount.delete(key)
        pendingRequests.delete(key)
        removed++
      }
    }

    if (removed > 0) log('log', `GC TTL: ${removed} entradas removidas`)

    if (cache.size <= maxEntries) return

    const sorted = Array.from(accessCount.entries()).sort((a, b) => a[1] - b[1])
    const toEvict = sorted.slice(0, cache.size - maxEntries)
    toEvict.forEach(([key]) => {
      cache.delete(key)
      accessCount.delete(key)
      pendingRequests.delete(key)
    })

    if (toEvict.length > 0) {
      log('log', `GC LRU: ${toEvict.length} entradas evictadas. Tamanho: ${cache.size}`)
      schedulePersist()
    }
  }

  // --- API publica ---

  /**
   * Inicializa o cache: hidrata do storage e inicia GC.
   * DEVE ser chamado explicitamente no bootstrap da plataforma.
   * Nao e chamado automaticamente no import.
   *
   * @returns {Promise<void>}
   */
  async function init() {
    if (initialized) return

    try {
      const persisted = await getJSON(storage, persistKey, null)
      if (Array.isArray(persisted)) {
        persisted.forEach(([key, value]) => {
          cache.set(key, { ...value, isRevalidating: false })
        })
        log('log', `Hidracao: ${persisted.length} entradas carregadas`)
      }
    } catch (err) {
      log('warn', `Falha ao hidratar cache: ${err.message}`)
    }

    gcInterval = setInterval(garbageCollect, GC_INTERVAL)
    initialized = true
  }

  /**
   * Executa uma query com semantica SWR (Stale-While-Revalidate):
   * 1. Cache valido (fresh) → retorna imediatamente
   * 2. Cache stale → retorna stale + revalida em background
   * 3. Cache MISS → executa fetcher e armazena
   *
   * @param {string} key - Chave unica
   * @param {Function} fetcher - Funcao que retorna Promise com os dados
   * @param {Object} [options]
   * @param {number} [options.staleTime] - Override de staleTime para esta query
   * @param {boolean} [options.dedupe=true] - Deduplica requests em voo
   * @returns {Promise<*>}
   */
  async function cachedQuery(key, fetcher, options = {}) {
    const { dedupe = true, staleTime: customStaleTime } = options
    const cached = cache.get(key)

    if (dedupe && pendingRequests.has(key)) {
      log('log', `Deduplica: ${key}`)
      return pendingRequests.get(key)
    }

    if (cached && !isStale(cached.timestamp, customStaleTime)) {
      updateAccess(key)
      log('log', `HIT (fresh): ${key}`)
      return cached.data
    }

    if (cached) {
      log('log', `HIT (stale): ${key} — revalidando em background`)
      const capturedGen = cacheGeneration
      const revalPromise = (async () => {
        try {
          const data = await fetcher()
          if (capturedGen === cacheGeneration) {
            cache.set(key, { data, timestamp: Date.now(), isRevalidating: false })
            updateAccess(key)
            garbageCollect()
            schedulePersist()
          }
          return data
        } catch (err) {
          log('warn', `Revalidacao falhou: ${key} — ${err.message}`)
          cached.isRevalidating = false
          throw err
        }
      })()
      cached.isRevalidating = true
      revalPromise.catch(() => {})
      updateAccess(key)
      return cached.data
    }

    log('log', `MISS: ${key}`)
    const capturedGen = cacheGeneration
    const fetchPromise = (async () => {
      try {
        const data = await fetcher()
        if (capturedGen === cacheGeneration) {
          cache.set(key, { data, timestamp: Date.now(), isRevalidating: false })
          updateAccess(key)
          garbageCollect()
          schedulePersist()
        }
        return data
      } catch (err) {
        log('warn', `Fetch falhou: ${key} — ${err.message}`)
        throw err
      } finally {
        pendingRequests.delete(key)
      }
    })()

    if (dedupe) pendingRequests.set(key, fetchPromise)
    return fetchPromise
  }

  /**
   * Invalida entradas do cache por chave exata, prefixo (*) ou regex.
   *
   * @param {string|RegExp} pattern
   * @returns {number} Numero de entradas invalidadas
   */
  function invalidate(pattern) {
    let count = 0

    if (typeof pattern === 'string') {
      if (pattern.endsWith('*')) {
        const prefix = pattern.slice(0, -1)
        for (const key of cache.keys()) {
          if (key.startsWith(prefix)) {
            cache.delete(key)
            accessCount.delete(key)
            pendingRequests.delete(key)
            count++
          }
        }
      } else if (cache.has(pattern)) {
        cache.delete(pattern)
        accessCount.delete(pattern)
        pendingRequests.delete(pattern)
        count = 1
      }
    } else if (pattern instanceof RegExp) {
      for (const key of cache.keys()) {
        if (pattern.test(key)) {
          cache.delete(key)
          accessCount.delete(key)
          pendingRequests.delete(key)
          count++
        }
      }
    }

    if (count > 0) {
      schedulePersist()
      log('log', `Invalidadas ${count} entradas para: ${pattern}`)
    }

    return count
  }

  /**
   * Limpa todo o cache e cancela persist pendente.
   * Incrementa cacheGeneration para invalidar fetches em voo.
   */
  function clear() {
    if (persistTimer) {
      clearTimeout(persistTimer)
      persistTimer = null
    }
    cacheGeneration++
    const size = cache.size
    cache.clear()
    accessCount.clear()
    pendingRequests.clear()
    accessCounter = 0
    log('log', `Cache limpo: ${size} entradas removidas`)
  }

  /**
   * Preenche o cache com dados (util para pre-carregamento ou testes).
   *
   * @param {string} key
   * @param {*} data
   */
  function prefetch(key, data) {
    cache.set(key, { data, timestamp: Date.now(), isRevalidating: false })
    updateAccess(key)
    garbageCollect()
    schedulePersist()
  }

  /**
   * Retorna estatisticas do cache (debug).
   * @returns {Object}
   */
  function getStats() {
    const entries = Array.from(cache.entries())
    const staleCount = entries.filter(([, v]) => isStale(v.timestamp)).length
    return {
      size: cache.size,
      staleEntries: staleCount,
      freshEntries: cache.size - staleCount,
      pendingRequests: pendingRequests.size,
      maxEntries,
      initialized,
    }
  }

  /**
   * Cancela GC interval (para testes).
   * @internal
   */
  function cancelGC() {
    if (gcInterval) {
      clearInterval(gcInterval)
      gcInterval = null
    }
  }

  /**
   * Reinicia GC interval (para testes).
   * @internal
   */
  function restartGC() {
    if (!gcInterval) {
      gcInterval = setInterval(garbageCollect, GC_INTERVAL)
    }
  }

  return {
    init,
    cachedQuery,
    invalidate,
    clear,
    prefetch,
    getStats,
    // internals para testes
    cancelGC,
    restartGC,
  }
}

import cron from 'node-cron';
import { createLogger } from './logger.js';
import {
  checkStockAlerts,
  checkAdherenceReports,
  checkTitrationAlerts,
  checkMonthlyReport
} from './tasks.js';

const logger = createLogger('Alerts');

/**
 * Wrapper para cron jobs com tratamento de erro padronizado
 * @param {string} name - Nome do job para logging
 * @param {string} schedule - Expressão cron
 * @param {Function} task - Função async a ser executada
 */
function scheduleTask(name, schedule, task) {
  cron.schedule(schedule, async () => {
    try {
      logger.debug(`Starting scheduled task: ${name}`);
      await task();
      logger.debug(`Completed scheduled task: ${name}`);
    } catch (error) {
      logger.error(`Scheduled task failed: ${name}`, error);
    }
  });
  logger.info(`Scheduled task registered: ${name}`, { schedule });
}

export function startStockAlerts(bot, options = {}) {
  // Run daily at 9:00 AM
  scheduleTask('checkStockAlerts', '0 9 * * *', () => checkStockAlerts(bot, options));
  console.log('✅ Alertas de estoque configurados (diariamente às 9h)');
}

export function startAdherenceReports(bot, options = {}) {
  // Run every Sunday at 10:00 PM
  scheduleTask('checkAdherenceReports', '0 22 * * 0', () => checkAdherenceReports(bot, options));
  console.log('✅ Relatórios de adesão configurados (domingos às 22h)');
}

export function startTitrationAlerts(bot, options = {}) {
  // Run daily at 8:00 AM
